package com.formbuilder.service;

import com.formbuilder.dto.ValidationError;
import com.formbuilder.entity.FormFieldEntity;
import com.formbuilder.exception.SchemaDriftException;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.*;

/**
 * Core DDL service — creates / alters / drops the physical submission table
 * for each form using raw JdbcTemplate (NOT Hibernate).
 *
 * Table naming: form_<sanitizedFormName>_<6-char-hex>
 * e.g. form_contact_form_a3b8d1
 *
 * Base columns (created in CREATE TABLE):
 * id UUID PRIMARY KEY DEFAULT gen_random_uuid()
 * created_at TIMESTAMP DEFAULT NOW()
 * updated_at TIMESTAMP DEFAULT NOW()
 *
 * Field columns are added via ALTER TABLE ADD COLUMN after table creation.
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class DynamicTableService {

    // Map.ofEntries used because Map.of() is limited to 10 entries
    private static final Map<String, String> SQL_TYPE = Map.ofEntries(
            Map.entry("text", "TEXT"),
            Map.entry("number", "INTEGER"),
            Map.entry("decimal", "NUMERIC"),
            Map.entry("numeric", "NUMERIC"),
            Map.entry("date", "DATE"),
            Map.entry("boolean", "BOOLEAN"),
            // Normalize all string fields to TEXT for easier comparison in drift detection
            Map.entry("dropdown", "TEXT"),
            Map.entry("radio", "TEXT"),
            Map.entry("multiple_choice", "TEXT"),
            Map.entry("linear_scale", "INTEGER"),
            Map.entry("file", "TEXT"),
            Map.entry("multiple_choice_grid", "TEXT"),
            Map.entry("star_rating", "INTEGER"),
            Map.entry("checkbox_grid", "TEXT")
    );

    private final JdbcTemplate jdbc;

    private static final Set<String> RESERVED_KEYWORDS = Set.of(
            "SELECT", "INSERT", "UPDATE", "DELETE", "FROM", "WHERE", "JOIN", "INNER", "LEFT", "RIGHT", "FULL",
            "GROUP", "ORDER", "BY", "HAVING", "LIMIT", "OFFSET", "UNION", "DISTINCT",
            "TABLE", "COLUMN", "INDEX", "PRIMARY", "FOREIGN", "KEY", "CONSTRAINT", "REFERENCES",
            "VIEW", "SEQUENCE", "TRIGGER", "USER", "ROLE", "GRANT", "REVOKE",
            "ID", "CREATED_AT", "UPDATED_AT", "FORM_VERSION_ID", "IS_DRAFT", "IS_SOFT_DELETED", "DELETED_AT"
    );

    // ── Table Name Generation ─────────────────────────────────────────────────

    /**
     * Converts a human-readable form name or code to a safe PostgreSQL table name.
     * Format: form_data_<code>
     */
    public String generateTableName(String code) {
        String sanitized = code.toLowerCase()
                .replaceAll("[^a-z0-9]+", "_")
                .replaceAll("^_+|_+$", "");
        if (sanitized.isEmpty()) {
            sanitized = "generic_form";
        }
        return "form_data_" + sanitized;
    }

    // ── Public DDL API ────────────────────────────────────────────────────────

    public void validateFieldKey(String key) {
        if (key == null || key.isBlank()) {
            throw new IllegalArgumentException("Field key cannot be empty.");
        }
        if (key.length() > 100) {
            throw new IllegalArgumentException("Field key '" + key + "' exceeds maximum length of 100 characters.");
        }
        if (!key.matches("^[a-z0-9_]+$")) {
            throw new IllegalArgumentException("Field key '" + key + "' must contain only lowercase alphanumeric characters and underscores.");
        }
        if (RESERVED_KEYWORDS.contains(key.toUpperCase())) {
            throw new IllegalArgumentException("Field key '" + key + "' is a reserved keyword and cannot be used.");
        }
    }

    /**
     * Step 1: CREATE TABLE with base columns only.
     * Step 2: ALTER TABLE ADD COLUMN for every field in the form.
     */
    public void createTable(String tableName, List<FormFieldEntity> fields) {
        // Step 1 — base table structure
        String create = """
                CREATE TABLE %s (
                    id              UUID      PRIMARY KEY DEFAULT gen_random_uuid(),
                    form_version_id UUID      NOT NULL,
                    created_at      TIMESTAMP NOT NULL DEFAULT NOW(),
                    updated_at      TIMESTAMP NOT NULL DEFAULT NOW(),
                    is_draft        BOOLEAN   NOT NULL DEFAULT TRUE,
                    is_soft_deleted BOOLEAN   NOT NULL DEFAULT FALSE,
                    deleted_at      TIMESTAMP,
                    user_id         VARCHAR(255)
                )
                """.formatted(q(tableName));
        log.debug("DDL createTable: {}", create.trim());
        jdbc.execute(create);

        // Step 2 — one column per field
        for (FormFieldEntity field : fields) {
            if (!"field_group".equals(field.getFieldType())) {
                addColumn(tableName, field.getFieldKey(), field.getFieldType());
            }
        }
    }

    /**
     * Back-fills status and user_id columns on an existing submission table.
     */
    public void addDraftColumnsIfMissing(String tableName) {
        try {
            jdbc.execute("ALTER TABLE " + q(tableName) +
                    " ADD COLUMN IF NOT EXISTS form_version_id UUID");
            jdbc.execute("ALTER TABLE " + q(tableName) +
                    " ADD COLUMN IF NOT EXISTS is_draft BOOLEAN NOT NULL DEFAULT TRUE");
            jdbc.execute("ALTER TABLE " + q(tableName) +
                    " ADD COLUMN IF NOT EXISTS user_id VARCHAR(255)");
            log.debug("Standard columns ensured for table: {}", tableName);
        } catch (Exception e) {
            log.warn("Could not add standard columns to {}: {}", tableName, e.getMessage());
        }
    }

    /**
     * Back-fills is_soft_deleted and deleted_at columns on an existing submission
     * table
     * that was created before the soft-delete feature was added.
     * Safe to call repeatedly — uses ADD COLUMN IF NOT EXISTS.
     */
    public void addSoftDeleteColumnIfMissing(String tableName) {
        try {
            jdbc.execute("ALTER TABLE " + q(tableName) +
                    " ADD COLUMN IF NOT EXISTS is_soft_deleted BOOLEAN NOT NULL DEFAULT FALSE");
            jdbc.execute("ALTER TABLE " + q(tableName) +
                    " ADD COLUMN IF NOT EXISTS deleted_at TIMESTAMP");
            log.debug("Soft-delete columns ensured for table: {}", tableName);
        } catch (Exception e) {
            log.warn("Could not add soft-delete columns to {}: {}", tableName, e.getMessage());
        }
    }

    /** ALTER TABLE <tableName> ADD COLUMN <fieldKey> <sqlType> */
    public void addColumn(String tableName, String fieldKey, String fieldType) {
        if ("field_group".equals(fieldType))
            return;
        String sql = "ALTER TABLE " + q(tableName)
                + " ADD COLUMN IF NOT EXISTS " + q(fieldKey) + " " + sqlType(fieldType);
        log.debug("DDL addColumn: {}", sql);
        jdbc.execute(sql);
    }

    public void addColumnIfMissing(String tableName, String fieldKey, String fieldType) {
        addColumn(tableName, fieldKey, fieldType);
    }

    /** ALTER TABLE <tableName> DROP COLUMN <fieldKey> */
    public void dropColumn(String tableName, String fieldKey) {
        String sql = "ALTER TABLE " + q(tableName) + " DROP COLUMN IF EXISTS " + q(fieldKey);
        log.debug("DDL dropColumn: {}", sql);
        jdbc.execute(sql);
    }

    /**
     * ALTER TABLE <tableName> ALTER COLUMN <fieldKey> TYPE <newSqlType>
     * USING cast ensures PostgreSQL can coerce existing data.
     */
    public void alterColumnType(String tableName, String fieldKey, String newFieldType) {
        String type = sqlType(newFieldType);
        String sql = "ALTER TABLE " + q(tableName)
                + " ALTER COLUMN " + q(fieldKey)
                + " TYPE " + type
                + " USING " + q(fieldKey) + "::" + type;
        log.debug("DDL alterColumnType: {}", sql);
        jdbc.execute(sql);
    }

    /** DROP TABLE IF EXISTS <tableName> */
    public void dropTable(String tableName) {
        String sql = "DROP TABLE IF EXISTS " + q(tableName);
        log.debug("DDL dropTable: {}", sql);
        jdbc.execute(sql);
    }

    /**
     * S1 — Draft deletion logic.
     * 1. Query form_submission_meta to find linked rows in dynamic tables.
     * 2. Delete linked dynamic rows.
     * 3. Delete meta rows.
     */
    @Transactional
    public void deleteAllDrafts(UUID formId) {
        String queryMeta = "SELECT id, submission_table, submission_row_id FROM form_submission_meta " +
                           "WHERE form_id = ? AND status = 'DRAFT'";
        List<Map<String, Object>> drafts = jdbc.queryForList(queryMeta, formId);

        for (Map<String, Object> draft : drafts) {
            String rawTable = (String) draft.get("submission_table");
            UUID rowId = (UUID) draft.get("submission_row_id");

            // System Rule: Use String.format() with pre-validated table names only
            String sqlDeleteData = String.format("DELETE FROM %s WHERE id = ?", q(rawTable));
            jdbc.update(sqlDeleteData, rowId);
        }

        String sqlDeleteMeta = "DELETE FROM form_submission_meta WHERE form_id = ? AND status = 'DRAFT'";
        jdbc.update(sqlDeleteMeta, formId);
        log.info("S1: Cleaned up {} drafts for formId={}", drafts.size(), formId);
    }

    /**
     * S2 — Passive drift detection (Decision 4.3).
     * Throws SchemaDriftException if metadata and physical schema disagree.
     */
    public void validateSchema(String tableName, UUID versionId) {
        // 1. Get metadata fields
        List<Map<String, Object>> metadataFields = jdbc.queryForList(
                "SELECT field_key, field_type FROM form_fields WHERE form_version_id = ?", versionId);

        // 2. Get actual columns from information_schema
        Map<String, String> actualColumns = new HashMap<>();
        // Postgres information_schema uses lowercase for unquoted table names
        jdbc.query("SELECT column_name, data_type FROM information_schema.columns WHERE table_name = ?",
                (java.sql.ResultSet rs) -> {
                    while (rs.next()) {
                        actualColumns.put(rs.getString("column_name"), rs.getString("data_type").toLowerCase());
                    }
                    return null;
                }, tableName.toLowerCase());

        List<ValidationError> errors = new ArrayList<>();
        for (Map<String, Object> field : metadataFields) {
            String fieldKey = (String) field.get("field_key");
            String fieldType = (String) field.get("field_type");

            if (!actualColumns.containsKey(fieldKey)) {
                errors.add(new ValidationError(fieldKey, "Column is missing in physical table"));
                continue;
            }

            String expectedSqlType = sqlType(fieldType).toLowerCase();
            String actualSqlType = actualColumns.get(fieldKey);

            if (!isTypeCompatible(expectedSqlType, actualSqlType)) {
                errors.add(new ValidationError(
                        fieldKey,
                        String.format("Type mismatch (expected: %s, actual: %s)", expectedSqlType, actualSqlType)
                ));
            }
        }

        if (!errors.isEmpty()) {
            throw new SchemaDriftException(String.format(
                    "Decision 4.3 Violation: Physical table '%s' has drifted from metadata in version %s.",
                    tableName, versionId),
                    tableName,
                    versionId,
                    errors);
        }
    }

    private boolean isTypeCompatible(String expected, String actual) {
        if (expected.equals("text")) {
            return actual.equals("text") || actual.equals("character varying") || actual.equals("varchar");
        }
        if (expected.equals("integer")) {
            return actual.equals("integer") || actual.equals("int4");
        }
        if (expected.equals("numeric")) {
            return actual.equals("numeric") || actual.equals("decimal");
        }
        if (expected.equals("boolean")) {
            return actual.equals("boolean") || actual.equals("bool");
        }
        if (expected.equals("date")) {
            return actual.equals("date");
        }
        return actual.equals(expected);
    }

    /**
     * S3 — Integrity check queries.
     * Query 1: Version mismatch between meta and data table.
     */
    public List<Map<String, Object>> checkVersionMismatches(String tableName) {
        String sql = String.format(
            "SELECT m.id as meta_id, m.form_version_id as meta_v, d.form_version_id as data_v " +
            "FROM form_submission_meta m " +
            "JOIN %s d ON m.submission_row_id = d.id " +
            "WHERE m.form_version_id != d.form_version_id", q(tableName));
        return jdbc.queryForList(sql);
    }

    /**
     * S3 — Integrity check queries.
     * Query 2: Orphaned meta rows.
     */
    public List<Map<String, Object>> checkOrphanedMeta(String tableName) {
        String sql = String.format(
            "SELECT m.id, m.submission_row_id FROM form_submission_meta m " +
            "LEFT JOIN %s d ON m.submission_row_id = d.id " +
            "WHERE m.submission_table = ? AND d.id IS NULL", q(tableName));
        return jdbc.queryForList(sql, tableName);
    }

    /** Check whether a dynamic submission table exists in the database. */
    public boolean tableExists(String tableName) {
        Integer count = jdbc.queryForObject(
                "SELECT COUNT(*) FROM information_schema.tables WHERE table_name = ?",
                Integer.class, tableName);
        return count != null && count > 0;
    }

    /**
     * Ensures the submission table exists. If the table is missing (e.g. DB was
     * recreated but form metadata survived), it is re-created from the field
     * definitions stored in form_fields.
     */
    public void ensureTableExists(String tableName, UUID formId) {
        if (tableExists(tableName)) {
            return;
        }
        log.warn("Submission table '{}' missing — recreating from form_fields for formId={}", tableName, formId);
        // Fetch field definitions via JDBC (no JPA dependency)
        List<Map<String, Object>> fieldRows = jdbc.queryForList(
                "SELECT DISTINCT field_key, field_type FROM form_fields ff " +
                "JOIN form_versions fv ON ff.form_version_id = fv.id " +
                "WHERE fv.form_id = ?",
                formId);
        // Build minimal FormFieldEntity list for createTable()
        List<FormFieldEntity> fields = new java.util.ArrayList<>();
        for (Map<String, Object> row : fieldRows) {
            FormFieldEntity f = new FormFieldEntity();
            f.setFieldKey((String) row.get("field_key"));
            f.setFieldType((String) row.get("field_type"));
            fields.add(f);
        }
        createTable(tableName, fields);
        log.info("Recreated missing table '{}' with {} field columns", tableName, fields.size());
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    /** Double-quote an identifier, validating it contains only safe characters. */
    private String q(String identifier) {
        if (!identifier.matches("[a-zA-Z0-9_]+")) {
            throw new IllegalArgumentException("Unsafe SQL identifier rejected: " + identifier);
        }
        return '"' + identifier + '"';
    }

    private String sqlType(String fieldType) {
        String t = SQL_TYPE.get(fieldType);
        if (t == null) {
            throw new IllegalArgumentException("Unknown field type: " + fieldType);
        }
        return t;
    }
}

package com.formbuilder.service;

import com.formbuilder.dto.ValidationError;
import com.formbuilder.entity.FormFieldEntity;
import com.formbuilder.exception.SchemaDriftException;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.*;

/**
 * Core DDL service — creates / alters / drops the physical submission table
 * for each form using raw JdbcTemplate (NOT Hibernate).
 *
 * Table naming: form_<sanitizedFormName>_<6-char-hex>
 * e.g. form_contact_form_a3b8d1
 *
 * Base columns (created in CREATE TABLE):
 * id UUID PRIMARY KEY DEFAULT gen_random_uuid()
 * created_at TIMESTAMP DEFAULT NOW()
 * updated_at TIMESTAMP DEFAULT NOW()
 *
 * Field columns are added via ALTER TABLE ADD COLUMN after table creation.
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class DynamicTableService {

    // Map.ofEntries used because Map.of() is limited to 10 entries
    private static final Map<String, String> SQL_TYPE = Map.ofEntries(
            Map.entry("text", "TEXT"),
            Map.entry("number", "INTEGER"),
            Map.entry("decimal", "NUMERIC"),
            Map.entry("numeric", "NUMERIC"),
            Map.entry("date", "DATE"),
            Map.entry("boolean", "BOOLEAN"),
            // Normalize all string fields to TEXT for easier comparison in drift detection
            Map.entry("dropdown", "TEXT"),
            Map.entry("radio", "TEXT"),
            Map.entry("multiple_choice", "TEXT"),
            Map.entry("linear_scale", "INTEGER"),
            Map.entry("file", "TEXT"),
            Map.entry("multiple_choice_grid", "TEXT"),
            Map.entry("star_rating", "INTEGER"),
            Map.entry("checkbox_grid", "TEXT")
    );

    private final JdbcTemplate jdbc;

    private static final Set<String> RESERVED_KEYWORDS = Set.of(
            "SELECT", "INSERT", "UPDATE", "DELETE", "FROM", "WHERE", "JOIN", "INNER", "LEFT", "RIGHT", "FULL",
            "GROUP", "ORDER", "BY", "HAVING", "LIMIT", "OFFSET", "UNION", "DISTINCT",
            "TABLE", "COLUMN", "INDEX", "PRIMARY", "FOREIGN", "KEY", "CONSTRAINT", "REFERENCES",
            "VIEW", "SEQUENCE", "TRIGGER", "USER", "ROLE", "GRANT", "REVOKE",
            "ID", "CREATED_AT", "UPDATED_AT", "FORM_VERSION_ID", "IS_DRAFT", "IS_SOFT_DELETED", "DELETED_AT"
    );

    private static final Set<String> DRIFT_IGNORED_COLUMNS = Set.of(
            "id", "created_at", "updated_at", "form_version_id", "is_draft", "is_soft_deleted", "deleted_at", "user_id"
    );

    // ── Table Name Generation ─────────────────────────────────────────────────

    /**
     * Converts a human-readable form name or code to a safe PostgreSQL table name.
     * Format: form_data_<code>
     */
    public String generateTableName(String code) {
        String sanitized = code.toLowerCase()
                .replaceAll("[^a-z0-9]+", "_")
                .replaceAll("^_+|_+$", "");
        if (sanitized.isEmpty()) {
            sanitized = "generic_form";
        }
        return "form_data_" + sanitized;
    }

    // ── Public DDL API ────────────────────────────────────────────────────────

    public void validateFieldKey(String key) {
        if (key == null || key.isBlank()) {
            throw new IllegalArgumentException("Field key cannot be empty.");
        }
        if (key.length() > 100) {
            throw new IllegalArgumentException("Field key '" + key + "' exceeds maximum length of 100 characters.");
        }
        if (!key.matches("^[a-z0-9_]+$")) {
            throw new IllegalArgumentException("Field key '" + key + "' must contain only lowercase alphanumeric characters and underscores.");
        }
        if (RESERVED_KEYWORDS.contains(key.toUpperCase())) {
            throw new IllegalArgumentException("Field key '" + key + "' is a reserved keyword and cannot be used.");
        }
    }

    /**
     * Step 1: CREATE TABLE with base columns only.
     * Step 2: ALTER TABLE ADD COLUMN for every field in the form.
     */
    public void createTable(String tableName, List<FormFieldEntity> fields) {
        // Step 1 — base table structure
        String create = """
                CREATE TABLE %s (
                    id              UUID      PRIMARY KEY DEFAULT gen_random_uuid(),
                    form_version_id UUID      NOT NULL,
                    created_at      TIMESTAMP NOT NULL DEFAULT NOW(),
                    updated_at      TIMESTAMP NOT NULL DEFAULT NOW(),
                    is_draft        BOOLEAN   NOT NULL DEFAULT TRUE,
                    is_soft_deleted BOOLEAN   NOT NULL DEFAULT FALSE,
                    deleted_at      TIMESTAMP,
                    user_id         VARCHAR(255)
                )
                """.formatted(q(tableName));
        log.debug("DDL createTable: {}", create.trim());
        jdbc.execute(create);

        // Step 2 — one column per field
        for (FormFieldEntity field : fields) {
            if (!"field_group".equals(field.getFieldType())) {
                addColumn(tableName, field.getFieldKey(), field.getFieldType());
            }
        }
    }

    /**
     * Back-fills status and user_id columns on an existing submission table.
     */
    public void addDraftColumnsIfMissing(String tableName) {
        try {
            jdbc.execute("ALTER TABLE " + q(tableName) +
                    " ADD COLUMN IF NOT EXISTS form_version_id UUID");
            jdbc.execute("ALTER TABLE " + q(tableName) +
                    " ADD COLUMN IF NOT EXISTS is_draft BOOLEAN NOT NULL DEFAULT TRUE");
            jdbc.execute("ALTER TABLE " + q(tableName) +
                    " ADD COLUMN IF NOT EXISTS user_id VARCHAR(255)");
            log.debug("Standard columns ensured for table: {}", tableName);
        } catch (Exception e) {
            log.warn("Could not add standard columns to {}: {}", tableName, e.getMessage());
        }
    }

    /**
     * Back-fills is_soft_deleted and deleted_at columns on an existing submission
     * table
     * that was created before the soft-delete feature was added.
     * Safe to call repeatedly — uses ADD COLUMN IF NOT EXISTS.
     */
    public void addSoftDeleteColumnIfMissing(String tableName) {
        try {
            jdbc.execute("ALTER TABLE " + q(tableName) +
                    " ADD COLUMN IF NOT EXISTS is_soft_deleted BOOLEAN NOT NULL DEFAULT FALSE");
            jdbc.execute("ALTER TABLE " + q(tableName) +
                    " ADD COLUMN IF NOT EXISTS deleted_at TIMESTAMP");
            log.debug("Soft-delete columns ensured for table: {}", tableName);
        } catch (Exception e) {
            log.warn("Could not add soft-delete columns to {}: {}", tableName, e.getMessage());
        }
    }

    /** ALTER TABLE <tableName> ADD COLUMN <fieldKey> <sqlType> */
    public void addColumn(String tableName, String fieldKey, String fieldType) {
        if ("field_group".equals(fieldType))
            return;
        String sql = "ALTER TABLE " + q(tableName)
                + " ADD COLUMN IF NOT EXISTS " + q(fieldKey) + " " + sqlType(fieldType);
        log.debug("DDL addColumn: {}", sql);
        jdbc.execute(sql);
    }

    public void addColumnIfMissing(String tableName, String fieldKey, String fieldType) {
        addColumn(tableName, fieldKey, fieldType);
    }

    /** ALTER TABLE <tableName> DROP COLUMN <fieldKey> */
    public void dropColumn(String tableName, String fieldKey) {
        String sql = "ALTER TABLE " + q(tableName) + " DROP COLUMN IF EXISTS " + q(fieldKey);
        log.debug("DDL dropColumn: {}", sql);
        jdbc.execute(sql);
    }

    /**
     * ALTER TABLE <tableName> ALTER COLUMN <fieldKey> TYPE <newSqlType>
     * USING cast ensures PostgreSQL can coerce existing data.
     */
    public void alterColumnType(String tableName, String fieldKey, String newFieldType) {
        String type = sqlType(newFieldType);
        String sql = "ALTER TABLE " + q(tableName)
                + " ALTER COLUMN " + q(fieldKey)
                + " TYPE " + type
                + " USING " + q(fieldKey) + "::" + type;
        log.debug("DDL alterColumnType: {}", sql);
        jdbc.execute(sql);
    }

    /** DROP TABLE IF EXISTS <tableName> */
    public void dropTable(String tableName) {
        String sql = "DROP TABLE IF EXISTS " + q(tableName);
        log.debug("DDL dropTable: {}", sql);
        jdbc.execute(sql);
    }

    /**
     * S1 — Draft deletion logic.
     * 1. Query form_submission_meta to find linked rows in dynamic tables.
     * 2. Delete linked dynamic rows.
     * 3. Delete meta rows.
     */
    @Transactional
    public void deleteAllDrafts(UUID formId) {
        String queryMeta = "SELECT id, submission_table, submission_row_id FROM form_submission_meta " +
                           "WHERE form_id = ? AND status = 'DRAFT'";
        List<Map<String, Object>> drafts = jdbc.queryForList(queryMeta, formId);

        for (Map<String, Object> draft : drafts) {
            String rawTable = (String) draft.get("submission_table");
            UUID rowId = (UUID) draft.get("submission_row_id");

            // System Rule: Use String.format() with pre-validated table names only
            String sqlDeleteData = String.format("DELETE FROM %s WHERE id = ?", q(rawTable));
            jdbc.update(sqlDeleteData, rowId);
        }

        String sqlDeleteMeta = "DELETE FROM form_submission_meta WHERE form_id = ? AND status = 'DRAFT'";
        jdbc.update(sqlDeleteMeta, formId);
        log.info("S1: Cleaned up {} drafts for formId={}", drafts.size(), formId);
    }

    /**
     * S2 — Passive drift detection (Decision 4.3).
     * Throws SchemaDriftException if metadata and physical schema disagree.
     */
    public void validateSchema(String tableName, UUID versionId) {
        // 1. Get metadata fields
        List<Map<String, Object>> metadataFields = jdbc.queryForList(
                "SELECT field_key, field_type FROM form_fields WHERE form_version_id = ?", versionId);

        // 2. Get actual columns from information_schema
        Map<String, String> actualColumns = new HashMap<>();
        // Postgres information_schema uses lowercase for unquoted table names
        jdbc.query("SELECT column_name, data_type FROM information_schema.columns WHERE table_name = ?",
                (java.sql.ResultSet rs) -> {
                    while (rs.next()) {
                        actualColumns.put(rs.getString("column_name"), rs.getString("data_type").toLowerCase());
                    }
                    return null;
                }, tableName.toLowerCase());

        List<ValidationError> errors = new ArrayList<>();
        Set<String> expectedFieldKeys = new HashSet<>();

        // 3. Metadata -> physical checks (strict)
        for (Map<String, Object> field : metadataFields) {
            String fieldKey = (String) field.get("field_key");
            String fieldType = (String) field.get("field_type");
            expectedFieldKeys.add(fieldKey);

            if (!actualColumns.containsKey(fieldKey)) {
                errors.add(new ValidationError(fieldKey, "Column is missing in physical table"));
                continue;
            }

            String expectedSqlType = sqlType(fieldType).toLowerCase();
            String actualSqlType = actualColumns.get(fieldKey);

            // Strict exact match: even minor type changes must be flagged as drift.
            if (!expectedSqlType.equals(actualSqlType)) {
                errors.add(new ValidationError(
                        fieldKey,
                        String.format("Type mismatch (expected: %s, actual: %s)", expectedSqlType, actualSqlType)
                ));
            }
        }

        // 4. Physical -> metadata checks: detect extra unexpected columns.
        for (String actualCol : actualColumns.keySet()) {
            if (DRIFT_IGNORED_COLUMNS.contains(actualCol)) {
                continue;
            }
            if (!expectedFieldKeys.contains(actualCol)) {
                errors.add(new ValidationError(actualCol, "Unexpected extra column exists in physical table"));
            }
        }

        if (!errors.isEmpty()) {
            throw new SchemaDriftException(String.format(
                    "Decision 4.3 Violation: Physical table '%s' has drifted from metadata in version %s.",
                    tableName, versionId),
                    tableName,
                    versionId,
                    errors);
        }
    }

    /**
     * S3 — Integrity check queries.
     * Query 1: Version mismatch between meta and data table.
     */
    public List<Map<String, Object>> checkVersionMismatches(String tableName) {
        String sql = String.format(
            "SELECT m.id as meta_id, m.form_version_id as meta_v, d.form_version_id as data_v " +
            "FROM form_submission_meta m " +
            "JOIN %s d ON m.submission_row_id = d.id " +
            "WHERE m.form_version_id != d.form_version_id", q(tableName));
        return jdbc.queryForList(sql);
    }

    /**
     * S3 — Integrity check queries.
     * Query 2: Orphaned meta rows.
     */
    public List<Map<String, Object>> checkOrphanedMeta(String tableName) {
        String sql = String.format(
            "SELECT m.id, m.submission_row_id FROM form_submission_meta m " +
            "LEFT JOIN %s d ON m.submission_row_id = d.id " +
            "WHERE m.submission_table = ? AND d.id IS NULL", q(tableName));
        return jdbc.queryForList(sql, tableName);
    }

    /** Check whether a dynamic submission table exists in the database. */
    public boolean tableExists(String tableName) {
        Integer count = jdbc.queryForObject(
                "SELECT COUNT(*) FROM information_schema.tables WHERE table_name = ?",
                Integer.class, tableName);
        return count != null && count > 0;
    }

    /**
     * Ensures the submission table exists. If the table is missing (e.g. DB was
     * recreated but form metadata survived), it is re-created from the field
     * definitions stored in form_fields.
     */
    public void ensureTableExists(String tableName, UUID formId) {
        if (tableExists(tableName)) {
            return;
        }
        log.warn("Submission table '{}' missing — recreating from form_fields for formId={}", tableName, formId);
        // Fetch field definitions via JDBC (no JPA dependency)
        List<Map<String, Object>> fieldRows = jdbc.queryForList(
                "SELECT DISTINCT field_key, field_type FROM form_fields ff " +
                "JOIN form_versions fv ON ff.form_version_id = fv.id " +
                "WHERE fv.form_id = ?",
                formId);
        // Build minimal FormFieldEntity list for createTable()
        List<FormFieldEntity> fields = new java.util.ArrayList<>();
        for (Map<String, Object> row : fieldRows) {
            FormFieldEntity f = new FormFieldEntity();
            f.setFieldKey((String) row.get("field_key"));
            f.setFieldType((String) row.get("field_type"));
            fields.add(f);
        }
        createTable(tableName, fields);
        log.info("Recreated missing table '{}' with {} field columns", tableName, fields.size());
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    /** Double-quote an identifier, validating it contains only safe characters. */
    private String q(String identifier) {
        if (!identifier.matches("[a-zA-Z0-9_]+")) {
            throw new IllegalArgumentException("Unsafe SQL identifier rejected: " + identifier);
        }
        return '"' + identifier + '"';
    }

    private String sqlType(String fieldType) {
        String t = SQL_TYPE.get(fieldType);
        if (t == null) {
            throw new IllegalArgumentException("Unknown field type: " + fieldType);
        }
        return t;
    }
}

import { useState, useRef, useEffect, useMemo } from 'react';
import ValidationEngine from '../services/validation';
import RuleEngine, { setDefaultValues } from '../services/RuleEngine';
import CalculationEngine from '../services/CalculationEngine';
import { getDraft, saveDraft } from '../services/api';
import { toastInfo, showWarning } from '../services/toast';

/**
 * FormRenderer — enterprise dynamic form renderer with Conditional Rule Engine.
 *
 * Rule Engine lifecycle:
 *   Fields load  → withParsedRules()    pre-parses all rulesJson ONCE (not per keystroke)
 *                → buildDependencyMap() maps source→target field relationships
 *                → applyRules()         sets initial field states
 *   onChange     → applyRules() re-evaluates all rules with new values
 *                → cascading setValue handled internally (MAX_PASSES = 5)
 *                → fieldStates drives visible / required / disabled / setValue per field
 *   onSubmit     → validates VISIBLE fields only (hidden = skip validation)
 *                → hidden field VALUES preserved in state and sent to backend
 *                → backend validates independently — never trusts frontend rule state
 *
 * Priority: ascending fieldOrder. Higher order = evaluated later = wins conflicts.
 */
const STATIC_FIELD_TYPES = new Set(['section_header', 'label_text', 'description_block', 'page_break']);

export default function FormRenderer({ form, isPreview = false, onSubmit }) {
  const rawFields = form?.fields || [];

  // Static elements — identified purely by fieldType (isStatic from backend was mis-serialized as "static")
  const staticFields = useMemo(
    () => rawFields.filter(f => STATIC_FIELD_TYPES.has(f.fieldType)),
    [rawFields]
  );

  // Dynamic fields only — everything that is NOT a known static type
  const dynamicRawFields = useMemo(
    () => rawFields.filter(f => !STATIC_FIELD_TYPES.has(f.fieldType)),
    [rawFields]
  );

  // Pre-parse rulesJson once — avoids repeated JSON.parse inside evaluation loops
  const fields = useMemo(() => {
    const withRules = RuleEngine.withParsedRules(dynamicRawFields);
    // Map g.id to fieldKey so RuleEngine can track it, and map groupOrder to fieldOrder for priority
    const groupsWithRules = RuleEngine.withParsedRules((form?.groups || []).map(g => ({
      ...g,
      fieldKey: g.id,
      fieldOrder: g.groupOrder ?? 0
    })));
    return [...withRules, ...groupsWithRules];
  }, [dynamicRawFields, form?.groups]);

  // Dependency map: { sourceKey → Set<targetKey> }
  // eslint-disable-next-line no-unused-vars
  const depMap = useMemo(() => RuleEngine.buildDependencyMap(fields), [fields]);

  // ── Build initial values from field defaults ───────────────────────────────
  function makeInitialValues() {
    return Object.fromEntries(
      fields.map((f) => [
        f.fieldKey,
        f.fieldType === 'boolean'
          ? (f.defaultValue === 'true' || f.defaultValue === true)
          : (f.defaultValue || ''),
      ])
    );
  }

  const [values, setValues] = useState(makeInitialValues);
  const [errors, setErrors] = useState({});  // { fieldKey: string[] }
  const [touched, setTouched] = useState({});  // { fieldKey: boolean }
  const [fieldStates, setFieldStates] = useState(() => RuleEngine.applyRules(fields, makeInitialValues()));
  const [serverError, setServerError] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [lastSaved, setLastSaved] = useState(null); // timestamp of last autosave
  const [saving, setSaving] = useState(false);

  // ── Wizard (multi-step) state ──────────────────────────────────────────────
  const [currentPage, setCurrentPage] = useState(0);

  /**
   * Split all renderable items (dynamic + static) sorted by fieldOrder into pages.
   * A page_break static element acts as the divider — it is consumed and NOT rendered.
   * pages = [ { items: [...], title: string|null }, ... ]
   *
   * Detection: item.fieldType === 'page_break' (works for both render-endpoint
   * responses where isStatic=true AND builder-preview where field comes through staticFields).
   */
  const pages = useMemo(() => {
    // Merge dynamic fields + ALL static fields (including page_break) + groups, sort by fieldOrder
    // Use dynamicRawFields instead of fields to prevent mapping the groups inside fields array
    const allItems = [
      ...dynamicRawFields.map(f => ({ ...f, _renderType: 'dynamic' })),
      ...staticFields.map(f => ({ ...f, _renderType: 'static' })),
      ...(form?.groups || []).map(g => ({ ...g, _renderType: 'group', fieldOrder: g.groupOrder }))
    ].sort((a, b) => (a.fieldOrder ?? 0) - (b.fieldOrder ?? 0));

    const result = [];
    let currentPageItems = [];
    let currentPageTitle = null;

    for (const item of allItems) {
      // Detect page break by fieldType (primary) — works regardless of isStatic flag
      if (item.fieldType === 'page_break') {
        // Push everything collected so far as a completed page
        result.push({ items: currentPageItems, title: currentPageTitle });
        currentPageItems = [];
        // The page_break's data/staticData becomes the NEXT page's title
        currentPageTitle = item.staticData || item.data || item.label || null;
      } else {
        currentPageItems.push(item);
      }
    }
    // Always push the final (or only) page
    result.push({ items: currentPageItems, title: currentPageTitle });

    return result;
  }, [fields, staticFields]);

  const totalPages = pages.length;
  const isMultiStep = totalPages > 1;
  const isFirstPage = currentPage === 0;
  const isLastPage = currentPage === totalPages - 1;

  // File objects stored in ref (avoids stale-closure issues in async handlers)
  const filesRef = useRef({});

  // Keep a ref to current values so async handlers always read the latest
  const valuesRef = useRef(values);
  useEffect(() => { valuesRef.current = values; }, [values]);

  // Re-initialise when fields change (async load or form switch)
  useEffect(() => {
    const initial = makeInitialValues();

    // 1. Initial Rules
    const initialStates = RuleEngine.applyRules(fields, initial);
    let currentValues = { ...initial };
    for (const [key, st] of Object.entries(initialStates)) {
      if (st.setValue !== null) currentValues[key] = st.setValue;
      if (st.copyValue !== null) currentValues[key] = st.copyValue;
    }

    // 2. Initial Calculations
    let calculated = currentValues;
    try {
      calculated = CalculationEngine.recalculateCalculatedFields(fields, currentValues);
    } catch (err) {
      console.warn('[FormRenderer] Initial calculation error:', err.message);
    }

    // 3. Re-run rules if calculations changed values (cascade)
    const finalStates = RuleEngine.applyRules(fields, calculated);

    setDefaultValues(calculated); // snapshot for 'changed' operator (v2)
    setValues(calculated);
    valuesRef.current = calculated;
    filesRef.current = {};
    setErrors({});
    setTouched({});
    setFieldStates(finalStates);
    setCurrentPage(0); // reset wizard to first page
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [fields]);

  // ── Draft Retrieval ──────────────────────────────────────────────────────
  useEffect(() => {
    if (isPreview || !form?.id) return;

    async function fetchDraft() {
      try {
        const draft = await getDraft(form.id);
        if (draft && Object.keys(draft).length > 0) {
          // Merge draft values with initial values (in case form schema changed)
          const draftValues = { ...valuesRef.current };
          for (const field of fields) {
            if (draft[field.fieldKey] !== undefined && draft[field.fieldKey] !== null) {
              draftValues[field.fieldKey] = draft[field.fieldKey];
            }
          }

          // Re-apply rules and calculations based on draft data
          const states = RuleEngine.applyRules(fields, draftValues);
          let calculated = draftValues;
          try {
            calculated = CalculationEngine.recalculateCalculatedFields(fields, draftValues);
          } catch (err) {
            console.warn('[FormRenderer] Draft calculation error:', err.message);
          }
          const finalStates = RuleEngine.applyRules(fields, calculated);

          setValues(calculated);
          valuesRef.current = calculated;
          setFieldStates(finalStates);
          setLastSaved(new Date(draft.updated_at || Date.now()));

          // Ensure flag is set if we successfully loaded a draft
          localStorage.setItem(`draft_form_${form.id}`, 'true');
        } else {
          // No draft returned from backend. Check if we EXPECTED one (F2 requirement)
          const hadDraft = localStorage.getItem(`draft_form_${form.id}`);
          if (hadDraft) {
            showWarning('Your previous draft was discarded because the form was updated to a new version. Please review the fields.');
            localStorage.removeItem(`draft_form_${form.id}`);
          }
        }
      } catch (err) {
        if (err?.status === 404) {
           const hadDraft = localStorage.getItem(`draft_form_${form.id}`);
           if (hadDraft) {
             showWarning('Your previous draft was discarded because the form was updated to a new version.');
             localStorage.removeItem(`draft_form_${form.id}`);
           }
        }
        console.warn('Failed to fetch draft:', err);
      }
    }
    fetchDraft();
  }, [form?.id, isPreview, form?.formVersionId]);

  // ── Autosave Logic ───────────────────────────────────────────────────────
  const lastSavedValuesRef = useRef(values);

  useEffect(() => {
    if (isPreview || submitted || !form?.id) return;

    const timer = setInterval(async () => {
      const currentValues = valuesRef.current;
      // Only save if data has actually changed
      if (JSON.stringify(currentValues) === JSON.stringify(lastSavedValuesRef.current)) {
        return;
      }

      setSaving(true);
      try {
        // [F3] Compliance: formVersionId from React state (form object) only
        await saveDraft(form.id, currentValues, null, form.formVersionId);
        setLastSaved(new Date());
        lastSavedValuesRef.current = currentValues;
        // Signal that a draft now exists for this form
        localStorage.setItem(`draft_form_${form.id}`, 'true');
      } catch (err) {
        console.warn('Autosave failed:', err);
      } finally {
        setSaving(false);
      }
    }, 10000); // 10 seconds

    return () => clearInterval(timer);
  }, [form?.id, isPreview, submitted]);

  // Handle manual save on page navigate away
  useEffect(() => {
    if (isPreview || submitted || !form?.id) return;

    const handleBeforeUnload = () => {
      const currentValues = valuesRef.current;
      if (JSON.stringify(currentValues) !== JSON.stringify(lastSavedValuesRef.current)) {
        // [F3] Compliance: formVersionId from React state only
        saveDraft(form.id, currentValues, null, form.formVersionId).catch(() => { });
        localStorage.setItem(`draft_form_${form.id}`, 'true');
      }
    };

    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [form?.id, isPreview, submitted]);

  // ── onChange — live validation + rule re-evaluation on every keystroke ─────
  function handleChange(field, value) {
    // 1. Update formValues state (stage 1)
    let currentValues = { ...valuesRef.current, [field.fieldKey]: value };

    // 2. Update file ref — store FileList or single File
    if (field.fieldType === 'file') {
      if (value instanceof FileList) {
        filesRef.current = { ...filesRef.current, [field.fieldKey]: value };
      } else if (value instanceof File) {
        filesRef.current = { ...filesRef.current, [field.fieldKey]: value };
      }
    }

    // 3. Run RuleEngine.applyRules() (Rules before Calc)
    let currentStates = RuleEngine.applyRules(fields, currentValues);

    // 4. Apply setValue/copyValue overrides from rules
    for (const [key, st] of Object.entries(currentStates)) {
      if (st.setValue !== null && String(currentValues[key] ?? '') !== String(st.setValue)) {
        currentValues[key] = st.setValue;
      }
      if (st.copyValue !== null && String(currentValues[key] ?? '') !== String(st.copyValue)) {
        currentValues[key] = st.copyValue;
      }
    }

    // 5. Run CalculationEngine.recalculate()
    let calculatedValues = currentValues;
    try {
      calculatedValues = CalculationEngine.recalculateCalculatedFields(fields, currentValues);
    } catch (err) {
      // Logic: if a formula results in division by zero (e.g. while typing), just keep the current values.
      console.warn('[FormRenderer] Calculation error:', err.message);
    }

    // If calculations changed values, we might need a quick re-run of rules to update UI state (visible/required)
    // based on the new calculated values.
    if (JSON.stringify(calculatedValues) !== JSON.stringify(currentValues)) {
      currentStates = RuleEngine.applyRules(fields, calculatedValues);
      currentValues = calculatedValues;
    }

    // 6. Final State Updates
    setFieldStates(currentStates);
    setValues(currentValues);
    valuesRef.current = currentValues;

    // 7. Validate changed field using rule-adjusted required flag
    const effectiveField = {
      ...field,
      required: currentStates[field.fieldKey]?.required ?? field.required,
    };
    const errs = ValidationEngine.validateFieldSync(
      effectiveField, currentValues[field.fieldKey], currentValues, filesRef.current
    );
    setErrors((prev) => ({ ...prev, [field.fieldKey]: errs }));

    // 8. Mark field touched
    setTouched((prev) => ({ ...prev, [field.fieldKey]: true }));

    // 9. Clear server banner
    if (serverError) setServerError('');
  }

  // ── onBlur — ensure touched is set so error persists ──────────────────────
  function handleBlur(field, value) {
    setTouched((prev) => ({ ...prev, [field.fieldKey]: true }));
    // Re-run validation on blur (catches paste/autofill that skips onChange)
    const effectiveField = {
      ...field,
      required: fieldStates[field.fieldKey]?.required ?? field.required,
    };
    const errs = ValidationEngine.validateFieldSync(effectiveField, value, valuesRef.current, filesRef.current);
    setErrors((prev) => ({ ...prev, [field.fieldKey]: errs }));
  }

  // ── Wizard Next — validate current page's visible dynamic fields then advance ─
  const handleNext = async () => {
    // Mark only current page's dynamic fields as touched
    const currentDynamic = (pages[currentPage]?.items || []).filter(f => f._renderType === 'dynamic');
    const pageTouched = Object.fromEntries(currentDynamic.map(f => [f.fieldKey, true]));
    setTouched(prev => ({ ...prev, ...pageTouched }));

    // Validate only visible fields on current page
    const visiblePageFields = currentDynamic
      .filter(f => {
        if (fieldStates[f.fieldKey]?.visible === false) return false;
        if (f.groupId && fieldStates[f.groupId]?.visible === false) return false;
        return true;
      })
      .map(f => {
        const fieldSt = fieldStates[f.fieldKey] || {};
        const groupSt = f.groupId ? fieldStates[f.groupId] : null;
        const effectiveRequired =
          groupSt?.required === true ? true :
            groupSt?.required === false ? false :
              (fieldSt.required ?? f.required);
        return { ...f, required: effectiveRequired };
      });

    const pageErrors = await ValidationEngine.validateForm(visiblePageFields, valuesRef.current, filesRef.current);
    setErrors(prev => ({ ...prev, ...pageErrors }));

    if (Object.keys(pageErrors).length > 0) {
      const firstKey = Object.keys(pageErrors)[0];
      const el = document.getElementById(`field-${firstKey}`);
      if (el) { el.scrollIntoView({ behavior: 'smooth', block: 'center' }); el.focus(); }
      return;
    }

    // Advance to next page and scroll to top of form
    setCurrentPage(p => Math.min(p + 1, totalPages - 1));
    setServerError('');
    const card = document.querySelector('.form-renderer-card');
    if (card) card.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  const handleBack = () => {
    setCurrentPage(p => Math.max(p - 1, 0));
    setServerError('');
    const card = document.querySelector('.form-renderer-card');
    if (card) card.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  // ── onSubmit — full async validation, block if any errors ─────────────────
  const handleSubmit = async (e) => {
    e.preventDefault();

    // Guard: never submit if there are more pages ahead (wizard safety net)
    if (isMultiStep && !isLastPage) {
      handleNext();
      return;
    }

    // Mark all fields as touched so all errors become visible
    const allTouched = Object.fromEntries(fields.map((f) => [f.fieldKey, true]));
    setTouched(allTouched);

    // Validate VISIBLE fields only — hidden fields skip validation.
    // Hidden field VALUES are preserved in state and sent to backend.
    // Backend validates all required constraints independently of rule state.
    const visibleFields = fields
      .filter(f => {
        if (fieldStates[f.fieldKey]?.visible === false) return false;
        if (f.groupId && fieldStates[f.groupId]?.visible === false) return false;
        return true;
      })
      .map(f => {
        const fieldSt = fieldStates[f.fieldKey] || {};
        const groupSt = f.groupId ? fieldStates[f.groupId] : null;
        const effectiveRequired =
          groupSt?.required === true ? true :
            groupSt?.required === false ? false :
              (fieldSt.required ?? f.required);
        return { ...f, required: effectiveRequired };
      });

    const allErrors = await ValidationEngine.validateForm(visibleFields, valuesRef.current, filesRef.current);
    setErrors(allErrors);
    setServerError('');

    if (Object.keys(allErrors).length > 0) {
      // Scroll + focus first error field
      const firstKey = Object.keys(allErrors)[0];
      const el = document.getElementById(`field-${firstKey}`);
      if (el) { el.scrollIntoView({ behavior: 'smooth', block: 'center' }); el.focus(); }
      return;
    }

    // ── All valid — submit ───────────────────────────────────────────────────
    if (isPreview) {
      toastInfo(" Preview Mode: Form validation passed! Actual submission is disabled in preview mode.");
      return;
    }

    setSubmitting(true);
    try {
      const currentValues = valuesRef.current;
      const hasFile = fields.some(
        (f) => f.fieldType === 'file' &&
          (filesRef.current[f.fieldKey] instanceof File ||
            filesRef.current[f.fieldKey] instanceof FileList)
      );

      if (hasFile) {
        const fd = new FormData();
        for (const [key, val] of Object.entries(currentValues)) {
          const fileVal = filesRef.current[key];
          if (fileVal instanceof FileList) {
            // Append every file with the same key so backend receives all
            for (let i = 0; i < fileVal.length; i++) {
              fd.append(key, fileVal[i]);
            }
          } else if (fileVal instanceof File) {
            fd.append(key, fileVal);
          } else if (val != null) {
            fd.append(key, val);
          }
        }
        await onSubmit(fd);
      } else {
        await onSubmit(currentValues);
      }

      setSubmitted(true);
      localStorage.removeItem(`draft_form_${form.id}`); // Requirement [E9]
    } catch (err) {
      if (err?.errors && Array.isArray(err.errors)) {
        const fieldErrs = {};
        const unmatched = [];

        for (const error of err.errors) {
          // Backend sends { field: fieldKey, message: string }
          if (error && typeof error === 'object' && error.field && error.message) {
            const key = error.field;
            if (key === '__general__' || key === 'form' || key === 'general') {
              unmatched.push(error.message);
            } else {
              // Match by fieldKey directly (primary) or label (fallback)
              const matchedField = fields.find(
                (f) => f.fieldKey === key || f.label === key
              );
              const targetKey = matchedField ? matchedField.fieldKey : key;
              if (!fieldErrs[targetKey]) fieldErrs[targetKey] = [];
              fieldErrs[targetKey].push(error.message);
            }
          } else if (typeof error === 'string') {
            unmatched.push(error);
          }
        }

        if (Object.keys(fieldErrs).length) {
          setErrors(fieldErrs);
          // Mark all backend-errored fields as touched so errors show
          const newTouched = Object.fromEntries(Object.keys(fieldErrs).map((k) => [k, true]));
          setTouched((prev) => ({ ...prev, ...newTouched }));
          const firstKey = Object.keys(fieldErrs)[0];
          const el = document.getElementById(`field-${firstKey}`);
          if (el) { el.scrollIntoView({ behavior: 'smooth', block: 'center' }); el.focus(); }
        }
        if (unmatched.length) {
          setServerError(unmatched.join(' · '));
        } else if (Object.keys(fieldErrs).length) {
          // If we have field errors but no unmatched, still show a friendly top-level reminder
          const count = Object.keys(fieldErrs).length;
          setServerError(`Please fix the ${count} field${count > 1 ? 's' : ''} highlighted below.`);
        }
      } else {
        setServerError(err?.message || 'Submission failed. Please try again.');
      }
    } finally {
      setSubmitting(false);
    }
  };

  // ── Success screen ─────────────────────────────────────────────────────────
  if (submitted) {
    return (
      <div className="form-renderer-card">
        <div className="form-success-state">
          <div className="success-icon-ring">✓</div>
          <h2>Submitted Successfully!</h2>
          <p>Thank you — your response has been recorded.</p>
          <button
            className="btn btn-secondary success-another-btn"
            onClick={() => {
              const fresh = makeInitialValues();
              setValues(fresh);
              valuesRef.current = fresh;
              filesRef.current = {};
              setErrors({});
              setTouched({});
              setFieldStates(RuleEngine.applyRules(fields, fresh));
              setSubmitted(false);
            }}
          >
            Submit another response
          </button>
        </div>
      </div>
    );
  }

  // ── Main render ────────────────────────────────────────────────────────────
  return (
    <div className="form-renderer-card">
      {isPreview && (
        <div className="preview-banner">
          &nbsp;<strong>Preview Mode</strong> — submissions are disabled
        </div>
      )}

      <div className="form-renderer-header">
        <h1 className="form-renderer-title">{form.name}</h1>
        {form.description && <p className="form-renderer-desc">{form.description}</p>}
        <div className="form-renderer-meta">
          <span className="form-renderer-meta-item">
             {fields.length} field{fields.length !== 1 ? 's' : ''}
          </span>
          {fields.some((f) => f.required) && (
            <span className="form-renderer-meta-item">
              <span className="form-field-required-star">*</span> Required fields marked
            </span>
          )}
          {lastSaved && (
            <span className="form-renderer-meta-item draft-indicator">
              {saving ? (
                <><span className="spinner-micro" /> Saving draft…</>
              ) : (
                <>✔ Draft saved at {lastSaved.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</>
              )}
            </span>
          )}
        </div>
      </div>

      {serverError && (
        <div className={`auth-error ${serverError.includes('fixed') || serverError.includes('highlighted') ? 'validation-summary-banner' : ''}`} 
             style={{ margin: '0 32px 24px', borderRadius: 12, padding: '16px 20px', border: '1px solid rgba(239,68,68,0.2)' }}>
          <div style={{ display: 'flex', gap: '12px', alignItems: 'center' }}>
            <span style={{ fontSize: '20px' }}>⚠️</span>
            <div style={{ flex: 1 }}>
              <strong style={{ display: 'block', marginBottom: '4px', color: '#ff8e8e', fontSize: '15px' }}>
                Form Validation Failed
              </strong>
              <div style={{ fontSize: '14px', opacity: 0.9 }}>{serverError}</div>
            </div>
          </div>
        </div>
      )}


      {/* ── Wizard Progress Bar (only when multi-step) ────────────────────── */}
      {isMultiStep && (
        <div className="wizard-progress-bar">
          <div className="wizard-steps-track">
            {pages.map((page, idx) => (
              <div key={idx} className="wizard-step-wrapper">
                <div className={`wizard-step-dot ${idx < currentPage ? 'completed' : ''} ${idx === currentPage ? 'active' : ''}`}>
                  {idx < currentPage ? <span>✓</span> : <span>{idx + 1}</span>}
                </div>
                {idx < totalPages - 1 && (
                  <div className={`wizard-step-connector ${idx < currentPage ? 'completed' : ''}`} />
                )}
              </div>
            ))}
          </div>
          <div className="wizard-page-label">
            {pages[currentPage]?.title
              ? <span className="wizard-page-title">Step {currentPage + 1}: {pages[currentPage].title}</span>
              : <span>Page {currentPage + 1} of {totalPages}</span>
            }
          </div>
        </div>
      )}

      <form onSubmit={handleSubmit} noValidate>
        {fields.length === 0 && staticFields.length === 0 ? (
          <div className="form-empty-state">This form has no fields yet.</div>
        ) : (
          <div className="form-renderer-body">
            {/* Render fields with group hierarchy support */}
            {(() => {
              const currentItems = pages[currentPage]?.items || [];
              const topLevelItems = currentItems.filter(f => !f.parentGroupKey && !f.groupId);
              const childrenByParent = {};

              currentItems.forEach(f => {
                const parentId = f.groupId || f.parentGroupKey;
                if (parentId) {
                  if (!childrenByParent[parentId]) childrenByParent[parentId] = [];
                  childrenByParent[parentId].push(f);
                }
              });

              // Ensure children are sorted correctly within the group
              Object.values(childrenByParent).forEach(arr => arr.sort((a, b) => (a.fieldOrder ?? 0) - (b.fieldOrder ?? 0)));

              const renderField = (field, index = 0) => {
                // ── Group Container (New Architecture) ───────────────────
                if (field._renderType === 'group') {
                  const children = childrenByParent[field.id] || [];
                  const groupSt = fieldStates[field.id] || {};

                  // If the group itself is hidden by a rule, skip it and all children
                  if (groupSt.visible === false) return null;

                  return (
                    <div key={field.id} className="field-group-container" style={{ position: 'relative', zIndex: 100 - index }}>
                      <h3 className="field-group-title">{field.groupTitle || 'Untitled Section'}</h3>
                      {field.groupDescription && <p className="field-group-desc">{field.groupDescription}</p>}
                      <div className="field-group-children">
                        {children.map((f, i) => renderField(f, i))}
                      </div>
                    </div>
                  );
                }

                // ── Static elements — display only ───────────────────────
                if (field._renderType === 'static') {
                  return (
                    <StaticElement
                      key={field.fieldKey || field.id || `static-${field.fieldOrder}`}
                      field={field}
                    />
                  );
                }

                // ── Dynamic fields ───────────────────────────────────────
                const st = fieldStates[field.fieldKey] || {};

                // Hidden fields — render nothing, value preserved in state
                if (st.visible === false) return null;

                // Also check if this field belongs to a group that is currently hidden
                if (field.groupId && fieldStates[field.groupId]?.visible === false) {
                  return null;
                }

                // ── Field Group Container (Legacy Support) ───────────────
                if (field.fieldType === 'field_group') {
                  const children = childrenByParent[field.fieldKey] || [];
                  return (
                    <div key={field.id || field.fieldKey} className="field-group-container" style={{ position: 'relative', zIndex: 100 - index }}>
                      {field.label && <h3 className="field-group-title">{st.label ?? field.label}</h3>}
                      <div className="field-group-children">
                        {children.map((f, i) => renderField(f, i))} // Recursive mapping with descending zIndexes
                      </div>
                    </div>
                  );
                }

                // Effective value: copyValue > setValue > user input (priority order)
                const effectiveValue =
                  st.copyValue !== null && st.copyValue !== undefined
                    ? st.copyValue
                    : st.setValue !== null && st.setValue !== undefined
                      ? st.setValue
                      : values[field.fieldKey];

                const groupSt = field.groupId ? fieldStates[field.groupId] : null;
                const effectiveRequired =
                  groupSt?.required === true ? true :
                    groupSt?.required === false ? false :
                      (st.required ?? field.required);

                return (
                  <div key={field.id || field.fieldKey} style={{ position: 'relative', zIndex: 100 - index }}>
                    <FieldInput
                      field={{ ...field, required: effectiveRequired }}
                      value={effectiveValue}
                      errors={errors[field.fieldKey] || []}
                      touched={!!touched[field.fieldKey]}
                      onChange={(val) => handleChange(field, val)}
                      onBlur={(val) => handleBlur(field, val)}
                      disabled={
                        !!st.disabled ||
                        !!field.disabled ||
                        !!field.readOnly ||
                        !!field.lockAfterCalculation ||
                        (field.groupId && fieldStates[field.groupId]?.disabled === true)
                      }
                      filterOptions={st.filterOptions ?? null}
                      min={st.min ?? null}
                      max={st.max ?? null}
                      labelOverride={st.label ?? null}
                      placeholderOverride={st.placeholder ?? null}
                    />
                  </div>
                );
              };

              return topLevelItems.map((f, i) => renderField(f, i));
            })()}
          </div>
        )}

        {/* Hidden submit trigger — only used on last page */}
        <button type="submit" id="__form-submit-hidden__" style={{ display: 'none' }} aria-hidden="true" />
      </form>

      {/* ── Footer: Back / Next / Submit — OUTSIDE <form> to prevent accidental submission ── */}
      <div className={`form-renderer-footer${isMultiStep ? ' wizard-footer' : ''}`}>
        {isMultiStep && !isFirstPage && (
          <button
            type="button"
            className="btn btn-secondary wizard-back-btn"
            onClick={handleBack}
            disabled={submitting}
          >
            ← Back
          </button>
        )}

        {isMultiStep && !isLastPage ? (
          /* Next button — validates current page then advances */
          <button
            type="button"
            id="wizard-next-btn"
            className="form-submit-btn"
            onClick={handleNext}
            disabled={submitting}
            style={{ marginLeft: 'auto' }}
          >
            Next →
          </button>
        ) : (
          /* Submit button — triggers the hidden submit inside <form> */
          <button
            type="button"
            id="form-submit-btn"
            className="form-submit-btn"
            disabled={submitting || fields.length === 0}
            style={isMultiStep ? { marginLeft: 'auto' } : undefined}
            onClick={() => {
              const hidden = document.getElementById('__form-submit-hidden__');
              if (hidden) hidden.click();
            }}
          >
            {submitting ? (
              <><span className="spinner" style={{ borderTopColor: '#fff', width: 18, height: 18 }} /> Submitting…</>
            ) : isPreview ? (
              ' Preview Mode — Submit Disabled'
            ) : (
              'Submit Form →'
            )}
          </button>
        )}
      </div>
    </div>
  );
}

// ─── StaticElement ────────────────────────────────────────────────────────────
/**
 * Renders a static UI element — section_header, label_text, description_block.
 * Never collects input, never validated, never included in submission payload.
 */
function StaticElement({ field }) {
  // staticData from /render endpoint, or label as fallback (legacy)
  const content = field.staticData || field.label || field.data || '';

  if (field.fieldType === 'section_header') {
    return (
      <div className="static-section-header">
        <h3 className="static-section-header-text">{content}</h3>
        <div className="static-section-header-line" />
      </div>
    );
  }

  if (field.fieldType === 'label_text') {
    return (
      <div className="static-label-text">
        <p className="static-label-text-content">{content}</p>
      </div>
    );
  }

  if (field.fieldType === 'description_block') {
    return (
      <div className="static-description-block">
        <p className="static-description-block-content">{content}</p>
      </div>
    );
  }

  return null;
}

// ─── FieldInput ───────────────────────────────────────────────────────────────
/**
 * Renders a single form field.
 *
 * errors            = string[]      (all validation messages for this field)
 * touched           = boolean       (true once user has interacted)
 * filterOptions     = string[]|null (NEW v2) allowed option values; null = show all
 * min/max           = number|null   (NEW v2) dynamic bounds for number/date fields
 * labelOverride     = string|null   (NEW v2) runtime label override
 * placeholderOverride = string|null (NEW v2) runtime placeholder override
 *
 * Shows the FIRST (highest-priority) error only for clean UX.
 */
function FieldInput({ field, value, errors, touched, onChange, onBlur, disabled,
  filterOptions, min, max, labelOverride, placeholderOverride }) {
  const id = `field-${field.fieldKey}`;
  const errorList = Array.isArray(errors) ? errors : [];
  const shownError = touched && errorList.length > 0 ? errorList[0] : null;
  const hasError = !!shownError;
  const inputClass = `form-input${hasError ? ' input-error' : ''}`;

  // ── NEW (v2): resolve effective label and placeholder ──────────────────────
  const effectiveLabel = labelOverride ?? field.label;
  const effectivePlaceholder = placeholderOverride
    ?? (field.defaultValue ? `e.g. ${field.defaultValue}` : `Enter ${field.label.toLowerCase()}…`);

  // ── NEW (v2): filter helper for dropdown / radio ───────────────────────────
  function filterOpts(rawOpts) {
    if (!filterOptions || filterOptions.length === 0) return rawOpts;
    return rawOpts.filter(o =>
      filterOptions.includes(o.value) || filterOptions.includes(o.label)
    );
  }

  return (
    <div className="form-field-group" style={{
      animationDelay: `${(field.fieldOrder || 0) * 40}ms`,
      position: 'relative',
      zIndex: 100 - (field.fieldOrder || 0)
    }}>

      {/* Label */}
      {field.fieldType !== 'boolean' && (
        <label className="form-field-label" htmlFor={id}>
          {effectiveLabel}
          {field.required && <span className="form-field-required-star" title="Required"> *</span>}
          {field.isCalculated && <span className="badge badge-text" style={{ marginLeft: 8, background: 'rgba(99,102,241,0.1)', color: 'var(--accent)', fontSize: '0.7em', padding: '2px 6px' }}>∑ Calculated</span>}
        </label>
      )}

      {/* ── text ───────────────────────────────────────────────── */}
      {field.fieldType === 'text' && (
        <input
          id={id}
          type="text"
          className={inputClass}
          value={value || ''}
          onChange={(e) => onChange(e.target.value)}
          onBlur={(e) => onBlur(e.target.value)}
          placeholder={effectivePlaceholder}
          disabled={disabled}
          autoComplete="off"
          aria-describedby={hasError ? `${id}-err` : undefined}
          aria-invalid={hasError || undefined}
        />
      )}

      {/* ── number ─────────────────────────────────────────────── */}
      {field.fieldType === 'number' && (
        <input
          id={id}
          type="number"
          className={inputClass}
          value={value || ''}
          onChange={(e) => onChange(e.target.value)}
          onBlur={(e) => onBlur(e.target.value)}
          placeholder={placeholderOverride ?? (field.defaultValue || '')}
          min={min ?? undefined}
          max={max ?? undefined}
          disabled={disabled}
          aria-describedby={hasError ? `${id}-err` : undefined}
          aria-invalid={hasError || undefined}
        />
      )}

      {/* ── date ───────────────────────────────────────────────── */}
      {field.fieldType === 'date' && (() => {
        // Parse the configured display format from validationJson
        let customFormat = 'YYYY-MM-DD';
        try {
          const rules = JSON.parse(field.validationJson || '{}');
          if (rules.customFormat) customFormat = rules.customFormat;
        } catch { }

        return (
          <>
            <input
              id={id}
              type="date"
              className={inputClass}
              value={value || ''}
              onChange={(e) => onChange(e.target.value)}
              onBlur={(e) => onBlur(e.target.value)}
              min={min ?? undefined}
              max={max ?? undefined}
              disabled={disabled}
              aria-describedby={hasError ? `${id}-err` : undefined}
              aria-invalid={hasError || undefined}
            />
            {customFormat && customFormat !== 'YYYY-MM-DD' && (
              <span className="form-field-hint">
                 Display format: {customFormat}
              </span>
            )}
          </>
        );
      })()}

      {/* ── boolean ────────────────────────────────────────────── */}
      {field.fieldType === 'boolean' && (
        <label
          className={`bool-toggle-wrap${disabled ? ' opacity-50' : ''}${hasError ? ' bool-toggle-error' : ''}`}
          htmlFor={id}
        >
          <input
            id={id}
            type="checkbox"
            checked={!!value}
            onChange={(e) => { onChange(e.target.checked); onBlur(e.target.checked); }}
            disabled={disabled}
            aria-invalid={hasError || undefined}
          />
          <span className="bool-toggle-label">
            {effectiveLabel}
            {field.required && <span className="form-field-required-star"> *</span>}
          </span>
        </label>
      )}

      {/* ── dropdown (single or multi) ─────────────────────────── */}
      {field.fieldType === 'dropdown' && (() => {
        let isMulti = false;
        try {
          const uiCfg = JSON.parse(field.uiConfigJson || '{}');
          isMulti = !!uiCfg.multiple;
        } catch { }

        const options = filterOpts(parseOptions(field.optionsJson, field.options));

        if (!isMulti) {
          return (
            <select
              id={id}
              className={`form-select${hasError ? ' input-error' : ''}`}
              value={value || ''}
              onChange={(e) => onChange(e.target.value)}
              onBlur={(e) => onBlur(e.target.value)}
              disabled={disabled}
              aria-describedby={hasError ? `${id}-err` : undefined}
              aria-invalid={hasError || undefined}
            >
              <option value="">— Select {effectiveLabel} —</option>
              {options.map((opt, i) => (
                <option key={i} value={opt.value}>{opt.label}</option>
              ))}
            </select>
          );
        }

        // ── Custom Multi-Select Dropdown ──
        // Parse current value string array
        let selected = [];
        if (value) {
          const str = String(value).trim();
          if (str.startsWith('[')) {
            try { selected = JSON.parse(str); } catch { selected = []; }
          } else {
            selected = str.split(',').map(v => v.trim()).filter(Boolean);
          }
        }

        const [isOpen, setIsOpen] = useState(false);
        const dropdownRef = useRef(null);

        // Handle outside click
        useEffect(() => {
          const handleClickOutside = (event) => {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
              setIsOpen(false);
              onBlur(value);
            }
          };
          if (isOpen) {
            document.addEventListener("mousedown", handleClickOutside);
          } else {
            document.removeEventListener("mousedown", handleClickOutside);
          }
          return () => document.removeEventListener("mousedown", handleClickOutside);
        }, [isOpen, onBlur, value]);

        const handleRemove = (e, valToRemove) => {
          e.stopPropagation();
          if (disabled) return;
          const nextSelected = selected.filter(v => v !== valToRemove);
          onChange(nextSelected); // Pass the array directly, not stringified
        };

        const handleSelect = (valToAdd) => {
          if (disabled) return;
          let nextSelected;
          if (selected.includes(valToAdd)) {
            nextSelected = selected.filter(v => v !== valToAdd);
          } else {
            nextSelected = [...selected, valToAdd];
          }
          onChange(nextSelected); // Pass the array directly
          // keep open to allow multiple selections
        };

        return (
          <div ref={dropdownRef} style={{ position: 'relative', zIndex: isOpen ? 99 : 1 }}>
            <div
              className={`form-select${hasError ? ' input-error' : ''}`}
              style={{
                display: 'flex', flexWrap: 'wrap', gap: '6px', minHeight: '44px', paddingBottom: '7px', paddingTop: '7px',
                alignItems: 'center', cursor: disabled ? 'not-allowed' : 'pointer',
                opacity: disabled ? 0.6 : 1
              }}
              onClick={() => !disabled && setIsOpen(!isOpen)}
            >
              {selected.length === 0 ? (
                <span style={{ color: 'var(--text-muted)' }}>— Select {effectiveLabel} —</span>
              ) : (
                selected.map((val) => {
                  const optLabel = options.find(o => o.value === val)?.label || val;
                  return (
                    <span key={val} style={{
                      display: 'inline-flex', alignItems: 'center', gap: '4px',
                      padding: '2px 8px', borderRadius: '12px', fontSize: '13px',
                      background: 'rgba(99,102,241,0.15)', color: '#EDE9FF', border: '1px solid rgba(99,102,241,0.3)',
                    }}>
                      {optLabel}
                      <button
                        type="button"
                        onClick={(e) => handleRemove(e, val)}
                        style={{
                          background: 'none', border: 'none', color: '#9899BA', cursor: 'pointer', fontSize: '12px',
                          padding: 0, marginLeft: '2px', lineHeight: 1
                        }}
                      >✕</button>
                    </span>
                  );
                })
              )}
            </div>

            {isOpen && !disabled && (
              <ul style={{
                position: 'absolute', top: '100%', left: 0, right: 0, zIndex: 9999,
                marginTop: '6px', padding: '6px', background: '#13112b',
                border: '1px solid rgba(255,255,255,0.1)', borderRadius: '10px',
                boxShadow: '0 8px 32px rgba(0,0,0,0.55)', maxHeight: '250px', overflowY: 'auto', listStyle: 'none'
              }}>
                {options.length === 0 ? (
                  <li style={{ padding: '8px 12px', color: 'var(--text-muted)', fontSize: '14px', fontFamily: "'Inter', sans-serif" }}>No options</li>
                ) : (
                  options.map((opt, i) => {
                    const isSelected = selected.includes(opt.value);
                    return (
                      <li
                        key={i}
                        onClick={() => handleSelect(opt.value)}
                        style={{
                          padding: '8px 12px', cursor: 'pointer', borderRadius: '6px', fontSize: '14px', fontFamily: "'Inter', sans-serif",
                          display: 'flex', alignItems: 'center', gap: '10px',
                          background: isSelected ? '#2a2060' : 'transparent',
                          color: isSelected ? '#ffffff' : '#EDE9FF',
                        }}
                        onMouseOver={(e) => {
                          if (!isSelected) e.currentTarget.style.background = 'rgba(255,255,255,0.05)';
                        }}
                        onMouseOut={(e) => {
                          if (!isSelected) e.currentTarget.style.background = 'transparent';
                        }}
                      >
                        <input
                          type="checkbox"
                          checked={isSelected}
                          readOnly
                          style={{ accentColor: 'var(--accent)', width: '16px', height: '16px', borderRadius: '4px', cursor: 'pointer' }}
                        />
                        {opt.label}
                      </li>
                    );
                  })
                )}
              </ul>
            )}
          </div>
        );
      })()}

      {/* ── radio (single-select radio buttons) ────────────────── */}
      {field.fieldType === 'radio' && (
        <div
          className={`radio-group${hasError ? ' radio-group-error' : ''}`}
          role="radiogroup"
          aria-describedby={hasError ? `${id}-err` : undefined}
        >
          {filterOpts(parseOptions(field.optionsJson, field.options)).map((opt, i) => (
            <label key={i} className="radio-option">
              <input
                type="radio"
                name={id}
                value={opt.value}
                checked={value === opt.value}
                onChange={(e) => { onChange(e.target.value); onBlur(e.target.value); }}
                disabled={disabled}
              />
              <span>{opt.label}</span>
            </label>
          ))}
        </div>
      )}

      {/* ── multiple_choice (multi-select checkboxes) ─────────── */}
      {field.fieldType === 'multiple_choice' && (
        <div
          className={`radio-group${hasError ? ' multiple-choice-error' : ''}`}
          role="group"
          aria-describedby={hasError ? `${id}-err` : undefined}
        >
          {filterOpts(parseOptions(field.optionsJson, field.options)).map((opt, i) => {
            // value stored as JSON array string e.g. '["Red","Blue"]'
            let selected = [];
            if (value) {
              const str = String(value).trim();
              if (str.startsWith('[')) {
                try { selected = JSON.parse(str); } catch { selected = []; }
              } else {
                selected = str.split(',').map(v => v.trim()).filter(Boolean);
              }
            }
            const isChecked = selected.includes(opt.value);
            const handleCheckChange = (e) => {
              e.stopPropagation();
              // Always re-parse current value fresh to avoid stale closure
              let currentSelected = [];
              if (value) {
                const str = String(value).trim();
                if (str.startsWith('[')) {
                  try { currentSelected = JSON.parse(str); } catch { currentSelected = []; }
                } else {
                  currentSelected = str.split(',').map(v => v.trim()).filter(Boolean);
                }
              }
              const checked = e.target.checked;
              const next = checked
                ? [...currentSelected, opt.value]
                : currentSelected.filter(v => v !== opt.value);
              const unique = [...new Set(next)];
              // Store as JSON array string
              onChange(JSON.stringify(unique));
            };
            return (
              <label key={i} className="radio-option checkbox-style">
                <input
                  type="checkbox"
                  name={id}
                  value={opt.value}
                  checked={isChecked}
                  onChange={handleCheckChange}
                  disabled={disabled}
                />
                <span>{opt.label}</span>
              </label>
            );
          })}
        </div>
      )}

      {/* ── multiple_choice_grid ────────────────────────────────── */}
      {field.fieldType === 'multiple_choice_grid' && (() => {
        // gridJson comes from /render endpoint: {"rows":[...],"columns":[...]}
        let rows = [], cols = [];
        if (field.gridJson) {
          try {
            const g = JSON.parse(field.gridJson);
            rows = g.rows || [];
            cols = g.columns || [];
          } catch { }
        }
        // Current value is a JSON object {"Row":"Col"}
        let selected = {};
        if (value && typeof value === 'string') {
          try { selected = JSON.parse(value); } catch { }
        } else if (value && typeof value === 'object') {
          selected = value;
        }
        const handleGridChange = (row, col) => {
          if (disabled) return;
          const next = { ...selected, [row]: col };
          onChange(JSON.stringify(next));
          onBlur(JSON.stringify(next));
        };
        return (
          <div className={`mcg-wrapper${hasError ? ' input-error-group' : ''}`}>
            <table className="mcg-table">
              <thead>
                <tr className="mcg-header-row">
                  <th></th>
                  {cols.map((col, ci) => <th key={ci}>{col}</th>)}
                </tr>
              </thead>
              <tbody>
                {rows.map((row, ri) => (
                  <tr key={ri} className="mcg-row">
                    <td className="mcg-row-label">{row}</td>
                    {cols.map((col, ci) => (
                      <td key={ci} className="mcg-cell">
                        <label className={`mcg-radio-wrap${disabled ? ' disabled' : ''}`}>
                          <input
                            type="radio"
                            name={`${id}-row-${ri}`}
                            value={col}
                            checked={selected[row] === col}
                            onChange={() => handleGridChange(row, col)}
                            disabled={disabled}
                          />
                          <span className="mcg-radio-circle">
                            <span className="mcg-radio-dot" />
                          </span>
                        </label>
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        );
      })()}

      {/* ── linear_scale ───────────────────────────────────────── */}
      {field.fieldType === 'linear_scale' && (() => {
        // Parse ui_config_json for scale bounds and labels
        let uiCfg = {};
        if (field.uiConfigJson) {
          try { uiCfg = JSON.parse(field.uiConfigJson); } catch { }
        }
        const scaleMin = uiCfg.scaleMin ?? 1;
        const scaleMax = uiCfg.scaleMax ?? 5;
        const labelLeft = uiCfg.labelLeft || '';
        const labelRight = uiCfg.labelRight || '';
        const steps = [];
        for (let i = scaleMin; i <= scaleMax; i++) steps.push(i);
        const selected = value !== '' && value !== null && value !== undefined ? Number(value) : null;
        return (
          <div className={`linear-scale-wrapper${hasError ? ' input-error-group' : ''}`}>
            <div className="linear-scale-inner">
              <div className="linear-scale-track" role="group" aria-label={effectiveLabel}>
                {steps.map((step) => {
                  const isActive = selected === step;
                  return (
                    <button
                      key={step}
                      type="button"
                      className={`linear-scale-btn${isActive ? ' active' : ''}`}
                      onClick={() => { if (!disabled) { onChange(step); onBlur(step); } }}
                      disabled={disabled}
                      aria-pressed={isActive}
                      aria-label={`${step}`}
                    >
                      {step}
                    </button>
                  );
                })}
              </div>
              {(labelLeft || labelRight) && (
                <div className="linear-scale-labels">
                  <span className="linear-scale-label-left">{labelLeft}</span>
                  <span className="linear-scale-label-right">{labelRight}</span>
                </div>
              )}
            </div>
          </div>
        );
      })()}

      {/* ── star_rating ────────────────────────────────────────── */}
      {field.fieldType === 'star_rating' && (() => {
        // Parse ui_config_json for scale bounds and labels
        let uiCfg = {};
        if (field.uiConfigJson) {
          try { uiCfg = JSON.parse(field.uiConfigJson); } catch { }
        }
        const scaleMin = uiCfg.scaleMin ?? 1;
        const scaleMax = uiCfg.scaleMax ?? 5;
        const labelLeft = uiCfg.labelLeft || '';
        const labelRight = uiCfg.labelRight || '';
        const steps = [];
        for (let i = scaleMin; i <= scaleMax; i++) steps.push(i);
        const selected = value !== '' && value !== null && value !== undefined ? Number(value) : null;
        return (
          <div className={`linear-scale-wrapper${hasError ? ' input-error-group' : ''}`}>
            <div className="linear-scale-inner">
              <div className="linear-scale-track" role="group" aria-label={effectiveLabel}>
                {steps.map((step) => {
                  const isActive = selected === step;
                  return (
                    <button
                      key={step}
                      type="button"
                      className={`linear-scale-btn star-rating-btn${isActive ? ' active' : ''}`}
                      onClick={() => { if (!disabled) { onChange(step); onBlur(step); } }}
                      disabled={disabled}
                      aria-pressed={isActive}
                      aria-label={`${step}`}
                    >
                      {isActive ? '★' : '☆'}
                    </button>
                  );
                })}
              </div>
              {(labelLeft || labelRight) && (
                <div className="linear-scale-labels">
                  <span className="linear-scale-label-left">{labelLeft}</span>
                  <span className="linear-scale-label-right">{labelRight}</span>
                </div>
              )}
            </div>
          </div>
        );
      })()}

      {/* ── checkbox_grid ──────────────────────────────────────── */}
      {field.fieldType === 'checkbox_grid' && (() => {
        // gridJson comes from /render endpoint: {"rows":[...],"columns":[...]}
        let rows = [], cols = [];
        if (field.gridJson) {
          try {
            const g = JSON.parse(field.gridJson);
            rows = g.rows || [];
            cols = g.columns || [];
          } catch { }
        }
        // Current value: {"Row":["ColA","ColB"]} — arrays per row (multi-select)
        let selected = {};
        if (value && typeof value === 'string') {
          try { selected = JSON.parse(value); } catch { }
        } else if (value && typeof value === 'object') {
          selected = value;
        }
        const handleCbChange = (row, col, checked) => {
          if (disabled) return;
          const cur = Array.isArray(selected[row]) ? selected[row] : (selected[row] ? [selected[row]] : []);
          const next = checked ? [...new Set([...cur, col])] : cur.filter(v => v !== col);
          const updated = { ...selected, [row]: next };
          onChange(JSON.stringify(updated));
          onBlur(JSON.stringify(updated));
        };
        return (
          <div className={`mcg-wrapper${hasError ? ' input-error-group' : ''}`}>
            <table className="mcg-table">
              <thead>
                <tr className="mcg-header-row">
                  <th></th>
                  {cols.map((col, ci) => <th key={ci}>{col}</th>)}
                </tr>
              </thead>
              <tbody>
                {rows.map((row, ri) => {
                  const rowSel = Array.isArray(selected[row]) ? selected[row] : (selected[row] ? [selected[row]] : []);
                  return (
                    <tr key={ri} className="mcg-row">
                      <td className="mcg-row-label">{row}</td>
                      {cols.map((col, ci) => (
                        <td key={ci} className="mcg-cell">
                          <label className={`mcg-checkbox-wrap${disabled ? ' disabled' : ''}`}>
                            <input
                              type="checkbox"
                              value={col}
                              checked={rowSel.includes(col)}
                              onChange={(e) => handleCbChange(row, col, e.target.checked)}
                              disabled={disabled}
                            />
                            <span className="mcg-checkbox-box">
                              <span className="mcg-checkbox-tick">✓</span>
                            </span>
                          </label>
                        </td>
                      ))}
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        );
      })()}

      {/* ── file ───────────────────────────────────────────────── */}
      {field.fieldType === 'file' && (
        <input
          id={id}
          type="file"
          className={inputClass}
          multiple={getMultiple(field.validationJson)}
          accept={getAllowedAccept(field.validationJson)}
          onChange={(e) => {
            const files = e.target.files;
            if (!files || files.length === 0) return;
            // Pass full FileList so multi-file validation works
            const payload = files.length === 1 ? files[0] : files;
            onChange(payload);
            onBlur(payload);
          }}
          disabled={disabled}
          aria-describedby={hasError ? `${id}-err` : undefined}
          aria-invalid={hasError || undefined}
        />
      )}

      {/* ── Error (shows after first interaction, highest-priority only) ── */}
      {hasError && (
        <span id={`${id}-err`} className="form-field-error" role="alert" aria-live="polite">
          {shownError}
        </span>
      )}
    </div>
  );
}

// ─── Utilities ────────────────────────────────────────────────────────────────

function parseOptions(optionsJson, resolvedOptions) {
  // Priority 1: pre-resolved [{label, value}] objects from /render endpoint
  if (Array.isArray(resolvedOptions) && resolvedOptions.length > 0) {
    return resolvedOptions; // already [{label, value}]
  }
  // Priority 2: inline optionsJson string ["Opt1","Opt2"]
  if (!optionsJson || optionsJson === 'null') return [];
  try {
    const parsed = JSON.parse(optionsJson);
    if (!Array.isArray(parsed)) return [];
    // Could be strings or objects
    return parsed.map(o =>
      typeof o === 'string' ? { label: o, value: o } : o
    );
  } catch { return []; }
}

function getMultiple(validationJson) {
  try {
    return JSON.parse(validationJson || '{}').singleOrMultiple === 'multiple';
  } catch { return false; }
}

/**
 * Build the `accept` attribute from validationJson.
 * Uses allowedExtensions (e.g. ".pdf,.png") and/or mimeTypeValidation.
 * Returns empty string if no restriction (browser shows all files).
 */
function getAllowedAccept(validationJson) {
  try {
    const rules = JSON.parse(validationJson || '{}');
    const parts = [];
    if (rules.allowedExtensions) {
      rules.allowedExtensions.split(',')
        .map(e => e.trim().toLowerCase())
        .filter(Boolean)
        .forEach(ext => parts.push(ext.startsWith('.') ? ext : `.${ext}`));
    }
    if (rules.mimeTypeValidation) {
      rules.mimeTypeValidation.split(',')
        .map(m => m.trim())
        .filter(Boolean)
        .forEach(m => { if (!parts.includes(m)) parts.push(m); });
    }
    return parts.join(',');
  } catch { return ''; }
}

import { useState, useRef, useEffect, useMemo } from 'react';
import ValidationEngine from '../services/validation';
import RuleEngine, { setDefaultValues } from '../services/RuleEngine';
import CalculationEngine from '../services/CalculationEngine';
import { getDraft, saveDraft } from '../services/api';
import { toastInfo, showWarning } from '../services/toast';
import { translateApiError } from '../services/errorTranslator';

/**
 * FormRenderer — enterprise dynamic form renderer with Conditional Rule Engine.
 *
 * Rule Engine lifecycle:
 *   Fields load  → withParsedRules()    pre-parses all rulesJson ONCE (not per keystroke)
 *                → buildDependencyMap() maps source→target field relationships
 *                → applyRules()         sets initial field states
 *   onChange     → applyRules() re-evaluates all rules with new values
 *                → cascading setValue handled internally (MAX_PASSES = 5)
 *                → fieldStates drives visible / required / disabled / setValue per field
 *   onSubmit     → validates VISIBLE fields only (hidden = skip validation)
 *                → hidden field VALUES preserved in state and sent to backend
 *                → backend validates independently — never trusts frontend rule state
 *
 * Priority: ascending fieldOrder. Higher order = evaluated later = wins conflicts.
 */
const STATIC_FIELD_TYPES = new Set(['section_header', 'label_text', 'description_block', 'page_break']);

export default function FormRenderer({ form, isPreview = false, onSubmit }) {
  const rawFields = form?.fields || [];

  // Static elements — identified purely by fieldType (isStatic from backend was mis-serialized as "static")
  const staticFields = useMemo(
    () => rawFields.filter(f => STATIC_FIELD_TYPES.has(f.fieldType)),
    [rawFields]
  );

  // Dynamic fields only — everything that is NOT a known static type
  const dynamicRawFields = useMemo(
    () => rawFields.filter(f => !STATIC_FIELD_TYPES.has(f.fieldType)),
    [rawFields]
  );

  // Pre-parse rulesJson once — avoids repeated JSON.parse inside evaluation loops
  const fields = useMemo(() => {
    const withRules = RuleEngine.withParsedRules(dynamicRawFields);
    // Map g.id to fieldKey so RuleEngine can track it, and map groupOrder to fieldOrder for priority
    const groupsWithRules = RuleEngine.withParsedRules((form?.groups || []).map(g => ({
      ...g,
      fieldKey: g.id,
      fieldOrder: g.groupOrder ?? 0
    })));
    return [...withRules, ...groupsWithRules];
  }, [dynamicRawFields, form?.groups]);

  // Dependency map: { sourceKey → Set<targetKey> }
  // eslint-disable-next-line no-unused-vars
  const depMap = useMemo(() => RuleEngine.buildDependencyMap(fields), [fields]);

  // ── Build initial values from field defaults ───────────────────────────────
  function makeInitialValues() {
    return Object.fromEntries(
      fields.map((f) => [
        f.fieldKey,
        f.fieldType === 'boolean'
          ? (f.defaultValue === 'true' || f.defaultValue === true)
          : (f.defaultValue || ''),
      ])
    );
  }

  const [values, setValues] = useState(makeInitialValues);
  const [errors, setErrors] = useState({});  // { fieldKey: string[] }
  const [touched, setTouched] = useState({});  // { fieldKey: boolean }
  const [fieldStates, setFieldStates] = useState(() => RuleEngine.applyRules(fields, makeInitialValues()));
  const [serverError, setServerError] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [lastSaved, setLastSaved] = useState(null); // timestamp of last autosave
  const [saving, setSaving] = useState(false);

  // ── Wizard (multi-step) state ──────────────────────────────────────────────
  const [currentPage, setCurrentPage] = useState(0);

  /**
   * Split all renderable items (dynamic + static) sorted by fieldOrder into pages.
   * A page_break static element acts as the divider — it is consumed and NOT rendered.
   * pages = [ { items: [...], title: string|null }, ... ]
   *
   * Detection: item.fieldType === 'page_break' (works for both render-endpoint
   * responses where isStatic=true AND builder-preview where field comes through staticFields).
   */
  const pages = useMemo(() => {
    // Merge dynamic fields + ALL static fields (including page_break) + groups, sort by fieldOrder
    // Use dynamicRawFields instead of fields to prevent mapping the groups inside fields array
    const allItems = [
      ...dynamicRawFields.map(f => ({ ...f, _renderType: 'dynamic' })),
      ...staticFields.map(f => ({ ...f, _renderType: 'static' })),
      ...(form?.groups || []).map(g => ({ ...g, _renderType: 'group', fieldOrder: g.groupOrder }))
    ].sort((a, b) => (a.fieldOrder ?? 0) - (b.fieldOrder ?? 0));

    const result = [];
    let currentPageItems = [];
    let currentPageTitle = null;

    for (const item of allItems) {
      // Detect page break by fieldType (primary) — works regardless of isStatic flag
      if (item.fieldType === 'page_break') {
        // Push everything collected so far as a completed page
        result.push({ items: currentPageItems, title: currentPageTitle });
        currentPageItems = [];
        // The page_break's data/staticData becomes the NEXT page's title
        currentPageTitle = item.staticData || item.data || item.label || null;
      } else {
        currentPageItems.push(item);
      }
    }
    // Always push the final (or only) page
    result.push({ items: currentPageItems, title: currentPageTitle });

    return result;
  }, [fields, staticFields]);

  const totalPages = pages.length;
  const isMultiStep = totalPages > 1;
  const isFirstPage = currentPage === 0;
  const isLastPage = currentPage === totalPages - 1;

  // File objects stored in ref (avoids stale-closure issues in async handlers)
  const filesRef = useRef({});

  // Keep a ref to current values so async handlers always read the latest
  const valuesRef = useRef(values);
  useEffect(() => { valuesRef.current = values; }, [values]);

  // Re-initialise when fields change (async load or form switch)
  useEffect(() => {
    const initial = makeInitialValues();

    // 1. Initial Rules
    const initialStates = RuleEngine.applyRules(fields, initial);
    let currentValues = { ...initial };
    for (const [key, st] of Object.entries(initialStates)) {
      if (st.setValue !== null) currentValues[key] = st.setValue;
      if (st.copyValue !== null) currentValues[key] = st.copyValue;
    }

    // 2. Initial Calculations
    let calculated = currentValues;
    try {
      calculated = CalculationEngine.recalculateCalculatedFields(fields, currentValues);
    } catch (err) {
      console.warn('[FormRenderer] Initial calculation error:', err.message);
    }

    // 3. Re-run rules if calculations changed values (cascade)
    const finalStates = RuleEngine.applyRules(fields, calculated);

    setDefaultValues(calculated); // snapshot for 'changed' operator (v2)
    setValues(calculated);
    valuesRef.current = calculated;
    filesRef.current = {};
    setErrors({});
    setTouched({});
    setFieldStates(finalStates);
    setCurrentPage(0); // reset wizard to first page
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [fields]);

  // ── Draft Retrieval ──────────────────────────────────────────────────────
  useEffect(() => {
    if (isPreview || !form?.id) return;

    async function fetchDraft() {
      try {
        const draft = await getDraft(form.id);
        if (draft && Object.keys(draft).length > 0) {
          // Merge draft values with initial values (in case form schema changed)
          const draftValues = { ...valuesRef.current };
          for (const field of fields) {
            if (draft[field.fieldKey] !== undefined && draft[field.fieldKey] !== null) {
              draftValues[field.fieldKey] = draft[field.fieldKey];
            }
          }

          // Re-apply rules and calculations based on draft data
          const states = RuleEngine.applyRules(fields, draftValues);
          let calculated = draftValues;
          try {
            calculated = CalculationEngine.recalculateCalculatedFields(fields, draftValues);
          } catch (err) {
            console.warn('[FormRenderer] Draft calculation error:', err.message);
          }
          const finalStates = RuleEngine.applyRules(fields, calculated);

          setValues(calculated);
          valuesRef.current = calculated;
          setFieldStates(finalStates);
          setLastSaved(new Date(draft.updated_at || Date.now()));
          
          // Ensure flag is set if we successfully loaded a draft
          localStorage.setItem(`draft_form_${form.id}`, 'true');
        } else {
          // No draft returned from backend. Check if we EXPECTED one (F2 requirement)
          const hadDraft = localStorage.getItem(`draft_form_${form.id}`);
          if (hadDraft) {
            showWarning('Your previous draft was discarded because the form was updated to a new version. Please review the fields.');
            localStorage.removeItem(`draft_form_${form.id}`);
          }
        }
      } catch (err) {
        if (err?.status === 404) {
           const hadDraft = localStorage.getItem(`draft_form_${form.id}`);
           if (hadDraft) {
             showWarning('Your previous draft was discarded because the form was updated to a new version.');
             localStorage.removeItem(`draft_form_${form.id}`);
           }
        }
        console.warn('Failed to fetch draft:', err);
      }
    }
    fetchDraft();
  }, [form?.id, isPreview, form?.formVersionId]);

  // ── Autosave Logic ───────────────────────────────────────────────────────
  const lastSavedValuesRef = useRef(values);

  useEffect(() => {
    if (isPreview || submitted || !form?.id) return;

    const timer = setInterval(async () => {
      const currentValues = valuesRef.current;
      // Only save if data has actually changed
      if (JSON.stringify(currentValues) === JSON.stringify(lastSavedValuesRef.current)) {
        return;
      }

      setSaving(true);
      try {
        // [F3] Compliance: formVersionId from React state (form object) only
        await saveDraft(form.id, currentValues, null, form.formVersionId);
        setLastSaved(new Date());
        lastSavedValuesRef.current = currentValues;
        // Signal that a draft now exists for this form
        localStorage.setItem(`draft_form_${form.id}`, 'true');
      } catch (err) {
        console.warn('Autosave failed:', err);
      } finally {
        setSaving(false);
      }
    }, 10000); // 10 seconds

    return () => clearInterval(timer);
  }, [form?.id, isPreview, submitted]);

  // Handle manual save on page navigate away
  useEffect(() => {
    if (isPreview || submitted || !form?.id) return;

    const handleBeforeUnload = () => {
      const currentValues = valuesRef.current;
      if (JSON.stringify(currentValues) !== JSON.stringify(lastSavedValuesRef.current)) {
        // [F3] Compliance: formVersionId from React state only
        saveDraft(form.id, currentValues, null, form.formVersionId).catch(() => { });
        localStorage.setItem(`draft_form_${form.id}`, 'true');
      }
    };

    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [form?.id, isPreview, submitted]);

  // ── onChange — live validation + rule re-evaluation on every keystroke ─────
  function handleChange(field, value) {
    // 1. Update formValues state (stage 1)
    let currentValues = { ...valuesRef.current, [field.fieldKey]: value };

    // 2. Update file ref — store FileList or single File
    if (field.fieldType === 'file') {
      if (value instanceof FileList) {
        filesRef.current = { ...filesRef.current, [field.fieldKey]: value };
      } else if (value instanceof File) {
        filesRef.current = { ...filesRef.current, [field.fieldKey]: value };
      }
    }

    // 3. Run RuleEngine.applyRules() (Rules before Calc)
    let currentStates = RuleEngine.applyRules(fields, currentValues);

    // 4. Apply setValue/copyValue overrides from rules
    for (const [key, st] of Object.entries(currentStates)) {
      if (st.setValue !== null && String(currentValues[key] ?? '') !== String(st.setValue)) {
        currentValues[key] = st.setValue;
      }
      if (st.copyValue !== null && String(currentValues[key] ?? '') !== String(st.copyValue)) {
        currentValues[key] = st.copyValue;
      }
    }

    // 5. Run CalculationEngine.recalculate()
    let calculatedValues = currentValues;
    try {
      calculatedValues = CalculationEngine.recalculateCalculatedFields(fields, currentValues);
    } catch (err) {
      // Logic: if a formula results in division by zero (e.g. while typing), just keep the current values.
      console.warn('[FormRenderer] Calculation error:', err.message);
    }

    // If calculations changed values, we might need a quick re-run of rules to update UI state (visible/required)
    // based on the new calculated values.
    if (JSON.stringify(calculatedValues) !== JSON.stringify(currentValues)) {
      currentStates = RuleEngine.applyRules(fields, calculatedValues);
      currentValues = calculatedValues;
    }

    // 6. Final State Updates
    setFieldStates(currentStates);
    setValues(currentValues);
    valuesRef.current = currentValues;

    // 7. Validate changed field using rule-adjusted required flag
    const effectiveField = {
      ...field,
      required: currentStates[field.fieldKey]?.required ?? field.required,
    };
    const errs = ValidationEngine.validateFieldSync(
      effectiveField, currentValues[field.fieldKey], currentValues, filesRef.current
    );
    setErrors((prev) => ({ ...prev, [field.fieldKey]: errs }));

    // 8. Mark field touched
    setTouched((prev) => ({ ...prev, [field.fieldKey]: true }));

    // 9. Clear server banner
    if (serverError) setServerError('');
  }

  // ── onBlur — ensure touched is set so error persists ──────────────────────
  function handleBlur(field, value) {
    setTouched((prev) => ({ ...prev, [field.fieldKey]: true }));
    // Re-run validation on blur (catches paste/autofill that skips onChange)
    const effectiveField = {
      ...field,
      required: fieldStates[field.fieldKey]?.required ?? field.required,
    };
    const errs = ValidationEngine.validateFieldSync(effectiveField, value, valuesRef.current, filesRef.current);
    setErrors((prev) => ({ ...prev, [field.fieldKey]: errs }));
  }

  // ── Wizard Next — validate current page's visible dynamic fields then advance ─
  const handleNext = async () => {
    // Mark only current page's dynamic fields as touched
    const currentDynamic = (pages[currentPage]?.items || []).filter(f => f._renderType === 'dynamic');
    const pageTouched = Object.fromEntries(currentDynamic.map(f => [f.fieldKey, true]));
    setTouched(prev => ({ ...prev, ...pageTouched }));

    // Validate only visible fields on current page
    const visiblePageFields = currentDynamic
      .filter(f => {
        if (fieldStates[f.fieldKey]?.visible === false) return false;
        if (f.groupId && fieldStates[f.groupId]?.visible === false) return false;
        return true;
      })
      .map(f => {
        const fieldSt = fieldStates[f.fieldKey] || {};
        const groupSt = f.groupId ? fieldStates[f.groupId] : null;
        const effectiveRequired =
          groupSt?.required === true ? true :
            groupSt?.required === false ? false :
              (fieldSt.required ?? f.required);
        return { ...f, required: effectiveRequired };
      });

    const pageErrors = await ValidationEngine.validateForm(visiblePageFields, valuesRef.current, filesRef.current);
    setErrors(prev => ({ ...prev, ...pageErrors }));

    if (Object.keys(pageErrors).length > 0) {
      const firstKey = Object.keys(pageErrors)[0];
      const el = document.getElementById(`field-${firstKey}`);
      if (el) { el.scrollIntoView({ behavior: 'smooth', block: 'center' }); el.focus(); }
      return;
    }

    // Advance to next page and scroll to top of form
    setCurrentPage(p => Math.min(p + 1, totalPages - 1));
    setServerError('');
    const card = document.querySelector('.form-renderer-card');
    if (card) card.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  const handleBack = () => {
    setCurrentPage(p => Math.max(p - 1, 0));
    setServerError('');
    const card = document.querySelector('.form-renderer-card');
    if (card) card.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  // ── onSubmit — full async validation, block if any errors ─────────────────
  const handleSubmit = async (e) => {
    e.preventDefault();

    // Guard: never submit if there are more pages ahead (wizard safety net)
    if (isMultiStep && !isLastPage) {
      handleNext();
      return;
    }

    // Mark all fields as touched so all errors become visible
    const allTouched = Object.fromEntries(fields.map((f) => [f.fieldKey, true]));
    setTouched(allTouched);

    // Validate VISIBLE fields only — hidden fields skip validation.
    // Hidden field VALUES are preserved in state and sent to backend.
    // Backend validates all required constraints independently of rule state.
    const visibleFields = fields
      .filter(f => {
        if (fieldStates[f.fieldKey]?.visible === false) return false;
        if (f.groupId && fieldStates[f.groupId]?.visible === false) return false;
        return true;
      })
      .map(f => {
        const fieldSt = fieldStates[f.fieldKey] || {};
        const groupSt = f.groupId ? fieldStates[f.groupId] : null;
        const effectiveRequired =
          groupSt?.required === true ? true :
            groupSt?.required === false ? false :
              (fieldSt.required ?? f.required);
        return { ...f, required: effectiveRequired };
      });

    const allErrors = await ValidationEngine.validateForm(visibleFields, valuesRef.current, filesRef.current);
    setErrors(allErrors);
    setServerError('');

    if (Object.keys(allErrors).length > 0) {
      // Scroll + focus first error field
      const firstKey = Object.keys(allErrors)[0];
      const el = document.getElementById(`field-${firstKey}`);
      if (el) { el.scrollIntoView({ behavior: 'smooth', block: 'center' }); el.focus(); }
      return;
    }

    // ── All valid — submit ───────────────────────────────────────────────────
    if (isPreview) {
      toastInfo(" Preview Mode: Form validation passed! Actual submission is disabled in preview mode.");
      return;
    }

    setSubmitting(true);
    try {
      const currentValues = valuesRef.current;
      const hasFile = fields.some(
        (f) => f.fieldType === 'file' &&
          (filesRef.current[f.fieldKey] instanceof File ||
            filesRef.current[f.fieldKey] instanceof FileList)
      );

      if (hasFile) {
        const fd = new FormData();
        for (const [key, val] of Object.entries(currentValues)) {
          const fileVal = filesRef.current[key];
          if (fileVal instanceof FileList) {
            // Append every file with the same key so backend receives all
            for (let i = 0; i < fileVal.length; i++) {
              fd.append(key, fileVal[i]);
            }
          } else if (fileVal instanceof File) {
            fd.append(key, fileVal);
          } else if (val != null) {
            fd.append(key, val);
          }
        }
        await onSubmit(fd);
      } else {
        await onSubmit(currentValues);
      }

      setSubmitted(true);
      localStorage.removeItem(`draft_form_${form.id}`); // Requirement [E9]
    } catch (err) {
      if (err?.errors && Array.isArray(err.errors)) {
        const fieldErrs = {};
        const unmatched = [];

        for (const error of err.errors) {
          // Backend sends { field: fieldKey, message: string }
          if (error && typeof error === 'object' && error.field && error.message) {
            const key = error.field;
            if (key === '__general__' || key === 'form' || key === 'general') {
              unmatched.push(error.message);
            } else {
              // Match by fieldKey directly (primary) or label (fallback)
              const matchedField = fields.find(
                (f) => f.fieldKey === key || f.label === key
              );
              const targetKey = matchedField ? matchedField.fieldKey : key;
              if (!fieldErrs[targetKey]) fieldErrs[targetKey] = [];
              fieldErrs[targetKey].push(error.message);
            }
          } else if (typeof error === 'string') {
            unmatched.push(error);
          }
        }

        if (Object.keys(fieldErrs).length) {
          setErrors(fieldErrs);
          // Mark all backend-errored fields as touched so errors show
          const newTouched = Object.fromEntries(Object.keys(fieldErrs).map((k) => [k, true]));
          setTouched((prev) => ({ ...prev, ...newTouched }));
          const firstKey = Object.keys(fieldErrs)[0];
          const el = document.getElementById(`field-${firstKey}`);
          if (el) { el.scrollIntoView({ behavior: 'smooth', block: 'center' }); el.focus(); }
        }
        if (unmatched.length) {
          setServerError(unmatched.join(' · '));
        } else if (Object.keys(fieldErrs).length) {
          // If we have field errors but no unmatched, still show a friendly top-level reminder
          const count = Object.keys(fieldErrs).length;
          setServerError(`Please fix the ${count} field${count > 1 ? 's' : ''} highlighted below.`);
        }
      } else {
        setServerError(err?.message || 'Submission failed. Please try again.');
      }
    } finally {
      setSubmitting(false);
    }
  };

  // ── Success screen ─────────────────────────────────────────────────────────
  if (submitted) {
    return (
      <div className="form-renderer-card">
        <div className="form-success-state">
          <div className="success-icon-ring">✓</div>
          <h2>Submitted Successfully!</h2>
          <p>Thank you — your response has been recorded.</p>
          <button
            className="btn btn-secondary success-another-btn"
            onClick={() => {
              const fresh = makeInitialValues();
              setValues(fresh);
              valuesRef.current = fresh;
              filesRef.current = {};
              setErrors({});
              setTouched({});
              setFieldStates(RuleEngine.applyRules(fields, fresh));
              setSubmitted(false);
            }}
          >
            Submit another response
          </button>
        </div>
      </div>
    );
  }

  // ── Main render ────────────────────────────────────────────────────────────
  return (
    <div className="form-renderer-card">
      {isPreview && (
        <div className="preview-banner">
          &nbsp;<strong>Preview Mode</strong> — submissions are disabled
        </div>
      )}

      <div className="form-renderer-header">
        <h1 className="form-renderer-title">{form.name}</h1>
        {form.description && <p className="form-renderer-desc">{form.description}</p>}
        <div className="form-renderer-meta">
          <span className="form-renderer-meta-item">
             {fields.length} field{fields.length !== 1 ? 's' : ''}
          </span>
          {fields.some((f) => f.required) && (
            <span className="form-renderer-meta-item">
              <span className="form-field-required-star">*</span> Required fields marked
            </span>
          )}
          {lastSaved && (
            <span className="form-renderer-meta-item draft-indicator">
              {saving ? (
                <><span className="spinner-micro" /> Saving draft…</>
              ) : (
                <>✔ Draft saved at {lastSaved.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</>
              )}
            </span>
          )}
        </div>
      </div>

      {serverError && (
        <div className={`auth-error ${serverError.includes('fixed') || serverError.includes('highlighted') ? 'validation-summary-banner' : ''}`} 
             style={{ margin: '0 32px 24px', borderRadius: 12, padding: '16px 20px', border: '1px solid rgba(239,68,68,0.2)' }}>
          <div style={{ display: 'flex', gap: '12px', alignItems: 'center' }}>
            <span style={{ fontSize: '20px' }}>⚠️</span>
            <div style={{ flex: 1 }}>
              <strong style={{ display: 'block', marginBottom: '4px', color: '#ff8e8e', fontSize: '15px' }}>
                Form Validation Failed
              </strong>
              <div style={{ fontSize: '14px', opacity: 0.9 }}>{serverError}</div>
            </div>
          </div>
        </div>
      )}


      {/* ── Wizard Progress Bar (only when multi-step) ────────────────────── */}
      {isMultiStep && (
        <div className="wizard-progress-bar">
          <div className="wizard-steps-track">
            {pages.map((page, idx) => (
              <div key={idx} className="wizard-step-wrapper">
                <div className={`wizard-step-dot ${idx < currentPage ? 'completed' : ''} ${idx === currentPage ? 'active' : ''}`}>
                  {idx < currentPage ? <span>✓</span> : <span>{idx + 1}</span>}
                </div>
                {idx < totalPages - 1 && (
                  <div className={`wizard-step-connector ${idx < currentPage ? 'completed' : ''}`} />
                )}
              </div>
            ))}
          </div>
          <div className="wizard-page-label">
            {pages[currentPage]?.title
              ? <span className="wizard-page-title">Step {currentPage + 1}: {pages[currentPage].title}</span>
              : <span>Page {currentPage + 1} of {totalPages}</span>
            }
          </div>
        </div>
      )}

      <form onSubmit={handleSubmit} noValidate>
        {fields.length === 0 && staticFields.length === 0 ? (
          <div className="form-empty-state">This form has no fields yet.</div>
        ) : (
          <div className="form-renderer-body">
            {/* Render fields with group hierarchy support */}
            {(() => {
              const currentItems = pages[currentPage]?.items || [];
              const topLevelItems = currentItems.filter(f => !f.parentGroupKey && !f.groupId);
              const childrenByParent = {};

              currentItems.forEach(f => {
                const parentId = f.groupId || f.parentGroupKey;
                if (parentId) {
                  if (!childrenByParent[parentId]) childrenByParent[parentId] = [];
                  childrenByParent[parentId].push(f);
                }
              });

              // Ensure children are sorted correctly within the group
              Object.values(childrenByParent).forEach(arr => arr.sort((a, b) => (a.fieldOrder ?? 0) - (b.fieldOrder ?? 0)));

              const renderField = (field, index = 0) => {
                // ── Group Container (New Architecture) ───────────────────
                if (field._renderType === 'group') {
                  const children = childrenByParent[field.id] || [];
                  const groupSt = fieldStates[field.id] || {};

                  // If the group itself is hidden by a rule, skip it and all children
                  if (groupSt.visible === false) return null;

                  return (
                    <div key={field.id} className="field-group-container" style={{ position: 'relative', zIndex: 100 - index }}>
                      <h3 className="field-group-title">{field.groupTitle || 'Untitled Section'}</h3>
                      {field.groupDescription && <p className="field-group-desc">{field.groupDescription}</p>}
                      <div className="field-group-children">
                        {children.map((f, i) => renderField(f, i))}
                      </div>
                    </div>
                  );
                }

                // ── Static elements — display only ───────────────────────
                if (field._renderType === 'static') {
                  return (
                    <StaticElement
                      key={field.fieldKey || field.id || `static-${field.fieldOrder}`}
                      field={field}
                    />
                  );
                }

                // ── Dynamic fields ───────────────────────────────────────
                const st = fieldStates[field.fieldKey] || {};

                // Hidden fields — render nothing, value preserved in state
                if (st.visible === false) return null;

                // Also check if this field belongs to a group that is currently hidden
                if (field.groupId && fieldStates[field.groupId]?.visible === false) {
                  return null;
                }

                // ── Field Group Container (Legacy Support) ───────────────
                if (field.fieldType === 'field_group') {
                  const children = childrenByParent[field.fieldKey] || [];
                  return (
                    <div key={field.id || field.fieldKey} className="field-group-container" style={{ position: 'relative', zIndex: 100 - index }}>
                      {field.label && <h3 className="field-group-title">{st.label ?? field.label}</h3>}
                      <div className="field-group-children">
                        {children.map((f, i) => renderField(f, i))} // Recursive mapping with descending zIndexes
                      </div>
                    </div>
                  );
                }

                // Effective value: copyValue > setValue > user input (priority order)
                const effectiveValue =
                  st.copyValue !== null && st.copyValue !== undefined
                    ? st.copyValue
                    : st.setValue !== null && st.setValue !== undefined
                      ? st.setValue
                      : values[field.fieldKey];

                const groupSt = field.groupId ? fieldStates[field.groupId] : null;
                const effectiveRequired =
                  groupSt?.required === true ? true :
                    groupSt?.required === false ? false :
                      (st.required ?? field.required);

                return (
                  <div key={field.id || field.fieldKey} style={{ position: 'relative', zIndex: 100 - index }}>
                    <FieldInput
                      field={{ ...field, required: effectiveRequired }}
                      value={effectiveValue}
                      errors={errors[field.fieldKey] || []}
                      touched={!!touched[field.fieldKey]}
                      onChange={(val) => handleChange(field, val)}
                      onBlur={(val) => handleBlur(field, val)}
                      disabled={
                        !!st.disabled ||
                        !!field.disabled ||
                        !!field.readOnly ||
                        !!field.lockAfterCalculation ||
                        (field.groupId && fieldStates[field.groupId]?.disabled === true)
                      }
                      filterOptions={st.filterOptions ?? null}
                      min={st.min ?? null}
                      max={st.max ?? null}
                      labelOverride={st.label ?? null}
                      placeholderOverride={st.placeholder ?? null}
                    />
                  </div>
                );
              };

              return topLevelItems.map((f, i) => renderField(f, i));
            })()}
          </div>
        )}

        {/* Hidden submit trigger — only used on last page */}
        <button type="submit" id="__form-submit-hidden__" style={{ display: 'none' }} aria-hidden="true" />
      </form>

      {/* ── Footer: Back / Next / Submit — OUTSIDE <form> to prevent accidental submission ── */}
      <div className={`form-renderer-footer${isMultiStep ? ' wizard-footer' : ''}`}>
        {isMultiStep && !isFirstPage && (
          <button
            type="button"
            className="btn btn-secondary wizard-back-btn"
            onClick={handleBack}
            disabled={submitting}
          >
            ← Back
          </button>
        )}

        {isMultiStep && !isLastPage ? (
          /* Next button — validates current page then advances */
          <button
            type="button"
            id="wizard-next-btn"
            className="form-submit-btn"
            onClick={handleNext}
            disabled={submitting}
            style={{ marginLeft: 'auto' }}
          >
            Next →
          </button>
        ) : (
          /* Submit button — triggers the hidden submit inside <form> */
          <button
            type="button"
            id="form-submit-btn"
            className="form-submit-btn"
            disabled={submitting || fields.length === 0}
            style={isMultiStep ? { marginLeft: 'auto' } : undefined}
            onClick={() => {
              const hidden = document.getElementById('__form-submit-hidden__');
              if (hidden) hidden.click();
            }}
          >
            {submitting ? (
              <><span className="spinner" style={{ borderTopColor: '#fff', width: 18, height: 18 }} /> Submitting…</>
            ) : isPreview ? (
              ' Preview Mode — Submit Disabled'
            ) : (
              'Submit Form →'
            )}
          </button>
        )}
      </div>
    </div>
  );
}

// ─── StaticElement ────────────────────────────────────────────────────────────
/**
 * Renders a static UI element — section_header, label_text, description_block.
 * Never collects input, never validated, never included in submission payload.
 */
function StaticElement({ field }) {
  // staticData from /render endpoint, or label as fallback (legacy)
  const content = field.staticData || field.label || field.data || '';

  if (field.fieldType === 'section_header') {
    return (
      <div className="static-section-header">
        <h3 className="static-section-header-text">{content}</h3>
        <div className="static-section-header-line" />
      </div>
    );
  }

  if (field.fieldType === 'label_text') {
    return (
      <div className="static-label-text">
        <p className="static-label-text-content">{content}</p>
      </div>
    );
  }

  if (field.fieldType === 'description_block') {
    return (
      <div className="static-description-block">
        <p className="static-description-block-content">{content}</p>
      </div>
    );
  }

  return null;
}

// ─── FieldInput ───────────────────────────────────────────────────────────────
/**
 * Renders a single form field.
 *
 * errors            = string[]      (all validation messages for this field)
 * touched           = boolean       (true once user has interacted)
 * filterOptions     = string[]|null (NEW v2) allowed option values; null = show all
 * min/max           = number|null   (NEW v2) dynamic bounds for number/date fields
 * labelOverride     = string|null   (NEW v2) runtime label override
 * placeholderOverride = string|null (NEW v2) runtime placeholder override
 *
 * Shows the FIRST (highest-priority) error only for clean UX.
 */
function FieldInput({ field, value, errors, touched, onChange, onBlur, disabled,
  filterOptions, min, max, labelOverride, placeholderOverride }) {
  const id = `field-${field.fieldKey}`;
  const errorList = Array.isArray(errors) ? errors : [];
  const shownError = touched && errorList.length > 0 ? errorList[0] : null;
  const hasError = !!shownError;
  const inputClass = `form-input${hasError ? ' input-error' : ''}`;

  // ── NEW (v2): resolve effective label and placeholder ──────────────────────
  const effectiveLabel = labelOverride ?? field.label;
  const effectivePlaceholder = placeholderOverride
    ?? (field.defaultValue ? `e.g. ${field.defaultValue}` : `Enter ${field.label.toLowerCase()}…`);

  // ── NEW (v2): filter helper for dropdown / radio ───────────────────────────
  function filterOpts(rawOpts) {
    if (!filterOptions || filterOptions.length === 0) return rawOpts;
    return rawOpts.filter(o =>
      filterOptions.includes(o.value) || filterOptions.includes(o.label)
    );
  }

  return (
    <div className="form-field-group" style={{
      animationDelay: `${(field.fieldOrder || 0) * 40}ms`,
      position: 'relative',
      zIndex: 100 - (field.fieldOrder || 0)
    }}>

      {/* Label */}
      {field.fieldType !== 'boolean' && (
        <label className="form-field-label" htmlFor={id}>
          {effectiveLabel}
          {field.required && <span className="form-field-required-star" title="Required"> *</span>}
          {field.isCalculated && <span className="badge badge-text" style={{ marginLeft: 8, background: 'rgba(99,102,241,0.1)', color: 'var(--accent)', fontSize: '0.7em', padding: '2px 6px' }}>∑ Calculated</span>}
        </label>
      )}

      {/* ── text ───────────────────────────────────────────────── */}
      {field.fieldType === 'text' && (
        <input
          id={id}
          type="text"
          className={inputClass}
          value={value || ''}
          onChange={(e) => onChange(e.target.value)}
          onBlur={(e) => onBlur(e.target.value)}
          placeholder={effectivePlaceholder}
          disabled={disabled}
          autoComplete="off"
          aria-describedby={hasError ? `${id}-err` : undefined}
          aria-invalid={hasError || undefined}
        />
      )}

      {/* ── number ─────────────────────────────────────────────── */}
      {field.fieldType === 'number' && (
        <input
          id={id}
          type="number"
          className={inputClass}
          value={value || ''}
          onChange={(e) => onChange(e.target.value)}
          onBlur={(e) => onBlur(e.target.value)}
          placeholder={placeholderOverride ?? (field.defaultValue || '')}
          min={min ?? undefined}
          max={max ?? undefined}
          disabled={disabled}
          aria-describedby={hasError ? `${id}-err` : undefined}
          aria-invalid={hasError || undefined}
        />
      )}

      {/* ── date ───────────────────────────────────────────────── */}
      {field.fieldType === 'date' && (() => {
        // Parse the configured display format from validationJson
        let customFormat = 'YYYY-MM-DD';
        try {
          const rules = JSON.parse(field.validationJson || '{}');
          if (rules.customFormat) customFormat = rules.customFormat;
        } catch { }

        return (
          <>
            <input
              id={id}
              type="date"
              className={inputClass}
              value={value || ''}
              onChange={(e) => onChange(e.target.value)}
              onBlur={(e) => onBlur(e.target.value)}
              min={min ?? undefined}
              max={max ?? undefined}
              disabled={disabled}
              aria-describedby={hasError ? `${id}-err` : undefined}
              aria-invalid={hasError || undefined}
            />
            {customFormat && customFormat !== 'YYYY-MM-DD' && (
              <span className="form-field-hint">
                 Display format: {customFormat}
              </span>
            )}
          </>
        );
      })()}

      {/* ── boolean ────────────────────────────────────────────── */}
      {field.fieldType === 'boolean' && (
        <label
          className={`bool-toggle-wrap${disabled ? ' opacity-50' : ''}${hasError ? ' bool-toggle-error' : ''}`}
          htmlFor={id}
        >
          <input
            id={id}
            type="checkbox"
            checked={!!value}
            onChange={(e) => { onChange(e.target.checked); onBlur(e.target.checked); }}
            disabled={disabled}
            aria-invalid={hasError || undefined}
          />
          <span className="bool-toggle-label">
            {effectiveLabel}
            {field.required && <span className="form-field-required-star"> *</span>}
          </span>
        </label>
      )}

      {/* ── dropdown (single or multi) ─────────────────────────── */}
      {field.fieldType === 'dropdown' && (() => {
        let isMulti = false;
        try {
          const uiCfg = JSON.parse(field.uiConfigJson || '{}');
          isMulti = !!uiCfg.multiple;
        } catch { }

        const options = filterOpts(parseOptions(field.optionsJson, field.options));

        if (!isMulti) {
          return (
            <select
              id={id}
              className={`form-select${hasError ? ' input-error' : ''}`}
              value={value || ''}
              onChange={(e) => onChange(e.target.value)}
              onBlur={(e) => onBlur(e.target.value)}
              disabled={disabled}
              aria-describedby={hasError ? `${id}-err` : undefined}
              aria-invalid={hasError || undefined}
            >
              <option value="">— Select {effectiveLabel} —</option>
              {options.map((opt, i) => (
                <option key={i} value={opt.value}>{opt.label}</option>
              ))}
            </select>
          );
        }

        // ── Custom Multi-Select Dropdown ──
        // Parse current value string array
        let selected = [];
        if (value) {
          const str = String(value).trim();
          if (str.startsWith('[')) {
            try { selected = JSON.parse(str); } catch { selected = []; }
          } else {
            selected = str.split(',').map(v => v.trim()).filter(Boolean);
          }
        }

        const [isOpen, setIsOpen] = useState(false);
        const dropdownRef = useRef(null);

        // Handle outside click
        useEffect(() => {
          const handleClickOutside = (event) => {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
              setIsOpen(false);
              onBlur(value);
            }
          };
          if (isOpen) {
            document.addEventListener("mousedown", handleClickOutside);
          } else {
            document.removeEventListener("mousedown", handleClickOutside);
          }
          return () => document.removeEventListener("mousedown", handleClickOutside);
        }, [isOpen, onBlur, value]);

        const handleRemove = (e, valToRemove) => {
          e.stopPropagation();
          if (disabled) return;
          const nextSelected = selected.filter(v => v !== valToRemove);
          onChange(nextSelected); // Pass the array directly, not stringified
        };

        const handleSelect = (valToAdd) => {
          if (disabled) return;
          let nextSelected;
          if (selected.includes(valToAdd)) {
            nextSelected = selected.filter(v => v !== valToAdd);
          } else {
            nextSelected = [...selected, valToAdd];
          }
          onChange(nextSelected); // Pass the array directly
          // keep open to allow multiple selections
        };

        return (
          <div ref={dropdownRef} style={{ position: 'relative', zIndex: isOpen ? 99 : 1 }}>
            <div
              className={`form-select${hasError ? ' input-error' : ''}`}
              style={{
                display: 'flex', flexWrap: 'wrap', gap: '6px', minHeight: '44px', paddingBottom: '7px', paddingTop: '7px',
                alignItems: 'center', cursor: disabled ? 'not-allowed' : 'pointer',
                opacity: disabled ? 0.6 : 1
              }}
              onClick={() => !disabled && setIsOpen(!isOpen)}
            >
              {selected.length === 0 ? (
                <span style={{ color: 'var(--text-muted)' }}>— Select {effectiveLabel} —</span>
              ) : (
                selected.map((val) => {
                  const optLabel = options.find(o => o.value === val)?.label || val;
                  return (
                    <span key={val} style={{
                      display: 'inline-flex', alignItems: 'center', gap: '4px',
                      padding: '2px 8px', borderRadius: '12px', fontSize: '13px',
                      background: 'rgba(99,102,241,0.15)', color: '#EDE9FF', border: '1px solid rgba(99,102,241,0.3)',
                    }}>
                      {optLabel}
                      <button
                        type="button"
                        onClick={(e) => handleRemove(e, val)}
                        style={{
                          background: 'none', border: 'none', color: '#9899BA', cursor: 'pointer', fontSize: '12px',
                          padding: 0, marginLeft: '2px', lineHeight: 1
                        }}
                      >✕</button>
                    </span>
                  );
                })
              )}
            </div>

            {isOpen && !disabled && (
              <ul style={{
                position: 'absolute', top: '100%', left: 0, right: 0, zIndex: 9999,
                marginTop: '6px', padding: '6px', background: '#13112b',
                border: '1px solid rgba(255,255,255,0.1)', borderRadius: '10px',
                boxShadow: '0 8px 32px rgba(0,0,0,0.55)', maxHeight: '250px', overflowY: 'auto', listStyle: 'none'
              }}>
                {options.length === 0 ? (
                  <li style={{ padding: '8px 12px', color: 'var(--text-muted)', fontSize: '14px', fontFamily: "'Inter', sans-serif" }}>No options</li>
                ) : (
                  options.map((opt, i) => {
                    const isSelected = selected.includes(opt.value);
                    return (
                      <li
                        key={i}
                        onClick={() => handleSelect(opt.value)}
                        style={{
                          padding: '8px 12px', cursor: 'pointer', borderRadius: '6px', fontSize: '14px', fontFamily: "'Inter', sans-serif",
                          display: 'flex', alignItems: 'center', gap: '10px',
                          background: isSelected ? '#2a2060' : 'transparent',
                          color: isSelected ? '#ffffff' : '#EDE9FF',
                        }}
                        onMouseOver={(e) => {
                          if (!isSelected) e.currentTarget.style.background = 'rgba(255,255,255,0.05)';
                        }}
                        onMouseOut={(e) => {
                          if (!isSelected) e.currentTarget.style.background = 'transparent';
                        }}
                      >
                        <input
                          type="checkbox"
                          checked={isSelected}
                          readOnly
                          style={{ accentColor: 'var(--accent)', width: '16px', height: '16px', borderRadius: '4px', cursor: 'pointer' }}
                        />
                        {opt.label}
                      </li>
                    );
                  })
                )}
              </ul>
            )}
          </div>
        );
      })()}

      {/* ── radio (single-select radio buttons) ────────────────── */}
      {field.fieldType === 'radio' && (
        <div
          className={`radio-group${hasError ? ' radio-group-error' : ''}`}
          role="radiogroup"
          aria-describedby={hasError ? `${id}-err` : undefined}
        >
          {filterOpts(parseOptions(field.optionsJson, field.options)).map((opt, i) => (
            <label key={i} className="radio-option">
              <input
                type="radio"
                name={id}
                value={opt.value}
                checked={value === opt.value}
                onChange={(e) => { onChange(e.target.value); onBlur(e.target.value); }}
                disabled={disabled}
              />
              <span>{opt.label}</span>
            </label>
          ))}
        </div>
      )}

      {/* ── multiple_choice (multi-select checkboxes) ─────────── */}
      {field.fieldType === 'multiple_choice' && (
        <div
          className={`radio-group${hasError ? ' multiple-choice-error' : ''}`}
          role="group"
          aria-describedby={hasError ? `${id}-err` : undefined}
        >
          {filterOpts(parseOptions(field.optionsJson, field.options)).map((opt, i) => {
            // value stored as JSON array string e.g. '["Red","Blue"]'
            let selected = [];
            if (value) {
              const str = String(value).trim();
              if (str.startsWith('[')) {
                try { selected = JSON.parse(str); } catch { selected = []; }
              } else {
                selected = str.split(',').map(v => v.trim()).filter(Boolean);
              }
            }
            const isChecked = selected.includes(opt.value);
            const handleCheckChange = (e) => {
              e.stopPropagation();
              // Always re-parse current value fresh to avoid stale closure
              let currentSelected = [];
              if (value) {
                const str = String(value).trim();
                if (str.startsWith('[')) {
                  try { currentSelected = JSON.parse(str); } catch { currentSelected = []; }
                } else {
                  currentSelected = str.split(',').map(v => v.trim()).filter(Boolean);
                }
              }
              const checked = e.target.checked;
              const next = checked
                ? [...currentSelected, opt.value]
                : currentSelected.filter(v => v !== opt.value);
              const unique = [...new Set(next)];
              // Store as JSON array string
              onChange(JSON.stringify(unique));
            };
            return (
              <label key={i} className="radio-option checkbox-style">
                <input
                  type="checkbox"
                  name={id}
                  value={opt.value}
                  checked={isChecked}
                  onChange={handleCheckChange}
                  disabled={disabled}
                />
                <span>{opt.label}</span>
              </label>
            );
          })}
        </div>
      )}

      {/* ── multiple_choice_grid ────────────────────────────────── */}
      {field.fieldType === 'multiple_choice_grid' && (() => {
        // gridJson comes from /render endpoint: {"rows":[...],"columns":[...]}
        let rows = [], cols = [];
        if (field.gridJson) {
          try {
            const g = JSON.parse(field.gridJson);
            rows = g.rows || [];
            cols = g.columns || [];
          } catch { }
        }
        // Current value is a JSON object {"Row":"Col"}
        let selected = {};
        if (value && typeof value === 'string') {
          try { selected = JSON.parse(value); } catch { }
        } else if (value && typeof value === 'object') {
          selected = value;
        }
        const handleGridChange = (row, col) => {
          if (disabled) return;
          const next = { ...selected, [row]: col };
          onChange(JSON.stringify(next));
          onBlur(JSON.stringify(next));
        };
        return (
          <div className={`mcg-wrapper${hasError ? ' input-error-group' : ''}`}>
            <table className="mcg-table">
              <thead>
                <tr className="mcg-header-row">
                  <th></th>
                  {cols.map((col, ci) => <th key={ci}>{col}</th>)}
                </tr>
              </thead>
              <tbody>
                {rows.map((row, ri) => (
                  <tr key={ri} className="mcg-row">
                    <td className="mcg-row-label">{row}</td>
                    {cols.map((col, ci) => (
                      <td key={ci} className="mcg-cell">
                        <label className={`mcg-radio-wrap${disabled ? ' disabled' : ''}`}>
                          <input
                            type="radio"
                            name={`${id}-row-${ri}`}
                            value={col}
                            checked={selected[row] === col}
                            onChange={() => handleGridChange(row, col)}
                            disabled={disabled}
                          />
                          <span className="mcg-radio-circle">
                            <span className="mcg-radio-dot" />
                          </span>
                        </label>
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        );
      })()}

      {/* ── linear_scale ───────────────────────────────────────── */}
      {field.fieldType === 'linear_scale' && (() => {
        // Parse ui_config_json for scale bounds and labels
        let uiCfg = {};
        if (field.uiConfigJson) {
          try { uiCfg = JSON.parse(field.uiConfigJson); } catch { }
        }
        const scaleMin = uiCfg.scaleMin ?? 1;
        const scaleMax = uiCfg.scaleMax ?? 5;
        const labelLeft = uiCfg.labelLeft || '';
        const labelRight = uiCfg.labelRight || '';
        const steps = [];
        for (let i = scaleMin; i <= scaleMax; i++) steps.push(i);
        const selected = value !== '' && value !== null && value !== undefined ? Number(value) : null;
        return (
          <div className={`linear-scale-wrapper${hasError ? ' input-error-group' : ''}`}>
            <div className="linear-scale-inner">
              <div className="linear-scale-track" role="group" aria-label={effectiveLabel}>
                {steps.map((step) => {
                  const isActive = selected === step;
                  return (
                    <button
                      key={step}
                      type="button"
                      className={`linear-scale-btn${isActive ? ' active' : ''}`}
                      onClick={() => { if (!disabled) { onChange(step); onBlur(step); } }}
                      disabled={disabled}
                      aria-pressed={isActive}
                      aria-label={`${step}`}
                    >
                      {step}
                    </button>
                  );
                })}
              </div>
              {(labelLeft || labelRight) && (
                <div className="linear-scale-labels">
                  <span className="linear-scale-label-left">{labelLeft}</span>
                  <span className="linear-scale-label-right">{labelRight}</span>
                </div>
              )}
            </div>
          </div>
        );
      })()}

      {/* ── star_rating ────────────────────────────────────────── */}
      {field.fieldType === 'star_rating' && (() => {
        // Parse ui_config_json for scale bounds and labels
        let uiCfg = {};
        if (field.uiConfigJson) {
          try { uiCfg = JSON.parse(field.uiConfigJson); } catch { }
        }
        const scaleMin = uiCfg.scaleMin ?? 1;
        const scaleMax = uiCfg.scaleMax ?? 5;
        const labelLeft = uiCfg.labelLeft || '';
        const labelRight = uiCfg.labelRight || '';
        const steps = [];
        for (let i = scaleMin; i <= scaleMax; i++) steps.push(i);
        const selected = value !== '' && value !== null && value !== undefined ? Number(value) : null;
        return (
          <div className={`linear-scale-wrapper${hasError ? ' input-error-group' : ''}`}>
            <div className="linear-scale-inner">
              <div className="linear-scale-track" role="group" aria-label={effectiveLabel}>
                {steps.map((step) => {
                  const isActive = selected === step;
                  return (
                    <button
                      key={step}
                      type="button"
                      className={`linear-scale-btn star-rating-btn${isActive ? ' active' : ''}`}
                      onClick={() => { if (!disabled) { onChange(step); onBlur(step); } }}
                      disabled={disabled}
                      aria-pressed={isActive}
                      aria-label={`${step}`}
                    >
                      {isActive ? '★' : '☆'}
                    </button>
                  );
                })}
              </div>
              {(labelLeft || labelRight) && (
                <div className="linear-scale-labels">
                  <span className="linear-scale-label-left">{labelLeft}</span>
                  <span className="linear-scale-label-right">{labelRight}</span>
                </div>
              )}
            </div>
          </div>
        );
      })()}

      {/* ── checkbox_grid ──────────────────────────────────────── */}
      {field.fieldType === 'checkbox_grid' && (() => {
        // gridJson comes from /render endpoint: {"rows":[...],"columns":[...]}
        let rows = [], cols = [];
        if (field.gridJson) {
          try {
            const g = JSON.parse(field.gridJson);
            rows = g.rows || [];
            cols = g.columns || [];
          } catch { }
        }
        // Current value: {"Row":["ColA","ColB"]} — arrays per row (multi-select)
        let selected = {};
        if (value && typeof value === 'string') {
          try { selected = JSON.parse(value); } catch { }
        } else if (value && typeof value === 'object') {
          selected = value;
        }
        const handleCbChange = (row, col, checked) => {
          if (disabled) return;
          const cur = Array.isArray(selected[row]) ? selected[row] : (selected[row] ? [selected[row]] : []);
          const next = checked ? [...new Set([...cur, col])] : cur.filter(v => v !== col);
          const updated = { ...selected, [row]: next };
          onChange(JSON.stringify(updated));
          onBlur(JSON.stringify(updated));
        };
        return (
          <div className={`mcg-wrapper${hasError ? ' input-error-group' : ''}`}>
            <table className="mcg-table">
              <thead>
                <tr className="mcg-header-row">
                  <th></th>
                  {cols.map((col, ci) => <th key={ci}>{col}</th>)}
                </tr>
              </thead>
              <tbody>
                {rows.map((row, ri) => {
                  const rowSel = Array.isArray(selected[row]) ? selected[row] : (selected[row] ? [selected[row]] : []);
                  return (
                    <tr key={ri} className="mcg-row">
                      <td className="mcg-row-label">{row}</td>
                      {cols.map((col, ci) => (
                        <td key={ci} className="mcg-cell">
                          <label className={`mcg-checkbox-wrap${disabled ? ' disabled' : ''}`}>
                            <input
                              type="checkbox"
                              value={col}
                              checked={rowSel.includes(col)}
                              onChange={(e) => handleCbChange(row, col, e.target.checked)}
                              disabled={disabled}
                            />
                            <span className="mcg-checkbox-box">
                              <span className="mcg-checkbox-tick">✓</span>
                            </span>
                          </label>
                        </td>
                      ))}
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        );
      })()}

      {/* ── file ───────────────────────────────────────────────── */}
      {field.fieldType === 'file' && (
        <input
          id={id}
          type="file"
          className={inputClass}
          multiple={getMultiple(field.validationJson)}
          accept={getAllowedAccept(field.validationJson)}
          onChange={(e) => {
            const files = e.target.files;
            if (!files || files.length === 0) return;
            // Pass full FileList so multi-file validation works
            const payload = files.length === 1 ? files[0] : files;
            onChange(payload);
            onBlur(payload);
          }}
          disabled={disabled}
          aria-describedby={hasError ? `${id}-err` : undefined}
          aria-invalid={hasError || undefined}
        />
      )}

      {/* ── Error (shows after first interaction, highest-priority only) ── */}
      {hasError && (
        <span id={`${id}-err`} className="form-field-error" role="alert" aria-live="polite">
          {shownError}
        </span>
      )}
    </div>
  );
}

// ─── Utilities ────────────────────────────────────────────────────────────────

function parseOptions(optionsJson, resolvedOptions) {
  // Priority 1: pre-resolved [{label, value}] objects from /render endpoint
  if (Array.isArray(resolvedOptions) && resolvedOptions.length > 0) {
    return resolvedOptions; // already [{label, value}]
  }
  // Priority 2: inline optionsJson string ["Opt1","Opt2"]
  if (!optionsJson || optionsJson === 'null') return [];
  try {
    const parsed = JSON.parse(optionsJson);
    if (!Array.isArray(parsed)) return [];
    // Could be strings or objects
    return parsed.map(o =>
      typeof o === 'string' ? { label: o, value: o } : o
    );
  } catch { return []; }
}

function getMultiple(validationJson) {
  try {
    return JSON.parse(validationJson || '{}').singleOrMultiple === 'multiple';
  } catch { return false; }
}

/**
 * Build the `accept` attribute from validationJson.
 * Uses allowedExtensions (e.g. ".pdf,.png") and/or mimeTypeValidation.
 * Returns empty string if no restriction (browser shows all files).
 */
function getAllowedAccept(validationJson) {
  try {
    const rules = JSON.parse(validationJson || '{}');
    const parts = [];
    if (rules.allowedExtensions) {
      rules.allowedExtensions.split(',')
        .map(e => e.trim().toLowerCase())
        .filter(Boolean)
        .forEach(ext => parts.push(ext.startsWith('.') ? ext : `.${ext}`));
    }
    if (rules.mimeTypeValidation) {
      rules.mimeTypeValidation.split(',')
        .map(m => m.trim())
        .filter(Boolean)
        .forEach(m => { if (!parts.includes(m)) parts.push(m); });
    }
    return parts.join(',');
  } catch { return ''; }
}

import { useState, useEffect } from 'react';
import { useRouter } from 'next/router';
import Head from 'next/head';
import FormRenderer from '../../components/FormRenderer';
import { getFormRender, submitForm, isSchemaDriftError, saveSchemaDriftReport } from '../../services/api';
import { toastSuccess, toastError } from '../../services/toast';

/**
 * Public Submission Page — /submit/[id]
 *
 * Accessible without authentication.
 * Flow:
 *   1. Load form config (GET /api/forms/:id — public endpoint)
 *   2. Render FormRenderer with real submit enabled
 *   3. FormRenderer validates client-side (required + regex)
 *   4. On valid submit → POST /api/forms/:id/submit
 *   5. Backend validates again (required + regex) then INSERTs into form's table
 *   6. Toast + success screen on response
 */
export default function SubmitPage() {
    const router = useRouter();
    const { id } = router.query;

    const [form, setForm] = useState(null);
    const [loading, setLoading] = useState(true);
    const [notFound, setNotFound] = useState(false);
    const [isDraft, setIsDraft] = useState(false);
    const [alreadySubmitted, setAlreadySubmitted] = useState(false);
    const [isExpired, setIsExpired] = useState(false);
    const [submitted, setSubmitted] = useState(false); // shown after successful submit
    const [versionMismatch, setVersionMismatch] = useState(false);
    const [draftDiscarded, setDraftDiscarded] = useState(false);
    const [submissionId, setSubmissionId] = useState(null);
    const [initialValues, setInitialValues] = useState({});

    // 1. Initial Load: Fetch Form Configuration
    useEffect(() => {
        if (!id) return;
        setLoading(true);
        getFormRender(id)
            .then((data) => {
                const formObj = {
                    id: data.formId,
                    formVersionId: data.formVersionId,
                    versionNumber: data.versionNumber,
                    name: data.formName,
                    description: data.formDescription,
                    allowMultipleSubmissions: data.allowMultipleSubmissions ?? true,
                    showTimestamp: data.showTimestamp ?? false,
                    fields: (data.fields || []).map(f => ({ ...f })),
                    groups: data.groups || [],
                };
                setForm(formObj);

                if (data.expiresAt && new Date(data.expiresAt) < new Date()) {
                    setIsExpired(true);
                }

                if (!formObj.allowMultipleSubmissions) {
                    const key = `submitted_${id}`;
                    if (typeof window !== 'undefined' && localStorage.getItem(key)) {
                        setAlreadySubmitted(true);
                    }
                }
            })
            .catch((err) => {
                if (err?.status === 403) setIsDraft(true);
                else if (err?.status === 404) setNotFound(true);
                else if (err?.status === 410) setIsExpired(true);
                else if (err?.status === 409) setAlreadySubmitted(true);
                else toastError('Failed to load form.');
            })
            .finally(() => setLoading(false));
    }, [id]);

    // 2. Draft Recovery: Fetch existing draft if authenticated
    useEffect(() => {
        if (!id || !form) return;

        import('../../services/api').then(api => {
            api.getDraft(id).then(draft => {
                if (draft && draft.submissionId) {
                    // Check if draft version matches current form version
                    // Note: Backend might have cleared stale drafts, but we check here too.
                    if (draft.formVersionId !== form.formVersionId) {
                        console.warn("Draft version mismatch detected");

                        // Clear the local flag if we found a mismatching draft (stale)
                        if (localStorage.getItem(`draft_form_${id}`)) {
                            setDraftDiscarded(true);
                            localStorage.removeItem(`draft_form_${id}`);
                        }
                    } else {
                        setSubmissionId(draft.submissionId);
                        setInitialValues(draft);
                    }
                }
            }).catch(err => {
                // F2: Draft not found warning for returning users
                if (err?.status === 404) {
                    const key = `draft_form_${id}`;
                    if (localStorage.getItem(key)) {
                        setDraftDiscarded(true);
                        localStorage.removeItem(key);
                    }
                }
            });
        });
    }, [id, form]);

    const redirectToDriftPage = (error) => {
        saveSchemaDriftReport({
            source: 'submit',
            formId: id || null,
            action: 'submit',
            at: new Date().toISOString(),
            message: error?.message || 'Schema drift detected',
            errorCode: error?.errorCode,
            errors: Array.isArray(error?.errors) ? error.errors : [],
            details: error?.details || null,
        });
        toastError('Schema drift detected for this form. Submission is temporarily blocked.');
        router.push('/schema-drift');
    };

    const handleSubmit = async (values) => {
        try {
            // F1/F3 Compliance: Pass formVersionId to ensure authority checks
            // Backend is the only source (stored in form.formVersionId state)
            await submitForm(id, values, submissionId, form?.formVersionId);

            if (form && !form.allowMultipleSubmissions) {
                localStorage.setItem(`submitted_${id}`, '1');
            }
            // Clear draft flag on successful submit
            localStorage.removeItem(`draft_form_${id}`);

            toastSuccess('Form submitted successfully! ');
            setSubmitted(true);
        } catch (err) {
            if (isSchemaDriftError(err)) {
                redirectToDriftPage(err);
                return;
            }

            // F1: Version Mismatch (409 Conflict returned by B2/B3 guards)
            if (err?.status === 409 && err.message?.includes('VERSION_MISMATCH')) {
                setVersionMismatch(true);
                toastError('The form version has changed. Please refresh.');
                return;
            }

            // Single-submit conflict only (do not treat SCHEMA_DRIFT as already submitted)
            if (err?.status === 409 && err?.errorCode === 'CONFLICT') {
                localStorage.setItem(`submitted_${id}`, '1');
                setAlreadySubmitted(true);
                toastError('You have already submitted this form.');
                return;
            }
            if (err?.status === 410) {
                setIsExpired(true);
                toastError('This form has expired.');
                return;
            }
            if (err?.errors && Array.isArray(err.errors) && err.errors.length > 0) {
                const firstErr = err.errors[0];
                const preview = typeof firstErr === 'object' ? firstErr.message : String(firstErr);
                toastError(preview || 'Please fix the errors and try again.');
            } else {
                toastError(err?.message || 'Submission failed.');
            }
            throw err;
        }
    };

    // ── Loading ────────────────────────────────────────────────────────────────

    if (loading) {
        return (
            <div style={{
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                height: '100vh', background: 'var(--bg-base)',
            }}>
                <span className="spinner" style={{ width: 36, height: 36 }} />
            </div>
        );
    }

    // ── Success — form was just submitted ──────────────────────────────────────

    if (submitted) {
        return (
            <>
                <Head><title>Submitted — {form?.name || 'FormCraft'}</title></Head>
                <div className="form-page">
                    <div className="form-page-nav animate-down" style={{ justifyContent: 'center' }}>
                        <span style={{ fontFamily: 'Outfit', fontWeight: 800, fontSize: 16, background: 'var(--accent-grad)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>
                            ⚡ FormCraft
                        </span>
                    </div>
                    <div className="form-renderer-card" style={{ padding: '64px 32px', textAlign: 'center', maxWidth: 560, margin: '0 auto' }}>
                        {/* Animated checkmark */}
                        <div style={{
                            width: 80, height: 80, borderRadius: '50%',
                            background: 'linear-gradient(135deg, rgba(16,185,129,0.2), rgba(16,185,129,0.08))',
                            border: '2px solid rgba(16,185,129,0.4)',
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            margin: '0 auto 24px',
                            boxShadow: '0 0 32px rgba(16,185,129,0.2)',
                            fontSize: 36,
                        }}>
                            ✅
                        </div>
                        <h2 style={{
                            fontFamily: 'Outfit', fontSize: 28, fontWeight: 800,
                            color: 'var(--text-primary)', marginBottom: 12, letterSpacing: '-0.02em',
                        }}>
                            Response Submitted!
                        </h2>
                        <p style={{
                            color: 'var(--text-secondary)', fontSize: 15,
                            maxWidth: 380, margin: '0 auto 28px', lineHeight: 1.6,
                        }}>
                            Your response for <strong style={{ color: 'var(--text-primary)' }}>{form?.name}</strong> has been recorded successfully. Thank you!
                        </p>
                        <div style={{ display: 'flex', gap: 12, justifyContent: 'center', flexWrap: 'wrap' }}>
                            <span style={{
                                display: 'inline-flex', alignItems: 'center', gap: 6,
                                padding: '8px 20px', borderRadius: 20,
                                background: 'rgba(16,185,129,0.12)', color: '#34D399',
                                border: '1px solid rgba(16,185,129,0.28)', fontSize: 13, fontWeight: 700,
                            }}>
                                ✓ Response recorded
                            </span>
                        </div>
                    </div>
                    <p style={{ marginTop: 20, fontSize: 12, color: 'var(--text-muted)', textAlign: 'center' }}>
                        Powered by FormCraft
                    </p>
                </div>
            </>
        );
    }

    // ── Version Mismatch (409 Conflict) ────────────────────────────────────────
    if (versionMismatch) {
        return (
            <>
                <Head><title>Version Updated — FormCraft</title></Head>
                <div className="form-page">
                    <div className="form-page-nav animate-down" style={{ justifyContent: 'center' }}>
                        <span style={{ fontFamily: 'Outfit', fontWeight: 800, fontSize: 16, background: 'var(--accent-grad)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>⚡ FormCraft</span>
                    </div>
                    <div className="form-renderer-card" style={{ padding: '60px 32px', textAlign: 'center' }}>
                        <div style={{ fontSize: 60, marginBottom: 20 }}></div>
                        <h2 style={{ fontFamily: 'Outfit', fontSize: 26, marginBottom: 12, color: 'var(--text-primary)', fontWeight: 800 }}>
                            Form Updated
                        </h2>
                        <p style={{ color: 'var(--text-secondary)', fontSize: 15, maxWidth: 420, margin: '0 auto 24px' }}>
                            A new version of this form has been published. To ensure data integrity, please refresh the page to load the latest fields.
                        </p>
                        <button 
                            onClick={() => router.reload()}
                            style={{
                                background: 'var(--accent-primary)', color: 'white',
                                border: 'none', padding: '12px 28px', borderRadius: 8,
                                fontWeight: 700, cursor: 'pointer', fontSize: 15,
                                boxShadow: '0 4px 12px rgba(var(--accent-primary-rgb), 0.3)'
                            }}
                        >
                            Refresh Page
                        </button>
                    </div>
                    <p style={{ marginTop: 20, fontSize: 12, color: 'var(--text-muted)', textAlign: 'center' }}>Powered by FormCraft</p>
                </div>
            </>
        );
    }

    // ── Already submitted ──────────────────────────────────────────────────────

    if (alreadySubmitted) {
        return (
            <>
                <Head><title>Already Submitted — FormCraft</title></Head>
                <div className="form-page">
                    <div className="form-page-nav animate-down" style={{ justifyContent: 'center' }}>
                        <span style={{ fontFamily: 'Outfit', fontWeight: 800, fontSize: 16, background: 'var(--accent-grad)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>⚡ FormCraft</span>
                    </div>
                    <div className="form-renderer-card" style={{ padding: '60px 32px', textAlign: 'center' }}>
                        <div style={{ fontSize: 60, marginBottom: 20 }}>✅</div>
                        <h2 style={{ fontFamily: 'Outfit', fontSize: 26, marginBottom: 12, color: 'var(--text-primary)', fontWeight: 800 }}>
                            Already Submitted
                        </h2>
                        <p style={{ color: 'var(--text-secondary)', fontSize: 15, maxWidth: 380, margin: '0 auto 24px' }}>
                            You have already submitted a response for this form. Only one submission per person is allowed.
                        </p>
                        <span style={{
                            display: 'inline-block',
                            padding: '7px 20px', borderRadius: 20,
                            background: 'rgba(16,185,129,0.12)',
                            color: '#34D399',
                            border: '1px solid rgba(16,185,129,0.28)',
                            fontSize: 13, fontWeight: 700,
                        }}>
                             One response per person
                        </span>
                    </div>
                    <p style={{ marginTop: 20, fontSize: 12, color: 'var(--text-muted)', textAlign: 'center' }}>Powered by FormCraft</p>
                </div>
            </>
        );
    }

    // ── Expired ────────────────────────────────────────────────────────────────

    if (isExpired) {
        return (
            <>
                <Head><title>Form Expired — FormCraft</title></Head>
                <div className="form-page">
                    <div className="form-page-nav animate-down" style={{ justifyContent: 'center' }}>
                        <span style={{ fontFamily: 'Outfit', fontWeight: 800, fontSize: 16, background: 'var(--accent-grad)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>⚡ FormCraft</span>
                    </div>
                    <div className="form-renderer-card" style={{ padding: '60px 32px', textAlign: 'center' }}>
                        <div style={{ fontSize: 60, marginBottom: 20 }}>⏰</div>
                        <h2 style={{ fontFamily: 'Outfit', fontSize: 26, marginBottom: 12, color: 'var(--text-primary)', fontWeight: 800 }}>
                            Form Expired
                        </h2>
                        <p style={{ color: 'var(--text-secondary)', fontSize: 15, maxWidth: 400, margin: '0 auto 24px' }}>
                            This form is no longer accepting responses. The submission deadline has passed.
                        </p>
                        <span style={{
                            display: 'inline-block', padding: '7px 20px', borderRadius: 20,
                            background: 'rgba(239,68,68,0.12)', color: '#F87171',
                            border: '1px solid rgba(239,68,68,0.28)', fontSize: 13, fontWeight: 700,
                        }}>
                             Submission closed
                        </span>
                    </div>
                    <p style={{ marginTop: 20, fontSize: 12, color: 'var(--text-muted)', textAlign: 'center' }}>Powered by FormCraft</p>
                </div>
            </>
        );
    }

    // ── DRAFT — form not accepting submissions ─────────────────────────────────

    if (isDraft) {
        return (
            <>
                <Head><title>Form Not Available — FormCraft</title></Head>
                <div className="form-page">
                    <div className="form-renderer-card" style={{ padding: '60px 32px', textAlign: 'center' }}>
                        <div style={{ fontSize: 56, marginBottom: 20 }}></div>
                        <h2 style={{ fontFamily: 'Outfit', fontSize: 24, marginBottom: 12, color: 'var(--text-primary)' }}>
                            Form Not Available
                        </h2>
                        <p style={{ color: 'var(--text-secondary)', fontSize: 15, maxWidth: 380, margin: '0 auto' }}>
                            This form is not currently accepting responses. It may still be a draft or temporarily closed.
                        </p>
                        <div style={{ marginTop: 8 }}>
                            <span style={{
                                display: 'inline-block', marginTop: 20,
                                padding: '6px 18px', borderRadius: 20,
                                background: 'rgba(245,158,11,0.15)',
                                color: '#FCD34D',
                                border: '1px solid rgba(245,158,11,0.3)',
                                fontSize: 13, fontWeight: 600,
                            }}>
                                 DRAFT
                            </span>
                        </div>
                    </div>
                    <p style={{ marginTop: 20, fontSize: 12, color: 'var(--text-muted)', textAlign: 'center' }}>
                        Powered by FormCraft
                    </p>
                </div>
            </>
        );
    }

    // ── Not found ──────────────────────────────────────────────────────────────

    if (notFound || !form) {
        return (
            <>
                <Head><title>Form Not Found — FormCraft</title></Head>
                <div className="form-page">
                    <div className="form-renderer-card" style={{ padding: '60px 32px', textAlign: 'center' }}>
                        <div style={{ fontSize: 48, marginBottom: 16 }}></div>
                        <h2 style={{ fontFamily: 'Outfit', fontSize: 22, marginBottom: 8 }}>Form Not Found</h2>
                        <p style={{ color: 'var(--text-secondary)', fontSize: 14 }}>
                            This form link may be invalid or the form has been deleted.
                        </p>
                    </div>
                </div>
            </>
        );
    }

    // ── Render ─────────────────────────────────────────────────────────────────

    return (
        <>
            <Head>
                <title>{form.name} — FormCraft</title>
                <meta name="description" content={form.description || `Fill out ${form.name}`} />
            </Head>

            <div className="form-page">
                {/* Minimal branding header for public page */}
                <div className="form-page-nav animate-down" style={{ justifyContent: 'center' }}>
                    <span style={{
                        fontFamily: 'Outfit', fontWeight: 800, fontSize: 16,
                        background: 'var(--accent-grad)',
                        WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent',
                    }}>
                        ⚡ FormCraft
                    </span>
                </div>

                {/* F2: Draft discarded warning banner */}
                {draftDiscarded && (
                    <div style={{
                        maxWidth: 700, margin: '0 auto 14px',
                        padding: '12px 20px', borderRadius: 12,
                        background: 'rgba(245,158,11,0.12)', border: '1px solid rgba(245,158,11,0.3)',
                        color: '#FBBF24', fontSize: 13, fontWeight: 500, display: 'flex', gap: 10, alignItems: 'center',
                        animation: 'fadeIn 0.3s ease-out'
                    }}>
                        <span style={{ fontSize: 18 }}>⚠️</span>
                        <div style={{ flex: 1 }}>
                            <strong>Your saved progress was lost</strong> because this form was updated.
                            You are starting fresh with the latest version.
                        </div>
                        <button 
                            onClick={() => setDraftDiscarded(false)}
                            style={{ background: 'none', border: 'none', color: '#FBBF24', cursor: 'pointer', fontWeight: 800 }}
                        >
                            ✕
                        </button>
                    </div>
                )}

                {/* Single-submission notice */}
                {!form.allowMultipleSubmissions && (
                    <div style={{
                        maxWidth: 700, margin: '0 auto 14px',
                        padding: '10px 18px', borderRadius: 10,
                        background: 'rgba(245,158,11,0.10)',
                        border: '1px solid rgba(245,158,11,0.25)',
                        color: '#FCD34D', fontSize: 13, fontWeight: 500,
                        display: 'flex', alignItems: 'center', gap: 8,
                    }}>
                         This form allows <strong style={{ marginLeft: 4 }}>one submission per person</strong>.
                    </div>
                )}

                <FormRenderer
                    form={form}
                    initialData={initialValues}
                    isPreview={false}
                    onSubmit={handleSubmit}
                />

                <p style={{ marginTop: 20, fontSize: 12, color: 'var(--text-muted)', textAlign: 'center' }}>
                    Powered by FormCraft • Your response is securely recorded
                </p>
            </div>
        </>
    );
}

import { useState, useEffect } from 'react';
import { useRouter } from 'next/router';
import Head from 'next/head';
import FormRenderer from '../../components/FormRenderer';
import { getFormRender, submitForm, isSchemaDriftError, saveSchemaDriftReport } from '../../services/api';
import { toastSuccess, toastError } from '../../services/toast';

/**
 * Public Submission Page — /submit/[id]
 *
 * Accessible without authentication.
 * Flow:
 *   1. Load form config (GET /api/forms/:id — public endpoint)
 *   2. Render FormRenderer with real submit enabled
 *   3. FormRenderer validates client-side (required + regex)
 *   4. On valid submit → POST /api/forms/:id/submit
 *   5. Backend validates again (required + regex) then INSERTs into form's table
 *   6. Toast + success screen on response
 */
export default function SubmitPage() {
    const router = useRouter();
    const { id } = router.query;

    const [form, setForm] = useState(null);
    const [loading, setLoading] = useState(true);
    const [notFound, setNotFound] = useState(false);
    const [isDraft, setIsDraft] = useState(false);
    const [alreadySubmitted, setAlreadySubmitted] = useState(false);
    const [isExpired, setIsExpired] = useState(false);
    const [submitted, setSubmitted] = useState(false); // shown after successful submit
    const [versionMismatch, setVersionMismatch] = useState(false);
    const [draftDiscarded, setDraftDiscarded] = useState(false);
    const [submissionId, setSubmissionId] = useState(null);
    const [initialValues, setInitialValues] = useState({});

    // 1. Initial Load: Fetch Form Configuration
    useEffect(() => {
        if (!id) return;
        setLoading(true);
        getFormRender(id)
            .then((data) => {
                const formObj = {
                    id: data.formId,
                    formVersionId: data.formVersionId,
                    versionNumber: data.versionNumber,
                    name: data.formName,
                    description: data.formDescription,
                    allowMultipleSubmissions: data.allowMultipleSubmissions ?? true,
                    showTimestamp: data.showTimestamp ?? false,
                    fields: (data.fields || []).map(f => ({ ...f })),
                    groups: data.groups || [],
                };
                setForm(formObj);

                if (data.expiresAt && new Date(data.expiresAt) < new Date()) {
                    setIsExpired(true);
                }

                if (!formObj.allowMultipleSubmissions) {
                    const key = `submitted_${id}`;
                    if (typeof window !== 'undefined' && localStorage.getItem(key)) {
                        setAlreadySubmitted(true);
                    }
                }
            })
            .catch((err) => {
                if (err?.status === 403) setIsDraft(true);
                else if (err?.status === 404) setNotFound(true);
                else if (err?.status === 410) setIsExpired(true);
                else if (err?.status === 409) setAlreadySubmitted(true);
                else toastError('Failed to load form.');
            })
            .finally(() => setLoading(false));
    }, [id]);

    // 2. Draft Recovery: Fetch existing draft if authenticated
    useEffect(() => {
        if (!id || !form) return;

        import('../../services/api').then(api => {
            api.getDraft(id).then(draft => {
                if (draft && draft.submissionId) {
                    // Check if draft version matches current form version
                    // Note: Backend might have cleared stale drafts, but we check here too.
                    if (draft.formVersionId !== form.formVersionId) {
                        console.warn("Draft version mismatch detected");

                        // Clear the local flag if we found a mismatching draft (stale)
                        if (localStorage.getItem(`draft_form_${id}`)) {
                            setDraftDiscarded(true);
                            localStorage.removeItem(`draft_form_${id}`);
                        }
                    } else {
                        setSubmissionId(draft.submissionId);
                        setInitialValues(draft);
                    }
                }
            }).catch(err => {
                // F2: Draft not found warning for returning users
                if (err?.status === 404) {
                    const key = `draft_form_${id}`;
                    if (localStorage.getItem(key)) {
                        setDraftDiscarded(true);
                        localStorage.removeItem(key);
                    }
                }
            });
        });
    }, [id, form]);

    const redirectToDriftPage = (error) => {
        saveSchemaDriftReport({
            source: 'submit',
            formId: id || null,
            action: 'submit',
            at: new Date().toISOString(),
            message: error?.message || 'Schema drift detected',
            errorCode: error?.errorCode,
            errors: Array.isArray(error?.errors) ? error.errors : [],
            details: error?.details || null,
        });
        toastError('Schema drift detected for this form. Submission is temporarily blocked.');
        router.push('/schema-drift');
    };

    const handleSubmit = async (values) => {
        try {
            // F1/F3 Compliance: Pass formVersionId to ensure authority checks
            // Backend is the only source (stored in form.formVersionId state)
            await submitForm(id, values, submissionId, form?.formVersionId);

            if (form && !form.allowMultipleSubmissions) {
                localStorage.setItem(`submitted_${id}`, '1');
            }
            // Clear draft flag on successful submit
            localStorage.removeItem(`draft_form_${id}`);

            toastSuccess('Form submitted successfully! ');
            setSubmitted(true);
        } catch (err) {
            if (isSchemaDriftError(err)) {
                redirectToDriftPage(err);
                return;
            }

            // F1: Version Mismatch (409 Conflict returned by B2/B3 guards)
            if (err?.status === 409 && err.message?.includes('VERSION_MISMATCH')) {
                setVersionMismatch(true);
                toastError('The form version has changed. Please refresh.');
                return;
            }

            // Single-submit conflict only (do not treat SCHEMA_DRIFT as already submitted)
            if (
                err?.status === 409 &&
                err?.errorCode === 'CONFLICT' &&
                String(err?.message || '').toLowerCase().includes('already submitted')
            ) {
                localStorage.setItem(`submitted_${id}`, '1');
                setAlreadySubmitted(true);
                toastError('You have already submitted this form.');
                return;
            }
            if (err?.status === 410) {
                setIsExpired(true);
                toastError('This form has expired.');
                return;
            }
            if (err?.errors && Array.isArray(err.errors) && err.errors.length > 0) {
                const firstErr = err.errors[0];
                const preview = typeof firstErr === 'object' ? firstErr.message : String(firstErr);
                toastError(preview || 'Please fix the errors and try again.');
            } else {
                toastError(err?.message || 'Submission failed.');
            }
            throw err;
        }
    };

    // ── Loading ────────────────────────────────────────────────────────────────

    if (loading) {
        return (
            <div style={{
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                height: '100vh', background: 'var(--bg-base)',
            }}>
                <span className="spinner" style={{ width: 36, height: 36 }} />
            </div>
        );
    }

    // ── Success — form was just submitted ──────────────────────────────────────

    if (submitted) {
        return (
            <>
                <Head><title>Submitted — {form?.name || 'FormCraft'}</title></Head>
                <div className="form-page">
                    <div className="form-page-nav animate-down" style={{ justifyContent: 'center' }}>
                        <span style={{ fontFamily: 'Outfit', fontWeight: 800, fontSize: 16, background: 'var(--accent-grad)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>
                            ⚡ FormCraft
                        </span>
                    </div>
                    <div className="form-renderer-card" style={{ padding: '64px 32px', textAlign: 'center', maxWidth: 560, margin: '0 auto' }}>
                        {/* Animated checkmark */}
                        <div style={{
                            width: 80, height: 80, borderRadius: '50%',
                            background: 'linear-gradient(135deg, rgba(16,185,129,0.2), rgba(16,185,129,0.08))',
                            border: '2px solid rgba(16,185,129,0.4)',
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            margin: '0 auto 24px',
                            boxShadow: '0 0 32px rgba(16,185,129,0.2)',
                            fontSize: 36,
                        }}>
                            ✅
                        </div>
                        <h2 style={{
                            fontFamily: 'Outfit', fontSize: 28, fontWeight: 800,
                            color: 'var(--text-primary)', marginBottom: 12, letterSpacing: '-0.02em',
                        }}>
                            Response Submitted!
                        </h2>
                        <p style={{
                            color: 'var(--text-secondary)', fontSize: 15,
                            maxWidth: 380, margin: '0 auto 28px', lineHeight: 1.6,
                        }}>
                            Your response for <strong style={{ color: 'var(--text-primary)' }}>{form?.name}</strong> has been recorded successfully. Thank you!
                        </p>
                        <div style={{ display: 'flex', gap: 12, justifyContent: 'center', flexWrap: 'wrap' }}>
                            <span style={{
                                display: 'inline-flex', alignItems: 'center', gap: 6,
                                padding: '8px 20px', borderRadius: 20,
                                background: 'rgba(16,185,129,0.12)', color: '#34D399',
                                border: '1px solid rgba(16,185,129,0.28)', fontSize: 13, fontWeight: 700,
                            }}>
                                ✓ Response recorded
                            </span>
                        </div>
                    </div>
                    <p style={{ marginTop: 20, fontSize: 12, color: 'var(--text-muted)', textAlign: 'center' }}>
                        Powered by FormCraft
                    </p>
                </div>
            </>
        );
    }

    // ── Version Mismatch (409 Conflict) ────────────────────────────────────────
    if (versionMismatch) {
        return (
            <>
                <Head><title>Version Updated — FormCraft</title></Head>
                <div className="form-page">
                    <div className="form-page-nav animate-down" style={{ justifyContent: 'center' }}>
                        <span style={{ fontFamily: 'Outfit', fontWeight: 800, fontSize: 16, background: 'var(--accent-grad)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>⚡ FormCraft</span>
                    </div>
                    <div className="form-renderer-card" style={{ padding: '60px 32px', textAlign: 'center' }}>
                        <div style={{ fontSize: 60, marginBottom: 20 }}></div>
                        <h2 style={{ fontFamily: 'Outfit', fontSize: 26, marginBottom: 12, color: 'var(--text-primary)', fontWeight: 800 }}>
                            Form Updated
                        </h2>
                        <p style={{ color: 'var(--text-secondary)', fontSize: 15, maxWidth: 420, margin: '0 auto 24px' }}>
                            A new version of this form has been published. To ensure data integrity, please refresh the page to load the latest fields.
                        </p>
                        <button 
                            onClick={() => router.reload()}
                            style={{
                                background: 'var(--accent-primary)', color: 'white',
                                border: 'none', padding: '12px 28px', borderRadius: 8,
                                fontWeight: 700, cursor: 'pointer', fontSize: 15,
                                boxShadow: '0 4px 12px rgba(var(--accent-primary-rgb), 0.3)'
                            }}
                        >
                            Refresh Page
                        </button>
                    </div>
                    <p style={{ marginTop: 20, fontSize: 12, color: 'var(--text-muted)', textAlign: 'center' }}>Powered by FormCraft</p>
                </div>
            </>
        );
    }

    // ── Already submitted ──────────────────────────────────────────────────────

    if (alreadySubmitted) {
        return (
            <>
                <Head><title>Already Submitted — FormCraft</title></Head>
                <div className="form-page">
                    <div className="form-page-nav animate-down" style={{ justifyContent: 'center' }}>
                        <span style={{ fontFamily: 'Outfit', fontWeight: 800, fontSize: 16, background: 'var(--accent-grad)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>⚡ FormCraft</span>
                    </div>
                    <div className="form-renderer-card" style={{ padding: '60px 32px', textAlign: 'center' }}>
                        <div style={{ fontSize: 60, marginBottom: 20 }}>✅</div>
                        <h2 style={{ fontFamily: 'Outfit', fontSize: 26, marginBottom: 12, color: 'var(--text-primary)', fontWeight: 800 }}>
                            Already Submitted
                        </h2>
                        <p style={{ color: 'var(--text-secondary)', fontSize: 15, maxWidth: 380, margin: '0 auto 24px' }}>
                            You have already submitted a response for this form. Only one submission per person is allowed.
                        </p>
                        <span style={{
                            display: 'inline-block',
                            padding: '7px 20px', borderRadius: 20,
                            background: 'rgba(16,185,129,0.12)',
                            color: '#34D399',
                            border: '1px solid rgba(16,185,129,0.28)',
                            fontSize: 13, fontWeight: 700,
                        }}>
                             One response per person
                        </span>
                    </div>
                    <p style={{ marginTop: 20, fontSize: 12, color: 'var(--text-muted)', textAlign: 'center' }}>Powered by FormCraft</p>
                </div>
            </>
        );
    }

    // ── Expired ────────────────────────────────────────────────────────────────

    if (isExpired) {
        return (
            <>
                <Head><title>Form Expired — FormCraft</title></Head>
                <div className="form-page">
                    <div className="form-page-nav animate-down" style={{ justifyContent: 'center' }}>
                        <span style={{ fontFamily: 'Outfit', fontWeight: 800, fontSize: 16, background: 'var(--accent-grad)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>⚡ FormCraft</span>
                    </div>
                    <div className="form-renderer-card" style={{ padding: '60px 32px', textAlign: 'center' }}>
                        <div style={{ fontSize: 60, marginBottom: 20 }}>⏰</div>
                        <h2 style={{ fontFamily: 'Outfit', fontSize: 26, marginBottom: 12, color: 'var(--text-primary)', fontWeight: 800 }}>
                            Form Expired
                        </h2>
                        <p style={{ color: 'var(--text-secondary)', fontSize: 15, maxWidth: 400, margin: '0 auto 24px' }}>
                            This form is no longer accepting responses. The submission deadline has passed.
                        </p>
                        <span style={{
                            display: 'inline-block', padding: '7px 20px', borderRadius: 20,
                            background: 'rgba(239,68,68,0.12)', color: '#F87171',
                            border: '1px solid rgba(239,68,68,0.28)', fontSize: 13, fontWeight: 700,
                        }}>
                             Submission closed
                        </span>
                    </div>
                    <p style={{ marginTop: 20, fontSize: 12, color: 'var(--text-muted)', textAlign: 'center' }}>Powered by FormCraft</p>
                </div>
            </>
        );
    }

    // ── DRAFT — form not accepting submissions ─────────────────────────────────

    if (isDraft) {
        return (
            <>
                <Head><title>Form Not Available — FormCraft</title></Head>
                <div className="form-page">
                    <div className="form-renderer-card" style={{ padding: '60px 32px', textAlign: 'center' }}>
                        <div style={{ fontSize: 56, marginBottom: 20 }}></div>
                        <h2 style={{ fontFamily: 'Outfit', fontSize: 24, marginBottom: 12, color: 'var(--text-primary)' }}>
                            Form Not Available
                        </h2>
                        <p style={{ color: 'var(--text-secondary)', fontSize: 15, maxWidth: 380, margin: '0 auto' }}>
                            This form is not currently accepting responses. It may still be a draft or temporarily closed.
                        </p>
                        <div style={{ marginTop: 8 }}>
                            <span style={{
                                display: 'inline-block', marginTop: 20,
                                padding: '6px 18px', borderRadius: 20,
                                background: 'rgba(245,158,11,0.15)',
                                color: '#FCD34D',
                                border: '1px solid rgba(245,158,11,0.3)',
                                fontSize: 13, fontWeight: 600,
                            }}>
                                 DRAFT
                            </span>
                        </div>
                    </div>
                    <p style={{ marginTop: 20, fontSize: 12, color: 'var(--text-muted)', textAlign: 'center' }}>
                        Powered by FormCraft
                    </p>
                </div>
            </>
        );
    }

    // ── Not found ──────────────────────────────────────────────────────────────

    if (notFound || !form) {
        return (
            <>
                <Head><title>Form Not Found — FormCraft</title></Head>
                <div className="form-page">
                    <div className="form-renderer-card" style={{ padding: '60px 32px', textAlign: 'center' }}>
                        <div style={{ fontSize: 48, marginBottom: 16 }}></div>
                        <h2 style={{ fontFamily: 'Outfit', fontSize: 22, marginBottom: 8 }}>Form Not Found</h2>
                        <p style={{ color: 'var(--text-secondary)', fontSize: 14 }}>
                            This form link may be invalid or the form has been deleted.
                        </p>
                    </div>
                </div>
            </>
        );
    }

    // ── Render ─────────────────────────────────────────────────────────────────

    return (
        <>
            <Head>
                <title>{form.name} — FormCraft</title>
                <meta name="description" content={form.description || `Fill out ${form.name}`} />
            </Head>

            <div className="form-page">
                {/* Minimal branding header for public page */}
                <div className="form-page-nav animate-down" style={{ justifyContent: 'center' }}>
                    <span style={{
                        fontFamily: 'Outfit', fontWeight: 800, fontSize: 16,
                        background: 'var(--accent-grad)',
                        WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent',
                    }}>
                        ⚡ FormCraft
                    </span>
                </div>

                {/* F2: Draft discarded warning banner */}
                {draftDiscarded && (
                    <div style={{
                        maxWidth: 700, margin: '0 auto 14px',
                        padding: '12px 20px', borderRadius: 12,
                        background: 'rgba(245,158,11,0.12)', border: '1px solid rgba(245,158,11,0.3)',
                        color: '#FBBF24', fontSize: 13, fontWeight: 500, display: 'flex', gap: 10, alignItems: 'center',
                        animation: 'fadeIn 0.3s ease-out'
                    }}>
                        <span style={{ fontSize: 18 }}>⚠️</span>
                        <div style={{ flex: 1 }}>
                            <strong>Your saved progress was lost</strong> because this form was updated.
                            You are starting fresh with the latest version.
                        </div>
                        <button 
                            onClick={() => setDraftDiscarded(false)}
                            style={{ background: 'none', border: 'none', color: '#FBBF24', cursor: 'pointer', fontWeight: 800 }}
                        >
                            ✕
                        </button>
                    </div>
                )}

                {/* Single-submission notice */}
                {!form.allowMultipleSubmissions && (
                    <div style={{
                        maxWidth: 700, margin: '0 auto 14px',
                        padding: '10px 18px', borderRadius: 10,
                        background: 'rgba(245,158,11,0.10)',
                        border: '1px solid rgba(245,158,11,0.25)',
                        color: '#FCD34D', fontSize: 13, fontWeight: 500,
                        display: 'flex', alignItems: 'center', gap: 8,
                    }}>
                         This form allows <strong style={{ marginLeft: 4 }}>one submission per person</strong>.
                    </div>
                )}

                <FormRenderer
                    form={form}
                    initialData={initialValues}
                    isPreview={false}
                    onSubmit={handleSubmit}
                />

                <p style={{ marginTop: 20, fontSize: 12, color: 'var(--text-muted)', textAlign: 'center' }}>
                    Powered by FormCraft • Your response is securely recorded
                </p>
            </div>
        </>
    );
}

import { useState, useEffect } from 'react';
import { useRouter } from 'next/router';
import Head from 'next/head';
import Link from 'next/link';
import Navbar from '../../components/Navbar';
import UserProfileChip from '../../components/UserProfileChip';
import { getForms, deleteForm, publishForm, isSchemaDriftError, saveSchemaDriftReport } from '../../services/api';
import { toastSuccess, toastError } from '../../services/toast';
import { useAuth } from '../../context/AuthContext';

export default function FormVaultPage() {
    const router = useRouter();
    const { can, user, hasRole, loading: authLoading } = useAuth();

    const [forms, setForms] = useState([]);
    const [loading, setLoading] = useState(true);
    const [deleteTarget, setDeleteTarget] = useState(null);
    const [deleting, setDeleting] = useState(false);
    const [deleteErrorMessage, setDeleteErrorMessage] = useState('');
    const [statusLoading, setStatusLoading] = useState({});

    const [activeTab, setActiveTab] = useState('all');
    const [tabSearch, setTabSearch] = useState('');
    const [tabSelected, setTabSelected] = useState(new Set());
    const [tabPage, setTabPage] = useState(1);
    const [bulkDeleting, setBulkDeleting] = useState(false);
    const pageSize = 9;

    useEffect(() => {
        if (authLoading) return;
        if (!user) {
            router.replace('/login');
            return;
        }

        getForms()
            .then((formsData) => setForms(Array.isArray(formsData) ? formsData : []))
            .catch(() => toastError('Failed to load forms.'))
            .finally(() => setLoading(false));
    }, [authLoading, user, router]);

    useEffect(() => {
        setTabPage(1);
    }, [tabSearch, activeTab]);

    const visibleForms = forms.filter((f) => f.status !== 'ARCHIVED');
    const allPublished = visibleForms.filter((f) => f.status === 'PUBLISHED');
    const allDraft = visibleForms.filter((f) => f.status !== 'PUBLISHED');

    const getTabForms = () => {
        switch (activeTab) {
            case 'published':
                return allPublished;
            case 'draft':
                return allDraft;
            case 'all':
            default:
                return visibleForms;
        }
    };

    const match = (f, q) =>
        f.name?.toLowerCase().includes(q.toLowerCase()) ||
        (f.description || '').toLowerCase().includes(q.toLowerCase());

    const tabForms = getTabForms().filter((f) => match(f, tabSearch));

    const toggle = (setFn, id) =>
        setFn((prev) => {
            const n = new Set(prev);
            n.has(id) ? n.delete(id) : n.add(id);
            return n;
        });

    const selectAll = () => setTabSelected(new Set(tabForms.map((f) => f.id)));
    const clearSelection = () => setTabSelected(new Set());

    const handleDelete = async () => {
        if (!deleteTarget) return;
        setDeleting(true);
        try {
            await deleteForm(deleteTarget.id);
            setForms((prev) => prev.map((f) => (f.id === deleteTarget.id ? { ...f, status: 'ARCHIVED' } : f)));
            setTabSelected((p) => {
                const n = new Set(p);
                n.delete(deleteTarget.id);
                return n;
            });
            toastSuccess(`"${deleteTarget.name}" archived successfully.`);
            setDeleteErrorMessage('');
        } catch (error) {
            const liveSubmissionBlock = error?.status === 409 && (
                error?.errorCode === 'CONFLICT' ||
                String(error?.message || '').toLowerCase().includes('live submissions')
            );

            if (liveSubmissionBlock) {
                setDeleteErrorMessage('This form has live submissions, so you cannot archive it.');
            } else {
                setDeleteErrorMessage('');
                toastError('Failed to archive form.');
            }
        } finally {
            setDeleting(false);
        }
    };

    const handleBulkDelete = async () => {
        setBulkDeleting(true);
        let archived = 0;
        for (const id of [...tabSelected]) {
            try {
                await deleteForm(id);
                archived++;
            } catch {
                // Continue with best effort
            }
        }
        setForms((prev) => prev.map((f) => (tabSelected.has(f.id) ? { ...f, status: 'ARCHIVED' } : f)));
        clearSelection();
        setBulkDeleting(false);
        toastSuccess(`${archived} form${archived !== 1 ? 's' : ''} archived.`);
    };

    const redirectToDriftPage = (error, formId, formName) => {
        saveSchemaDriftReport({
            source: 'vault',
            formId,
            formName: formName || null,
            action: 'publishForm',
            at: new Date().toISOString(),
            message: error?.message || 'Schema drift detected',
            errorCode: error?.errorCode,
            errors: Array.isArray(error?.errors) ? error.errors : [],
            details: error?.details || null,
        });
        toastError('Schema drift detected. Only this affected form is blocked from publish/submit.');
        router.push('/schema-drift');
    };

    const handlePublish = async (formId, formName) => {
        setStatusLoading((p) => ({ ...p, [formId]: true }));
        try {
            await publishForm(formId);
            setForms((prev) => prev.map((f) => (f.id === formId ? { ...f, status: 'PUBLISHED' } : f)));
            toastSuccess(`"${formName}" is now PUBLISHED!`);
        } catch (error) {
            if (isSchemaDriftError(error)) {
                redirectToDriftPage(error, formId, formName);
                return;
            }
            toastError('Failed to publish form.');
        } finally {
            setStatusLoading((p) => ({ ...p, [formId]: false }));
        }
    };

    const formatDate = (dt) =>
        dt ? new Date(dt).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }) : '-';

    const renderCard = (form) => {
        const isPublished = form.status === 'PUBLISHED';
        const isPending = form.status === 'PENDING_APPROVAL';
        const isRejected = form.status === 'REJECTED';
        const isAssigned = form.status === 'ASSIGNED';
        const busy = !!statusLoading[form.id];
        const isSelected = tabSelected.has(form.id);
        const isOwner = form.isOwner;

        return (
            <div key={form.id} className={`form-card animate-in${isPublished ? ' form-card-published' : ''}${isSelected ? ' form-card-selected' : ''}`}>
                <div className="form-card-header">
                    <div className="form-card-icon">{isPublished ? '' : ''}</div>
                    <div className="form-card-menu">
                        {form.canEdit && !hasRole('Viewer') && (
                            <Link href={`/builder/${form.id}`} className="btn btn-secondary btn-sm" title="Edit">✎</Link>
                        )}
                        <Link href={`/preview/${form.id}`} className="btn btn-secondary btn-sm" title="Preview"></Link>
                        {form.canDelete && (
                            <button className="btn btn-danger btn-sm" onClick={() => setDeleteTarget(form)}>✕</button>
                        )}
                    </div>
                </div>

                <div style={{ marginBottom: 8, display: 'flex', alignItems: 'center', flexWrap: 'wrap', gap: 4 }}>
                    <span className={`status-badge status-badge-${isPublished ? 'published' : 'draft'}`} style={
                        isPending ? { background: 'rgba(245,158,11,0.18)', color: '#FCD34D', borderColor: 'rgba(245,158,11,0.35)' } :
                            isRejected ? { background: 'rgba(239,68,68,0.18)', color: '#FCA5A5', borderColor: 'rgba(239,68,68,0.35)' } :
                                undefined
                    }>
                        {isPublished ? ' Published' : isPending ? '⏳ Pending Approval' : isRejected ? '⛔ Rejected' : isAssigned ? ' Assigned' : ' Draft'}
                    </span>
                    {!isOwner && (
                        <span style={{ fontSize: 10, color: 'var(--text-muted)', marginLeft: 4 }}>
                            by {form.createdBy}
                        </span>
                    )}
                </div>

                <div className="form-card-name">{form.name}</div>
                <div className="form-card-desc">{form.description || 'No description'}</div>

                <div className="form-card-footer">
                    <div className="form-card-meta">
                        <span> {form.fields?.length || 0} fields</span>
                        <span> {formatDate(form.createdAt)}</span>
                    </div>
                    <div className="form-card-actions">
                        {isPublished ? (
                            <>
                                {form.canViewSubmissions && (
                                    <Link href={`/submissions/${form.id}`} className="btn btn-primary btn-sm"> Submissions</Link>
                                )}
                                <Link href={`/submit/${form.id}`} className="btn btn-secondary btn-sm">↗ Share</Link>
                            </>
                        ) : (
                            <>
                                {form.canPublish && (
                                    <button className="btn btn-publish btn-sm" onClick={() => handlePublish(form.id, form.name)} disabled={busy || bulkDeleting}>
                                        {busy ? <span className="spinner" style={{ width: 14, height: 14, borderWidth: 2 }} /> : ' Publish'}
                                    </button>
                                )}
                                {form.canAssignBuilder && !isPending && (
                                    <Link href={`/workflows/create/${form.id}`} className="btn btn-secondary btn-sm"> Assign Builder</Link>
                                )}
                                {(form.canStartWorkflow ?? form.canRequestWorkflow) && !isPending && (
                                    <Link href={`/workflows/create/${form.id}`} className="btn btn-secondary btn-sm"> Start Workflow</Link>
                                )}
                                {isPending && (
                                    <Link href="/workflows/status" className="btn btn-secondary btn-sm"> Track Status</Link>
                                )}
                            </>
                        )}
                    </div>
                </div>

                {form.canDelete && (
                    <label className={`card-select-checkbox${isSelected ? ' card-select-checked' : ''}`} onClick={(e) => e.stopPropagation()} title={isSelected ? 'Deselect' : 'Select'}>
                        <input type="checkbox" checked={isSelected} onChange={() => toggle(setTabSelected, form.id)} />
                        <span className="card-select-mark">{isSelected ? '✓' : ''}</span>
                    </label>
                )}
            </div>
        );
    };

    const allSel = tabForms.length > 0 && tabSelected.size === tabForms.length;

    return (
        <>
            <Head><title>Form Vault - FormCraft</title></Head>

            <div className="page">
                <Navbar />
                <UserProfileChip />
                <div className="container">
                    <div className="page-header">
                        <div>
                            <h1 className="page-title">Form Vault</h1>
                            <p className="page-subtitle">Manage all active forms (live and draft).</p>
                        </div>
                        <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
                            <Link href="/dashboard" className="btn btn-secondary">← Dashboard</Link>
                            {(can('WRITE') || hasRole('Viewer')) && (
                                <Link href="/builder/new" className="btn btn-primary" id="new-form-btn">+ New Form</Link>
                            )}
                            <Link href="/forms/trash" className="btn btn-secondary" title="View archived forms"> Archived</Link>
                        </div>
                    </div>

                    {loading ? (
                        <div className="loading-center"><span className="spinner" style={{ width: 36, height: 36 }} /></div>
                    ) : visibleForms.length === 0 ? (
                        <div className="empty-state">
                            <div className="empty-state-icon"></div>
                            <h3>No forms yet</h3>
                            <p>Create your first form to get started</p>
                            <br />
                            <Link href="/builder/new" className="btn btn-primary">+ Create Form</Link>
                        </div>
                    ) : (
                        <>
                            <div className="dashboard-tabs">
                                <button className={`tab-btn ${activeTab === 'all' ? 'tab-active' : ''}`} onClick={() => { setActiveTab('all'); setTabSearch(''); setTabSelected(new Set()); }}>
                                    All <span className="tab-count">{visibleForms.length}</span>
                                </button>
                                <button className={`tab-btn ${activeTab === 'published' ? 'tab-active' : ''}`} onClick={() => { setActiveTab('published'); setTabSearch(''); setTabSelected(new Set()); }}>
                                     Live <span className="tab-count">{allPublished.length}</span>
                                </button>
                                <button className={`tab-btn ${activeTab === 'draft' ? 'tab-active' : ''}`} onClick={() => { setActiveTab('draft'); setTabSearch(''); setTabSelected(new Set()); }}>
                                     Draft <span className="tab-count">{allDraft.length}</span>
                                </button>
                            </div>

                            <section className={`section-bar ${activeTab === 'published' ? 'section-bar-published' : 'section-bar-draft'}`}>
                                <div className="section-bar-top">
                                    <div className="section-bar-title">
                                        <h2 className="dashboard-section-title">{activeTab === 'published' ? 'Published Forms' : activeTab === 'draft' ? 'Draft Forms' : 'All Forms'}</h2>
                                        <span className="dashboard-section-count">{tabForms.length}</span>
                                    </div>
                                    {tabSelected.size > 0 && (
                                        <div className="section-sel-row">
                                            <span className="bulk-count">{tabSelected.size} selected</span>
                                            <button className="sb-btn sb-btn-ghost" onClick={clearSelection}>✕ Clear</button>
                                            {can('DELETE') && (
                                                <button className="sb-btn sb-btn-danger" onClick={handleBulkDelete} disabled={bulkDeleting}> Archive {tabSelected.size}</button>
                                            )}
                                        </div>
                                    )}
                                </div>

                                <div className="section-bar-bottom">
                                    <div className="section-search-wrapper">
                                        <span className="section-search-icon"></span>
                                        <input className="section-search-input" type="text" placeholder="Search forms..." value={tabSearch} onChange={(e) => setTabSearch(e.target.value)} />
                                        {tabSearch && <button className="section-search-clear" onClick={() => setTabSearch('')}>✕</button>}
                                    </div>
                                    <button className={`sb-btn ${allSel ? 'sb-btn-active' : 'sb-btn-ghost'}`} onClick={allSel ? clearSelection : selectAll} disabled={tabForms.length === 0}>
                                        {allSel ? '☑ Deselect All' : '☐ Select All'}
                                    </button>
                                </div>
                            </section>

                            {tabForms.length === 0 ? (
                                <div className="section-empty">
                                    <span></span> No forms available
                                </div>
                            ) : (
                                <div className="dashboard-grid">
                                    {tabForms
                                        .slice((tabPage - 1) * pageSize, tabPage * pageSize)
                                        .map((f) => renderCard(f))}
                                </div>
                            )}

                            {tabForms.length > pageSize && (
                                <div className="datatable-pagination" style={{ marginTop: '24px' }}>
                                    <button className="btn btn-secondary btn-sm" disabled={tabPage === 1} onClick={() => setTabPage((p) => p - 1)}>‹ Prev</button>
                                    <div className="pagination-pages">
                                        {Array.from({ length: Math.ceil(tabForms.length / pageSize) }, (_, i) => i + 1).map((p) => (
                                            <button key={p} className={`btn btn-sm ${tabPage === p ? 'btn-primary' : 'btn-secondary'}`} onClick={() => setTabPage(p)}>{p}</button>
                                        ))}
                                    </div>
                                    <button className="btn btn-secondary btn-sm" disabled={tabPage === Math.ceil(tabForms.length / pageSize)} onClick={() => setTabPage((p) => p + 1)}>Next ›</button>
                                </div>
                            )}
                        </>
                    )}
                </div>
            </div>

            {deleteTarget && (
                <div className="confirm-dialog">
                    <div className="confirm-box">
                        <div className="confirm-icon"></div>
                        <h3>Archive Form</h3>
                        <p>
                            Archive <strong>&quot;{deleteTarget.name}&quot;</strong>?<br />
                            Archived forms are hidden from active workflows and submissions.
                        </p>
                        {deleteErrorMessage && (
                            <p style={{ color: '#FCA5A5', textAlign: 'center', marginTop: 12, marginBottom: 0, fontWeight: 600 }}>
                                {deleteErrorMessage}
                            </p>
                        )}
                         <div className="confirm-actions">
                            <button className="btn btn-secondary" onClick={() => { setDeleteTarget(null); setDeleteErrorMessage(''); }}>Go Back</button>
                         </div>
                    </div>
                </div>
            )}
        </>
    );
}

import { useState, useEffect } from 'react';
import { useRouter } from 'next/router';
import Head from 'next/head';
import Link from 'next/link';
import Navbar from '../../components/Navbar';
import UserProfileChip from '../../components/UserProfileChip';
import { getForms, deleteForm, publishForm, isSchemaDriftError, saveSchemaDriftReport } from '../../services/api';
import { toastSuccess, toastError } from '../../services/toast';
import { useAuth } from '../../context/AuthContext';

export default function FormVaultPage() {
    const router = useRouter();
    const { can, user, hasRole, loading: authLoading } = useAuth();

    const [forms, setForms] = useState([]);
    const [loading, setLoading] = useState(true);
    const [deleteTarget, setDeleteTarget] = useState(null);
    const [deleting, setDeleting] = useState(false);
    const [deleteErrorMessage, setDeleteErrorMessage] = useState('');
    const [statusLoading, setStatusLoading] = useState({});

    const [activeTab, setActiveTab] = useState('all');
    const [tabSearch, setTabSearch] = useState('');
    const [tabSelected, setTabSelected] = useState(new Set());
    const [tabPage, setTabPage] = useState(1);
    const [bulkDeleting, setBulkDeleting] = useState(false);
    const pageSize = 9;

    useEffect(() => {
        if (authLoading) return;
        if (!user) {
            router.replace('/login');
            return;
        }

        getForms()
            .then((formsData) => setForms(Array.isArray(formsData) ? formsData : []))
            .catch(() => toastError('Failed to load forms.'))
            .finally(() => setLoading(false));
    }, [authLoading, user, router]);

    useEffect(() => {
        setTabPage(1);
    }, [tabSearch, activeTab]);

    const visibleForms = forms.filter((f) => f.status !== 'ARCHIVED');
    const allPublished = visibleForms.filter((f) => f.status === 'PUBLISHED');
    const allDraft = visibleForms.filter((f) => f.status !== 'PUBLISHED');

    const getTabForms = () => {
        switch (activeTab) {
            case 'published':
                return allPublished;
            case 'draft':
                return allDraft;
            case 'all':
            default:
                return visibleForms;
        }
    };

    const match = (f, q) =>
        f.name?.toLowerCase().includes(q.toLowerCase()) ||
        (f.description || '').toLowerCase().includes(q.toLowerCase());

    const tabForms = getTabForms().filter((f) => match(f, tabSearch));

    const toggle = (setFn, id) =>
        setFn((prev) => {
            const n = new Set(prev);
            n.has(id) ? n.delete(id) : n.add(id);
            return n;
        });

    const selectAll = () => setTabSelected(new Set(tabForms.map((f) => f.id)));
    const clearSelection = () => setTabSelected(new Set());

    const handleDelete = async () => {
        if (!deleteTarget) return;
        setDeleting(true);
        try {
            await deleteForm(deleteTarget.id);
            setForms((prev) => prev.map((f) => (f.id === deleteTarget.id ? { ...f, status: 'ARCHIVED' } : f)));
            setTabSelected((p) => {
                const n = new Set(p);
                n.delete(deleteTarget.id);
                return n;
            });
            toastSuccess(`"${deleteTarget.name}" archived successfully.`);
            setDeleteErrorMessage('');
        } catch (error) {
            const liveSubmissionBlock = error?.status === 409 && (
                error?.errorCode === 'CONFLICT' ||
                String(error?.message || '').toLowerCase().includes('live submissions')
            );

            if (liveSubmissionBlock) {
                setDeleteErrorMessage('This form has live submissions, so you cannot archive it.');
            } else {
                setDeleteErrorMessage('');
                toastError('Failed to archive form.');
            }
        } finally {
            setDeleting(false);
        }
    };

    const handleBulkDelete = async () => {
        setBulkDeleting(true);
        let archived = 0;
        for (const id of [...tabSelected]) {
            try {
                await deleteForm(id);
                archived++;
            } catch {
                // Continue with best effort
            }
        }
        setForms((prev) => prev.map((f) => (tabSelected.has(f.id) ? { ...f, status: 'ARCHIVED' } : f)));
        clearSelection();
        setBulkDeleting(false);
        toastSuccess(`${archived} form${archived !== 1 ? 's' : ''} archived.`);
    };

    const redirectToDriftPage = (error, formId, formName) => {
        saveSchemaDriftReport({
            source: 'vault',
            formId,
            formName: formName || null,
            action: 'publishForm',
            at: new Date().toISOString(),
            message: error?.message || 'Schema drift detected',
            errorCode: error?.errorCode,
            errors: Array.isArray(error?.errors) ? error.errors : [],
            details: error?.details || null,
        });
        toastError('Schema drift detected. Only this affected form is blocked from publish/submit.');
        router.push('/schema-drift');
    };

    const handlePublish = async (formId, formName) => {
        setStatusLoading((p) => ({ ...p, [formId]: true }));
        try {
            await publishForm(formId);
            setForms((prev) => prev.map((f) => (f.id === formId ? { ...f, status: 'PUBLISHED' } : f)));
            toastSuccess(`"${formName}" is now PUBLISHED!`);
        } catch (error) {
            if (isSchemaDriftError(error)) {
                redirectToDriftPage(error, formId, formName);
                return;
            }
            toastError('Failed to publish form.');
        } finally {
            setStatusLoading((p) => ({ ...p, [formId]: false }));
        }
    };

    const formatDate = (dt) =>
        dt ? new Date(dt).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }) : '-';

    const renderCard = (form) => {
        const isPublished = form.status === 'PUBLISHED';
        const isPending = form.status === 'PENDING_APPROVAL';
        const isRejected = form.status === 'REJECTED';
        const isAssigned = form.status === 'ASSIGNED';
        const busy = !!statusLoading[form.id];
        const isSelected = tabSelected.has(form.id);
        const isOwner = form.isOwner;

        return (
            <div key={form.id} className={`form-card animate-in${isPublished ? ' form-card-published' : ''}${isSelected ? ' form-card-selected' : ''}`}>
                <div className="form-card-header">
                    <div className="form-card-icon">{isPublished ? '' : ''}</div>
                    <div className="form-card-menu">
                        {form.canEdit && !hasRole('Viewer') && (
                            <Link href={`/builder/${form.id}`} className="btn btn-secondary btn-sm" title="Edit">✎</Link>
                        )}
                        <Link href={`/preview/${form.id}`} className="btn btn-secondary btn-sm" title="Preview"></Link>
                        {form.canDelete && (
                            <button className="btn btn-danger btn-sm" onClick={() => setDeleteTarget(form)}>✕</button>
                        )}
                    </div>
                </div>

                <div style={{ marginBottom: 8, display: 'flex', alignItems: 'center', flexWrap: 'wrap', gap: 4 }}>
                    <span className={`status-badge status-badge-${isPublished ? 'published' : 'draft'}`} style={
                        isPending ? { background: 'rgba(245,158,11,0.18)', color: '#FCD34D', borderColor: 'rgba(245,158,11,0.35)' } :
                            isRejected ? { background: 'rgba(239,68,68,0.18)', color: '#FCA5A5', borderColor: 'rgba(239,68,68,0.35)' } :
                                undefined
                    }>
                        {isPublished ? ' Published' : isPending ? '⏳ Pending Approval' : isRejected ? '⛔ Rejected' : isAssigned ? ' Assigned' : ' Draft'}
                    </span>
                    {!isOwner && (
                        <span style={{ fontSize: 10, color: 'var(--text-muted)', marginLeft: 4 }}>
                            by {form.createdBy}
                        </span>
                    )}
                </div>

                <div className="form-card-name">{form.name}</div>
                <div className="form-card-desc">{form.description || 'No description'}</div>

                <div className="form-card-footer">
                    <div className="form-card-meta">
                        <span> {form.fields?.length || 0} fields</span>
                        <span> {formatDate(form.createdAt)}</span>
                    </div>
                    <div className="form-card-actions">
                        {isPublished ? (
                            <>
                                {form.canViewSubmissions && (
                                    <Link href={`/submissions/${form.id}`} className="btn btn-primary btn-sm"> Submissions</Link>
                                )}
                                <Link href={`/submit/${form.id}`} className="btn btn-secondary btn-sm">↗ Share</Link>
                            </>
                        ) : (
                            <>
                                {form.canPublish && (
                                    <button className="btn btn-publish btn-sm" onClick={() => handlePublish(form.id, form.name)} disabled={busy || bulkDeleting}>
                                        {busy ? <span className="spinner" style={{ width: 14, height: 14, borderWidth: 2 }} /> : ' Publish'}
                                    </button>
                                )}
                                {form.canAssignBuilder && !isPending && (
                                    <Link href={`/workflows/create/${form.id}`} className="btn btn-secondary btn-sm"> Assign Builder</Link>
                                )}
                                {(form.canStartWorkflow ?? form.canRequestWorkflow) && !isPending && (
                                    <Link href={`/workflows/create/${form.id}`} className="btn btn-secondary btn-sm"> Start Workflow</Link>
                                )}
                                {isPending && (
                                    <Link href="/workflows/status" className="btn btn-secondary btn-sm"> Track Status</Link>
                                )}
                            </>
                        )}
                    </div>
                </div>

                {form.canDelete && (
                    <label className={`card-select-checkbox${isSelected ? ' card-select-checked' : ''}`} onClick={(e) => e.stopPropagation()} title={isSelected ? 'Deselect' : 'Select'}>
                        <input type="checkbox" checked={isSelected} onChange={() => toggle(setTabSelected, form.id)} />
                        <span className="card-select-mark">{isSelected ? '✓' : ''}</span>
                    </label>
                )}
            </div>
        );
    };

    const allSel = tabForms.length > 0 && tabSelected.size === tabForms.length;

    return (
        <>
            <Head><title>Form Vault - FormCraft</title></Head>

            <div className="page">
                <Navbar />
                <UserProfileChip />
                <div className="container">
                    <div className="page-header">
                        <div>
                            <h1 className="page-title">Form Vault</h1>
                            <p className="page-subtitle">Manage all active forms (live and draft).</p>
                        </div>
                        <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
                            <Link href="/dashboard" className="btn btn-secondary">← Dashboard</Link>
                            {(can('WRITE') || hasRole('Viewer')) && (
                                <Link href="/builder/new" className="btn btn-primary" id="new-form-btn">+ New Form</Link>
                            )}
                            <Link href="/forms/trash" className="btn btn-secondary" title="View archived forms"> Archived</Link>
                        </div>
                    </div>

                    {loading ? (
                        <div className="loading-center"><span className="spinner" style={{ width: 36, height: 36 }} /></div>
                    ) : visibleForms.length === 0 ? (
                        <div className="empty-state">
                            <div className="empty-state-icon"></div>
                            <h3>No forms yet</h3>
                            <p>Create your first form to get started</p>
                            <br />
                            <Link href="/builder/new" className="btn btn-primary">+ Create Form</Link>
                        </div>
                    ) : (
                        <>
                            <div className="dashboard-tabs">
                                <button className={`tab-btn ${activeTab === 'all' ? 'tab-active' : ''}`} onClick={() => { setActiveTab('all'); setTabSearch(''); setTabSelected(new Set()); }}>
                                    All <span className="tab-count">{visibleForms.length}</span>
                                </button>
                                <button className={`tab-btn ${activeTab === 'published' ? 'tab-active' : ''}`} onClick={() => { setActiveTab('published'); setTabSearch(''); setTabSelected(new Set()); }}>
                                     Live <span className="tab-count">{allPublished.length}</span>
                                </button>
                                <button className={`tab-btn ${activeTab === 'draft' ? 'tab-active' : ''}`} onClick={() => { setActiveTab('draft'); setTabSearch(''); setTabSelected(new Set()); }}>
                                     Draft <span className="tab-count">{allDraft.length}</span>
                                </button>
                            </div>

                            <section className={`section-bar ${activeTab === 'published' ? 'section-bar-published' : 'section-bar-draft'}`}>
                                <div className="section-bar-top">
                                    <div className="section-bar-title">
                                        <h2 className="dashboard-section-title">{activeTab === 'published' ? 'Published Forms' : activeTab === 'draft' ? 'Draft Forms' : 'All Forms'}</h2>
                                        <span className="dashboard-section-count">{tabForms.length}</span>
                                    </div>
                                    {tabSelected.size > 0 && (
                                        <div className="section-sel-row">
                                            <span className="bulk-count">{tabSelected.size} selected</span>
                                            <button className="sb-btn sb-btn-ghost" onClick={clearSelection}>✕ Clear</button>
                                            {can('DELETE') && (
                                                <button className="sb-btn sb-btn-danger" onClick={handleBulkDelete} disabled={bulkDeleting}> Archive {tabSelected.size}</button>
                                            )}
                                        </div>
                                    )}
                                </div>

                                <div className="section-bar-bottom">
                                    <div className="section-search-wrapper">
                                        <span className="section-search-icon"></span>
                                        <input className="section-search-input" type="text" placeholder="Search forms..." value={tabSearch} onChange={(e) => setTabSearch(e.target.value)} />
                                        {tabSearch && <button className="section-search-clear" onClick={() => setTabSearch('')}>✕</button>}
                                    </div>
                                    <button className={`sb-btn ${allSel ? 'sb-btn-active' : 'sb-btn-ghost'}`} onClick={allSel ? clearSelection : selectAll} disabled={tabForms.length === 0}>
                                        {allSel ? '☑ Deselect All' : '☐ Select All'}
                                    </button>
                                </div>
                            </section>

                            {tabForms.length === 0 ? (
                                <div className="section-empty">
                                    <span></span> No forms available
                                </div>
                            ) : (
                                <div className="dashboard-grid">
                                    {tabForms
                                        .slice((tabPage - 1) * pageSize, tabPage * pageSize)
                                        .map((f) => renderCard(f))}
                                </div>
                            )}

                            {tabForms.length > pageSize && (
                                <div className="datatable-pagination" style={{ marginTop: '24px' }}>
                                    <button className="btn btn-secondary btn-sm" disabled={tabPage === 1} onClick={() => setTabPage((p) => p - 1)}>‹ Prev</button>
                                    <div className="pagination-pages">
                                        {Array.from({ length: Math.ceil(tabForms.length / pageSize) }, (_, i) => i + 1).map((p) => (
                                            <button key={p} className={`btn btn-sm ${tabPage === p ? 'btn-primary' : 'btn-secondary'}`} onClick={() => setTabPage(p)}>{p}</button>
                                        ))}
                                    </div>
                                    <button className="btn btn-secondary btn-sm" disabled={tabPage === Math.ceil(tabForms.length / pageSize)} onClick={() => setTabPage((p) => p + 1)}>Next ›</button>
                                </div>
                            )}
                        </>
                    )}
                </div>
            </div>

            {deleteTarget && (
                <div className="confirm-dialog">
                    <div className="confirm-box">
                        <div className="confirm-icon">{deleteErrorMessage ? '⛔' : ''}</div>
                        <h3>{deleteErrorMessage ? 'Cannot Archive Form' : 'Archive Form'}</h3>
                        {deleteErrorMessage ? (
                            <p style={{ color: '#FCA5A5', textAlign: 'center', fontSize: 16, fontWeight: 600, margin: '16px 0' }}>
                                {deleteErrorMessage}
                            </p>
                        ) : (
                            <p>
                                Archive <strong>&quot;{deleteTarget.name}&quot;</strong>?<br />
                                Archived forms are hidden from active workflows and submissions.
                            </p>
                        )}
                         <div className="confirm-actions">
                            <button className="btn btn-secondary" onClick={() => { setDeleteTarget(null); setDeleteErrorMessage(''); }}>Go Back</button>
                         </div>
                    </div>
                </div>
            )}
        </>
    );
}

import { useState, useEffect } from 'react';
import { useRouter } from 'next/router';
import Head from 'next/head';
import Link from 'next/link';
import Navbar from '../../components/Navbar';
import PaginationControls from '../../components/PaginationControls';
import { getRoles, deleteRole } from '../../services/api';
import { toastSuccess, toastError } from '../../services/toast';
import { useAuth } from '../../context/AuthContext';

export default function RolesPage() {
    const router = useRouter();
    const { user, loading: authLoading } = useAuth();
    const [roles, setRoles] = useState([]);
    const [loading, setLoading] = useState(true);
    const [deleteTarget, setDeleteTarget] = useState(null);
    const [deleting, setDeleting] = useState(false);
    const [search, setSearch] = useState('');
    const [viewMode, setViewMode] = useState('all');
    const [page, setPage] = useState(0);
    const [size, setSize] = useState(10);
    const [totalElements, setTotalElements] = useState(0);
    const [totalPages, setTotalPages] = useState(0);

    useEffect(() => {
        if (authLoading) return;
        if (!user) { router.replace('/login'); return; }
        loadRoles(0, size);
    }, [authLoading, user, router]);

    async function loadRoles(nextPage = page, nextSize = size) {
        try {
            const data = await getRoles({ page: nextPage, size: nextSize });
            const allRoles = Array.isArray(data) ? data : (Array.isArray(data?.content) ? data.content : []);
            // Filter out 'admin' role
            const visibleRoles = allRoles.filter(r => r.roleName.toLowerCase() !== 'admin');
            setRoles(visibleRoles);
            setPage(Array.isArray(data) ? nextPage : Number(data?.page ?? nextPage));
            setSize(Array.isArray(data) ? nextSize : Number(data?.size ?? nextSize));
            setTotalElements(Array.isArray(data) ? visibleRoles.length : Number(data?.totalElements ?? visibleRoles.length));
            setTotalPages(Array.isArray(data) ? (visibleRoles.length > 0 ? 1 : 0) : Number(data?.totalPages ?? 0));
        } catch (err) {
            if (err.status === 403) {
                toastError('You do not have permission to manage roles.');
                router.replace('/dashboard');
            } else {
                toastError('Failed to load roles.');
            }
        } finally {
            setLoading(false);
        }
    }

    const filtered = roles.filter(r =>
        r.roleName.toLowerCase().includes(search.toLowerCase()) ||
        (r.permissions || []).some(p => p.toLowerCase().includes(search.toLowerCase()))
    );

    const visibleRoles = filtered.filter(r =>
        viewMode === 'all' ? true : viewMode === 'system' ? r.isSystemRole : !r.isSystemRole
    );
    const systemRoles = visibleRoles.filter(r => r.isSystemRole);
    const customRoles = visibleRoles.filter(r => !r.isSystemRole);

    async function handleDelete() {
        if (!deleteTarget) return;
        setDeleting(true);
        try {
            await deleteRole(deleteTarget.id);
            setRoles(prev => prev.filter(r => r.id !== deleteTarget.id));
            toastSuccess(`Role "${deleteTarget.roleName}" deleted.`);
            if (roles.length === 1 && page > 0) {
                await loadRoles(page - 1, size);
            } else {
                await loadRoles(page, size);
            }
        } catch (err) {
            toastError(err.message || 'Failed to delete role.');
        } finally {
            setDeleting(false);
            setDeleteTarget(null);
        }
    }

    function renderTable(roleList, title) {
        if (roleList.length === 0) return null;
        return (
            <>
                <h2 style={{ fontSize: 16, fontWeight: 700, color: 'var(--text-secondary)', marginBottom: 12, marginTop: 24 }}>
                    {title} ({roleList.length})
                </h2>
                <div className="roles-table-wrap">
                    <table className="roles-table">
                        <thead>
                            <tr>
                                <th>Role</th>
                                <th>Type</th>
                                <th>Permissions</th>
                                <th style={{ width: 100 }}>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {roleList.map((role, idx) => (
                                <tr 
                                    key={role.id}
                                    className="animate-fade-in stagger-item"
                                    style={{ animationDelay: `${idx * 0.05}s` }}
                                >
                                    <td data-label="Role">
                                        <div className="role-name-cell">
                                            <div className={`role-icon ${role.isSystemRole ? 'system' : 'custom'}`}>
                                                {role.isSystemRole ? '' : '⚙️'}
                                            </div>
                                            {role.roleName}
                                        </div>
                                    </td>
                                    <td data-label="Type">
                                        <span className={`badge ${role.isSystemRole ? 'badge-system' : 'badge-custom'}`}>
                                            {role.isSystemRole ? 'System' : 'Custom'}
                                        </span>
                                    </td>
                                    <td data-label="Permissions">
                                        <div className="perm-tags">
                                            {(role.permissions || []).map(p => (
                                                <span key={p} className="perm-tag">{p}</span>
                                            ))}
                                            {(!role.permissions || role.permissions.length === 0) && (
                                                <span style={{ color: 'var(--text-muted)', fontSize: 12 }}>No permissions</span>
                                            )}
                                        </div>
                                    </td>
                                    <td data-label="Actions">
                                        <div className="role-actions">
                                            {!role.isSystemRole && (
                                                <>
                                                    <button
                                                        className="role-action-btn"
                                                        title="Edit role"
                                                        onClick={() => router.push(`/roles/edit/${role.id}`)}
                                                    >
                                                        ✏️
                                                    </button>
                                                    <button
                                                        className="role-action-btn danger"
                                                        title="Delete role"
                                                        onClick={() => setDeleteTarget(role)}
                                                    >
                                                        ️
                                                    </button>
                                                </>
                                            )}
                                            {role.isSystemRole && (
                                                <button
                                                    className="role-action-btn"
                                                    title="View role details"
                                                    onClick={() => router.push(`/roles/edit/${role.id}`)}
                                                >
                                                    ️
                                                </button>
                                            )}
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </>
        );
    }

    return (
        <>
            <Head>
                <title>Role Management — FormCraft</title>
            </Head>
            <Navbar />

            <div className="roles-page">
                <div className="roles-page-header">
                    <div>
                        <h1>️ Role Management</h1>
                        <p>Manage roles and their permission assignments</p>
                    </div>
                    <div style={{ display: 'flex', gap: 10, alignItems: 'center', flexWrap: 'wrap', justifyContent: 'flex-end' }}>
                        <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                            <button
                                type="button"
                                className={`btn btn-sm ${viewMode === 'all' ? 'btn-primary' : 'btn-secondary'}`}
                                onClick={() => setViewMode('all')}
                                aria-pressed={viewMode === 'all'}
                            >
                                All Roles
                            </button>
                            <button
                                type="button"
                                className={`btn btn-sm ${viewMode === 'system' ? 'btn-primary' : 'btn-secondary'}`}
                                onClick={() => setViewMode('system')}
                                aria-pressed={viewMode === 'system'}
                            >
                                System Roles
                            </button>
                            <button
                                type="button"
                                className={`btn btn-sm ${viewMode === 'custom' ? 'btn-primary' : 'btn-secondary'}`}
                                onClick={() => setViewMode('custom')}
                                aria-pressed={viewMode === 'custom'}
                            >
                                Custom Roles
                            </button>
                        </div>
                        <input
                            type="text"
                            className="form-input"
                            placeholder="Search roles or permissions..."
                            value={search}
                            onChange={e => setSearch(e.target.value)}
                            style={{ width: 260 }}
                        />
                        <Link href="/roles/create" className="btn btn-primary">
                            + New Role
                        </Link>
                    </div>
                </div>

                {loading ? (
                    <div className="roles-skeleton">
                        {[...Array(5)].map((_, i) => (
                            <div key={i} className="roles-skeleton-row" />
                        ))}
                    </div>
                ) : roles.length === 0 ? (
                    <div className="roles-empty">
                        <div className="roles-empty-icon">️</div>
                        <h3>No roles found</h3>
                        <p>Create your first custom role to get started.</p>
                        <Link href="/roles/create" className="btn btn-primary">
                            + Create Role
                        </Link>
                    </div>
                ) : (
                    <>
                        {viewMode === 'all' && renderTable(systemRoles, ' System Roles')}
                        {viewMode === 'all' && renderTable(customRoles, '⚙️ Custom Roles')}
                        {viewMode === 'system' && renderTable(systemRoles, ' System Roles')}
                        {viewMode === 'custom' && renderTable(customRoles, '⚙️ Custom Roles')}
                        {visibleRoles.length === 0 && (
                            <div className="roles-empty">
                                <p>
                                    {search
                                        ? `No roles match "${search}"${viewMode !== 'all' ? ` in ${viewMode} roles` : ''}`
                                        : viewMode === 'system'
                                            ? 'No system roles available.'
                                            : viewMode === 'custom'
                                                ? 'No custom roles available.'
                                                : 'No roles available.'}
                                </p>
                            </div>
                        )}
                        <PaginationControls
                            page={page}
                            size={size}
                            totalElements={totalElements}
                            totalPages={totalPages}
                            loading={loading}
                            onPageChange={(nextPage) => loadRoles(nextPage, size)}
                            onSizeChange={(nextSize) => loadRoles(0, nextSize)}
                        />
                    </>
                )}
            </div>

            {/* Delete Confirmation Modal */}
            {deleteTarget && (
                <div className="role-modal-overlay" onClick={() => !deleting && setDeleteTarget(null)}>
                    <div className="role-modal" onClick={e => e.stopPropagation()}>
                        <h3>Delete Role</h3>
                        <p>
                            Are you sure you want to delete <strong>"{deleteTarget.roleName}"</strong>?
                            This will remove the role from all assigned users. This action cannot be undone.
                        </p>
                        <div className="role-modal-actions">
                            <button
                                className="btn btn-secondary"
                                onClick={() => setDeleteTarget(null)}
                                disabled={deleting}
                            >
                                Cancel
                            </button>
                            <button
                                className="btn btn-danger"
                                onClick={handleDelete}
                                disabled={deleting}
                            >
                                {deleting ? 'Deleting...' : 'Delete Role'}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </>
    );
}

