.badge-system {
  background: rgba(139,92,246,0.15);
  color: #C4B5FD;
  border: 1px solid rgba(139,92,246,0.25);
}

.badge-custom {
  background: rgba(6,182,212,0.12);
  color: #67E8F9;
  border: 1px solid rgba(6,182,212,0.25);
}

/* ── Permission Tags ─────────────────────────────── */
.perm-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
}

.perm-tag {
  display: inline-flex;
  align-items: center;
  padding: 2px 8px;
  border-radius: 6px;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.03em;
  background: rgba(255,255,255,0.06);
  color: var(--text-secondary);
  border: 1px solid rgba(255,255,255,0.08);
}

/* ── Actions Cell ────────────────────────────────── */
.role-actions {
  display: flex;
  gap: 6px;
  opacity: 0.6;
  transition: opacity 0.2s ease;
}

.roles-table tbody tr:hover .role-actions {
  opacity: 1;
}

.role-action-btn {
  width: 32px; height: 32px;
  border-radius: 8px;
  display: flex; align-items: center; justify-content: center;
  border: 1px solid var(--border);
  background: rgba(255,255,255,0.04);
  color: var(--text-secondary);
  cursor: pointer;
  transition: var(--transition-fast);
  font-size: 14px;
}

.role-action-btn:hover {
  background: rgba(139,92,246,0.12);
  border-color: rgba(139,92,246,0.35);
  color: #C4B5FD;
  transform: scale(1.08);
}

.role-action-btn.danger:hover {
  background: rgba(239,68,68,0.15);
  border-color: rgba(239,68,68,0.35);
  color: #FCA5A5;
}

/* ── Form Card (Create / Edit) ───────────────────── */
.role-form-card {
  max-width: 720px;
  margin: 0 auto;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  padding: 36px;
  box-shadow: var(--shadow);
}

.role-form-card h2 {
  font-size: 22px;
  font-weight: 700;
  margin-bottom: 24px;
  background: var(--accent-grad);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* ── Permission Checkbox Groups ──────────────────── */
.perm-groups {
  display: flex;
  flex-direction: column;
  gap: 20px;
  margin-top: 8px;
}

.perm-group {
  background: rgba(255,255,255,0.025);
  border: 1px solid rgba(255,255,255,0.07);
  border-radius: var(--radius-sm);
  padding: 18px 20px;
  transition: var(--transition-fast);
}

.perm-group:hover {
  border-color: rgba(139,92,246,0.2);
  background: rgba(255,255,255,0.035);
}

.perm-group-title {
  font-size: 13px;
  font-weight: 700;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  margin-bottom: 12px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.perm-group-title .group-icon {
  font-size: 16px;
}

.perm-group-items {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
  gap: 8px;
}

/* ── Checkbox Item ───────────────────────────────── */
.perm-checkbox {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 12px;
  border-radius: 8px;
  cursor: pointer;
  transition: var(--transition-fast);
  user-select: none;
}

.perm-checkbox:hover {
  background: rgba(139,92,246,0.08);
}

.perm-checkbox input[type="checkbox"] {
  appearance: none;
  -webkit-appearance: none;
  width: 18px; height: 18px;
  border: 2px solid rgba(255,255,255,0.2);
  border-radius: 5px;
  background: rgba(255,255,255,0.04);
  cursor: pointer;
  transition: var(--transition-fast);
  position: relative;
  flex-shrink: 0;
}

.perm-checkbox input[type="checkbox"]:checked {
  background: var(--accent);
  border-color: var(--accent);
  box-shadow: 0 0 12px rgba(139,92,246,0.4);
}

.perm-checkbox input[type="checkbox"]:checked::after {
  content: '✓';
  position: absolute;
  top: 50%; left: 50%;
  transform: translate(-50%, -50%);
  color: #fff;
  font-size: 12px;
  font-weight: 700;
}

.perm-checkbox-label {
  font-size: 13px;
  font-weight: 500;
  color: var(--text-primary);
}

.perm-checkbox-label .perm-key {
  font-family: 'SF Mono', 'Fira Code', monospace;
  font-size: 12px;
  color: var(--text-secondary);
}

/* ── Form Actions ────────────────────────────────── */
.role-form-actions {
  display: flex;
  gap: 12px;
  margin-top: 28px;
  padding-top: 20px;
  border-top: 1px solid var(--border);
}

/* ── Delete Confirmation Modal ───────────────────── */
.role-modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.7);
  backdrop-filter: blur(6px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  animation: fadeIn 0.2s ease;
}

.role-modal {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 32px;
  max-width: 420px;
  width: 90%;
  box-shadow: var(--shadow-lg);
  animation: slideUp 0.25s ease;
}

.role-modal h3 {
  font-size: 18px;
  font-weight: 700;
  margin-bottom: 12px;
  color: var(--text-primary);
}

.role-modal p {
  color: var(--text-secondary);
  font-size: 14px;
  margin-bottom: 24px;
  line-height: 1.6;
}

.role-modal-actions {
  display: flex;
  gap: 10px;
  justify-content: flex-end;
}

/* ── Loading Skeleton ────────────────────────────── */
.roles-skeleton {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.roles-skeleton-row {
  height: 56px;
  background: rgba(255,255,255,0.04);
  border-radius: var(--radius-sm);
  animation: pulse 1.5s infinite ease-in-out;
}

@keyframes pulse {
  0%, 100% { opacity: 0.4; }
  50% { opacity: 0.8; }
}

/* ── Empty State ─────────────────────────────────── */
.roles-empty {
  text-align: center;
  padding: 60px 20px;
  color: var(--text-muted);
}

.roles-empty-icon {
  font-size: 48px;
  margin-bottom: 16px;
  opacity: 0.5;
}

.roles-empty h3 {
  font-size: 18px;
  color: var(--text-secondary);
  margin-bottom: 8px;
}

.roles-empty p {
  font-size: 14px;
  margin-bottom: 20px;
}

/* ── Responsive ──────────────────────────────────── */
@media (max-width: 768px) {
  .roles-page { padding: 20px 16px 48px; }
  .roles-page-header { flex-direction: column; align-items: flex-start; }
  .roles-table thead { display: none; }
  .roles-table tbody tr {
    display: block;
    padding: 16px;
    border-bottom: 1px solid var(--border);
  }
  .roles-table tbody td {
    display: flex;
    justify-content: space-between;
    padding: 6px 0;
    border-bottom: none;
  }
  .roles-table tbody td::before {
    content: attr(data-label);
    font-weight: 700;
    font-size: 11px;
    text-transform: uppercase;
    color: var(--text-muted);
    letter-spacing: 0.06em;
  }
  .role-form-card { padding: 24px 18px; }
  .perm-group-items { grid-template-columns: 1fr; }
}

/* ================================================
   Phase 3 - Premium Roles Refinement
   UI-only overrides (no logic changes)
   ================================================ */

.roles-page {
  max-width: 1160px;
  padding: 36px 24px 72px;
}

.roles-page-header {
  margin-bottom: 30px;
}

.roles-page-header h1 {
  font-size: clamp(30px, 4vw, 42px);
  letter-spacing: -0.03em;
}

.roles-table-wrap {
  border-radius: 16px;
  border-color: rgba(255, 255, 255, 0.1);
  box-shadow: 0 10px 34px rgba(0, 0, 0, 0.38);
}

.roles-table thead th {
  padding: 15px 20px;
  font-size: 10.5px;
  letter-spacing: 0.1em;
}

.roles-table tbody td {
  padding: 15px 20px;
}

.roles-table tbody tr {
  transition: background 0.2s ease, transform 0.2s ease;
}

.roles-table tbody tr:hover {
  background: rgba(139, 92, 246, 0.08);
  transform: translateY(-1px);
}

.role-action-btn {
  border-radius: 10px;
  transition: transform 0.2s ease, background 0.2s ease, border-color 0.2s ease, color 0.2s ease;
}

.role-form-card {
  border-radius: 16px;
  border-color: rgba(255, 255, 255, 0.1);
  box-shadow: 0 14px 42px rgba(0, 0, 0, 0.42);
}

.role-form-card h2 {
  font-size: clamp(24px, 3vw, 30px);
  letter-spacing: -0.02em;
}

.perm-group {
  border-radius: 12px;
  border-color: rgba(255, 255, 255, 0.09);
  background: rgba(255, 255, 255, 0.03);
}

.perm-group:hover {
  border-color: rgba(139, 92, 246, 0.28);
  background: rgba(139, 92, 246, 0.05);
  box-shadow: 0 8px 20px rgba(20, 15, 50, 0.25);
}

@media (max-width: 1023px) {
  .roles-page {
    padding: 30px 20px 60px;
  }

  .roles-page-header {
    grid-template-columns: 1fr;
    align-items: start;
    row-gap: 14px;
  }

  .roles-toolbar {
    justify-content: flex-start;
  }

  .roles-table thead th,
  .roles-table tbody td {
    padding-left: 14px;
    padding-right: 14px;
  }
}

@media (max-width: 767px) {
  .roles-page {
    padding: 24px 16px 52px;
  }

  .role-form-card {
    padding: 24px 18px;
    border-radius: 14px;
  }
}

/* ══════════════════════════════════════════════════
   User Management Styles — Dark Glassmorphism
   ══════════════════════════════════════════════════ */

/* ── Page Layout ─────────────────────────────────── */
.users-page {
  max-width: 1100px;
  margin: 0 auto;
  padding: 32px 24px 64px;
}

.users-page-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 28px;
  gap: 16px;
  flex-wrap: wrap;
}

.users-page-header h1 {
  font-size: 28px;
  font-weight: 800;
  letter-spacing: -0.02em;
  background: var(--accent-grad);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.users-page-header p {
  color: var(--text-secondary);
  font-size: 14px;
  margin-top: 4px;
}

/* ── Users Table ─────────────────────────────────── */
.users-table-wrap {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  overflow: hidden;
  box-shadow: var(--shadow);
}

.users-table {
  width: 100%;
  border-collapse: collapse;
}

.users-table thead th {
  text-align: left;
  padding: 14px 20px;
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--text-muted);
  border-bottom: 1px solid var(--border);
  background: rgba(255,255,255,0.02);
}

.users-table tbody tr {
  transition: var(--transition-fast);
}

.users-table tbody tr:hover {
  background: rgba(139,92,246,0.06);
}

.users-table tbody td {
  padding: 14px 20px;
  font-size: 14px;
  color: var(--text-primary);
  border-bottom: 1px solid rgba(255,255,255,0.04);
  vertical-align: middle;
}

.users-table tbody tr:last-child td {
  border-bottom: none;
}

/* ── User Name Cell ──────────────────────────────── */
.user-name-cell {
  display: flex;
  align-items: center;
  gap: 12px;
  font-weight: 600;
}

.user-avatar {
  width: 38px; height: 38px;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  font-size: 15px;
  font-weight: 700;
  color: #fff;
  flex-shrink: 0;
  text-transform: uppercase;
  background: linear-gradient(135deg, rgba(139,92,246,0.5), rgba(99,102,241,0.4));
  border: 2px solid rgba(139,92,246,0.3);
  box-shadow: 0 2px 10px rgba(139,92,246,0.2);
}

.user-name-info {
  display: flex;
  flex-direction: column;
  gap: 1px;
}

.user-name-info .user-display-name {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
}

.user-name-info .user-username {
  font-size: 12px;
  color: var(--text-muted);
  font-family: 'SF Mono', 'Fira Code', monospace;
}

/* ── Role Tags ───────────────────────────────────── */
.role-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
}

.role-tag {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 3px 10px;
  border-radius: 20px;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.03em;
}

.role-tag.system-tag {
  background: rgba(139,92,246,0.15);
  color: #C4B5FD;
  border: 1px solid rgba(139,92,246,0.25);
}

.role-tag.custom-tag {
  background: rgba(6,182,212,0.12);
  color: #67E8F9;
  border: 1px solid rgba(6,182,212,0.25);
}

.role-tag .tag-remove {
  width: 14px; height: 14px;
  display: inline-flex; align-items: center; justify-content: center;
  border-radius: 50%;
  font-size: 10px;
  cursor: pointer;
  transition: var(--transition-fast);
  margin-left: 2px;
  opacity: 0;
}

.role-tag:hover .tag-remove {
  opacity: 1;
}

.role-tag .tag-remove:hover {
  background: rgba(239,68,68,0.3);
  color: #FCA5A5;
}

/* ── Actions Cell ────────────────────────────────── */
.user-actions {
  display: flex;
  gap: 6px;
  opacity: 0.6;
  transition: opacity 0.2s ease;
}

.users-table tbody tr:hover .user-actions {
  opacity: 1;
}

.user-action-btn {
  width: 32px; height: 32px;
  border-radius: 8px;
  display: flex; align-items: center; justify-content: center;
  border: 1px solid var(--border);
  background: rgba(255,255,255,0.04);
  color: var(--text-secondary);
  cursor: pointer;
  transition: var(--transition-fast);
  font-size: 14px;
}

.user-action-btn:hover {
  background: rgba(139,92,246,0.12);
  border-color: rgba(139,92,246,0.35);
  color: #C4B5FD;
  transform: scale(1.08);
}

.user-action-btn.danger:hover {
  background: rgba(239,68,68,0.15);
  border-color: rgba(239,68,68,0.35);
  color: #FCA5A5;
}

/* ── Form Card (Create / Edit) ───────────────────── */
.user-form-card {
  max-width: 720px;
  margin: 0 auto;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  padding: 36px;
  box-shadow: var(--shadow);
}

.user-form-card h2 {
  font-size: 22px;
  font-weight: 700;
  margin-bottom: 24px;
  background: var(--accent-grad);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* ── Role Assignment Section ─────────────────────── */
.role-assign-section {
  margin-top: 28px;
  padding-top: 24px;
  border-top: 1px solid var(--border);
}

.role-assign-section h3 {
  font-size: 14px;
  font-weight: 700;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  margin-bottom: 16px;
}

.role-assign-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
  gap: 8px;
}

.role-assign-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 14px;
  border-radius: 10px;
  border: 1px solid rgba(255,255,255,0.07);
  background: rgba(255,255,255,0.025);
  cursor: pointer;
  transition: var(--transition-fast);
  user-select: none;
}

.role-assign-item:hover {
  border-color: rgba(139,92,246,0.3);
  background: rgba(139,92,246,0.06);
}

.role-assign-item.assigned {
  border-color: rgba(139,92,246,0.4);
  background: rgba(139,92,246,0.1);
}

.role-assign-item input[type="checkbox"] {
  appearance: none;
  -webkit-appearance: none;
  width: 18px; height: 18px;
  border: 2px solid rgba(255,255,255,0.2);
  border-radius: 5px;
  background: rgba(255,255,255,0.04);
  cursor: pointer;
  transition: var(--transition-fast);
  position: relative;
  flex-shrink: 0;
}

.role-assign-item input[type="checkbox"]:checked {
  background: var(--accent);
  border-color: var(--accent);
  box-shadow: 0 0 12px rgba(139,92,246,0.4);
}

.role-assign-item input[type="checkbox"]:checked::after {
  content: '✓';
  position: absolute;
  top: 50%; left: 50%;
  transform: translate(-50%, -50%);
  color: #fff;
  font-size: 12px;
  font-weight: 700;
}

.role-assign-label {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.role-assign-label .role-assign-name {
  font-size: 13px;
  font-weight: 600;
  color: var(--text-primary);
}

.role-assign-label .role-assign-type {
  font-size: 11px;
  color: var(--text-muted);
}

/* ── Current Roles (Edit page) ───────────────────── */
.current-roles-list {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-top: 10px;
}

.current-role-chip {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 6px 14px;
  border-radius: 20px;
  font-size: 13px;
  font-weight: 600;
}

.current-role-chip.system-chip {
  background: rgba(139,92,246,0.15);
  color: #C4B5FD;
  border: 1px solid rgba(139,92,246,0.25);
}

.current-role-chip.custom-chip {
  background: rgba(6,182,212,0.12);
  color: #67E8F9;
  border: 1px solid rgba(6,182,212,0.25);
}

.current-role-chip .chip-remove {
  width: 18px; height: 18px;
  display: inline-flex; align-items: center; justify-content: center;
  border-radius: 50%;
  font-size: 11px;
  cursor: pointer;
  transition: var(--transition-fast);
  background: rgba(255,255,255,0.08);
}

.current-role-chip .chip-remove:hover {
  background: rgba(239,68,68,0.3);
  color: #FCA5A5;
}

/* ── Form Actions ────────────────────────────────── */
.user-form-actions {
  display: flex;
  gap: 12px;
  margin-top: 28px;
  padding-top: 20px;
  border-top: 1px solid var(--border);
}

/* ── Delete Modal ────────────────────────────────── */
.user-modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.82);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
