}

.user-modal h3 {
  font-size: 18px;
  font-weight: 700;
  margin-bottom: 12px;
}

.user-modal p {
  color: var(--text-secondary);
  font-size: 14px;
  margin-bottom: 24px;
  line-height: 1.6;
}

.user-modal-actions {
  display: flex;
  gap: 10px;
  justify-content: flex-end;
}

/* ── Loading & Empty ─────────────────────────────── */
.users-skeleton {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.users-skeleton-row {
  height: 56px;
  background: rgba(255,255,255,0.04);
  border-radius: var(--radius-sm);
  animation: pulse 1.5s infinite ease-in-out;
}

.users-empty {
  text-align: center;
  padding: 60px 20px;
  color: var(--text-muted);
}

.users-empty-icon {
  font-size: 48px;
  margin-bottom: 16px;
  opacity: 0.5;
}

.users-empty h3 {
  font-size: 18px;
  color: var(--text-secondary);
  margin-bottom: 8px;
}

.users-empty p {
  font-size: 14px;
  margin-bottom: 20px;
}

/* ── Email Cell ──────────────────────────────────── */
.user-email {
  color: var(--text-secondary);
  font-size: 13px;
}

.user-email a {
  color: var(--accent);
  text-decoration: none;
  transition: var(--transition-fast);
}

.user-email a:hover {
  color: var(--accent-3);
  text-decoration: underline;
}

/* ── Responsive ──────────────────────────────────── */
@media (max-width: 768px) {
  .users-page { padding: 20px 16px 48px; }
  .users-page-header { flex-direction: column; align-items: flex-start; }
  .users-table thead { display: none; }
  .users-table tbody tr {
    display: block;
    padding: 16px;
    border-bottom: 1px solid var(--border);
  }
  .users-table tbody td {
    display: flex;
    justify-content: space-between;
    padding: 6px 0;
    border-bottom: none;
  }
  .users-table tbody td::before {
    content: attr(data-label);
    font-weight: 700;
    font-size: 11px;
    text-transform: uppercase;
    color: var(--text-muted);
    letter-spacing: 0.06em;
  }
  .user-form-card { padding: 24px 18px; }
  .role-assign-grid { grid-template-columns: 1fr; }
}

/* ================================================
   Phase 3 - Premium Users Refinement
   UI-only overrides (no logic changes)
   ================================================ */

.users-page {
  max-width: 1160px;
  padding: 36px 24px 72px;
}

.users-page-header {
  margin-bottom: 30px;
}

.users-page-header h1 {
  font-size: clamp(30px, 4vw, 42px);
  letter-spacing: -0.03em;
}

.users-table-wrap {
  border-radius: 16px;
  border-color: rgba(255, 255, 255, 0.1);
  box-shadow: 0 10px 34px rgba(0, 0, 0, 0.38);
}

.users-table thead th {
  padding: 15px 20px;
  font-size: 10.5px;
  letter-spacing: 0.1em;
}

.users-table tbody td {
  padding: 15px 20px;
}

.users-table tbody tr {
  transition: background 0.2s ease, transform 0.2s ease;
}

.users-table tbody tr:hover {
  background: rgba(139, 92, 246, 0.08);
  transform: translateY(-1px);
}

.user-avatar {
  box-shadow: 0 4px 14px rgba(99, 102, 241, 0.24);
}

.user-action-btn {
  border-radius: 10px;
  transition: transform 0.2s ease, background 0.2s ease, border-color 0.2s ease, color 0.2s ease;
}

.user-form-card {
  border-radius: 16px;
  border-color: rgba(255, 255, 255, 0.1);
  box-shadow: 0 14px 42px rgba(0, 0, 0, 0.42);
}

.user-form-card h2 {
  font-size: clamp(24px, 3vw, 30px);
  letter-spacing: -0.02em;
}

.role-assign-item {
  border-radius: 12px;
  border-color: rgba(255, 255, 255, 0.09);
  background: rgba(255, 255, 255, 0.03);
}

.role-assign-item:hover {
  border-color: rgba(139, 92, 246, 0.3);
  background: rgba(139, 92, 246, 0.07);
  box-shadow: 0 8px 20px rgba(20, 15, 50, 0.22);
}

.role-assign-item.assigned {
  border-color: rgba(139, 92, 246, 0.45);
  background: rgba(139, 92, 246, 0.11);
}

@media (max-width: 1023px) {
  .users-page {
    padding: 30px 20px 60px;
  }

  .users-table thead th,
  .users-table tbody td {
    padding-left: 14px;
    padding-right: 14px;
  }
}

@media (max-width: 767px) {
  .users-page {
    padding: 24px 16px 52px;
  }

  .user-form-card {
    padding: 24px 18px;
    border-radius: 14px;
  }
}

/* ══════════════════════════════════════════════════
   User Management Styles — Dark Glassmorphism
   ══════════════════════════════════════════════════ */

/* ── Page Layout ─────────────────────────────────── */
.users-page {
  max-width: 1100px;
  margin: 0 auto;
  padding: 32px 24px 64px;
}

.users-page-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 28px;
  gap: 16px;
  flex-wrap: wrap;
}

.users-page-header h1 {
  font-size: 28px;
  font-weight: 800;
  letter-spacing: -0.02em;
  background: var(--accent-grad);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.users-page-header p {
  color: var(--text-secondary);
  font-size: 14px;
  margin-top: 4px;
}

.users-toolbar {
  display: flex;
  gap: 10px;
  align-items: center;
}

.users-search-input {
  width: 260px;
  min-height: 38px;
}

.users-actions-col {
  width: 100px;
}

.users-muted-sm {
  color: var(--text-muted);
  font-size: 12px;
}

.users-alert {
  padding: 12px 16px;
  margin-bottom: 20px;
  border-radius: var(--radius-sm);
  border: 1px solid transparent;
  font-size: 14px;
}

.users-alert-error {
  background: rgba(239, 68, 68, 0.1);
  border-color: rgba(239, 68, 68, 0.3);
  color: #fca5a5;
}

.users-form-group {
  margin-bottom: 20px;
}

.users-help-text {
  display: block;
  margin-top: 4px;
  font-size: 11px;
  color: var(--text-muted);
}

.users-note {
  display: block;
  font-size: 12px;
  color: var(--text-muted);
}

.users-note-tight {
  margin-bottom: 4px;
}

.users-note-spaced {
  margin-bottom: 16px;
}

.users-note-inline {
  align-self: center;
}

.users-input-disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

.user-form-actions-inline {
  border-top: none;
  margin-top: 8px;
  padding-top: 0;
}

.role-actions-inline {
  margin-top: 12px;
}

.users-current-role-block {
  margin-bottom: 16px;
}

.users-subtitle-label {
  display: block;
  font-size: 11px;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  font-weight: 700;
}

.users-subtitle-label-spaced {
  margin-bottom: 8px;
}

.users-effective-permissions {
  margin-top: 20px;
}

.users-perm-chip-list {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
}

/* ── Users Table ─────────────────────────────────── */
.users-table-wrap {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  overflow: hidden;
  box-shadow: var(--shadow);
}

.users-table {
  width: 100%;
  border-collapse: collapse;
}

.users-table thead th {
  text-align: left;
  padding: 14px 20px;
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--text-muted);
  border-bottom: 1px solid var(--border);
  background: rgba(255,255,255,0.02);
}

.users-table tbody tr {
  transition: var(--transition-fast);
}

.users-table tbody tr:hover {
  background: rgba(139,92,246,0.06);
}

.users-table tbody td {
  padding: 14px 20px;
  font-size: 14px;
  color: var(--text-primary);
  border-bottom: 1px solid rgba(255,255,255,0.04);
  vertical-align: middle;
}

.users-table tbody tr:last-child td {
  border-bottom: none;
}

/* ── User Name Cell ──────────────────────────────── */
.user-name-cell {
  display: flex;
  align-items: center;
  gap: 12px;
  font-weight: 600;
}

.user-avatar {
  width: 38px; height: 38px;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  font-size: 15px;
  font-weight: 700;
  color: #fff;
  flex-shrink: 0;
  text-transform: uppercase;
  background: linear-gradient(135deg, rgba(139,92,246,0.5), rgba(99,102,241,0.4));
  border: 2px solid rgba(139,92,246,0.3);
  box-shadow: 0 2px 10px rgba(139,92,246,0.2);
}

.user-name-info {
  display: flex;
  flex-direction: column;
  gap: 1px;
}

.user-name-info .user-display-name {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
}

.user-name-info .user-username {
  font-size: 12px;
  color: var(--text-muted);
  font-family: 'SF Mono', 'Fira Code', monospace;
}

/* ── Role Tags ───────────────────────────────────── */
.role-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
}

.role-tag {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 3px 10px;
  border-radius: 20px;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.03em;
}

.role-tag.system-tag {
  background: rgba(139,92,246,0.15);
  color: #C4B5FD;
  border: 1px solid rgba(139,92,246,0.25);
}

.role-tag.custom-tag {
  background: rgba(6,182,212,0.12);
  color: #67E8F9;
  border: 1px solid rgba(6,182,212,0.25);
}

.role-tag .tag-remove {
  width: 14px; height: 14px;
  display: inline-flex; align-items: center; justify-content: center;
  border-radius: 50%;
  font-size: 10px;
  cursor: pointer;
  transition: var(--transition-fast);
  margin-left: 2px;
  opacity: 0;
}

.role-tag:hover .tag-remove {
  opacity: 1;
}

.role-tag .tag-remove:hover {
  background: rgba(239,68,68,0.3);
  color: #FCA5A5;
}

/* ── Actions Cell ────────────────────────────────── */
.user-actions {
  display: flex;
  gap: 6px;
  opacity: 0.6;
  transition: opacity 0.2s ease;
}

.users-table tbody tr:hover .user-actions {
  opacity: 1;
}

.user-action-btn {
  width: 32px; height: 32px;
  border-radius: 8px;
  display: flex; align-items: center; justify-content: center;
  border: 1px solid var(--border);
  background: rgba(255,255,255,0.04);
  color: var(--text-secondary);
  cursor: pointer;
  transition: var(--transition-fast);
  font-size: 14px;
}

.user-action-btn:hover {
  background: rgba(139,92,246,0.12);
  border-color: rgba(139,92,246,0.35);
  color: #C4B5FD;
  transform: scale(1.08);
}

.user-action-btn.danger:hover {
  background: rgba(239,68,68,0.15);
  border-color: rgba(239,68,68,0.35);
  color: #FCA5A5;
}

/* ── Form Card (Create / Edit) ───────────────────── */
.user-form-card {
  max-width: 720px;
  margin: 0 auto;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  padding: 36px;
  box-shadow: var(--shadow);
}

.user-form-card h2 {
  font-size: 22px;
  font-weight: 700;
  margin-bottom: 24px;
  background: var(--accent-grad);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* ── Role Assignment Section ─────────────────────── */
.role-assign-section {
  margin-top: 28px;
  padding-top: 24px;
  border-top: 1px solid var(--border);
}

.role-assign-section h3 {
  font-size: 14px;
  font-weight: 700;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  margin-bottom: 16px;
}

.role-assign-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
  gap: 8px;
}

.role-assign-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 14px;
  border-radius: 10px;
  border: 1px solid rgba(255,255,255,0.07);
  background: rgba(255,255,255,0.025);
  cursor: pointer;
  transition: var(--transition-fast);
  user-select: none;
}

.role-assign-item:hover {
  border-color: rgba(139,92,246,0.3);
  background: rgba(139,92,246,0.06);
}

.role-assign-item.assigned {
  border-color: rgba(139,92,246,0.4);
  background: rgba(139,92,246,0.1);
}

.role-assign-item input[type="checkbox"] {
  appearance: none;
  -webkit-appearance: none;
  width: 18px; height: 18px;
  border: 2px solid rgba(255,255,255,0.2);
  border-radius: 5px;
  background: rgba(255,255,255,0.04);
  cursor: pointer;
  transition: var(--transition-fast);
  position: relative;
  flex-shrink: 0;
}

.role-assign-item input[type="checkbox"]:checked {
  background: var(--accent);
  border-color: var(--accent);
  box-shadow: 0 0 12px rgba(139,92,246,0.4);
}

.role-assign-item input[type="checkbox"]:checked::after {
  content: '✓';
  position: absolute;
  top: 50%; left: 50%;
  transform: translate(-50%, -50%);
  color: #fff;
  font-size: 12px;
  font-weight: 700;
}

.role-assign-label {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.role-assign-label .role-assign-name {
  font-size: 13px;
  font-weight: 600;
  color: var(--text-primary);
}

.role-assign-label .role-assign-type {
  font-size: 11px;
  color: var(--text-muted);
}

/* ── Current Roles (Edit page) ───────────────────── */
.current-roles-list {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-top: 10px;
}

.current-role-chip {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 6px 14px;
  border-radius: 20px;
  font-size: 13px;
  font-weight: 600;
}

.current-role-chip.system-chip {
  background: rgba(139,92,246,0.15);
  color: #C4B5FD;
  border: 1px solid rgba(139,92,246,0.25);
}

.current-role-chip.custom-chip {
  background: rgba(6,182,212,0.12);
  color: #67E8F9;
  border: 1px solid rgba(6,182,212,0.25);
}

.current-role-chip .chip-remove {
  width: 18px; height: 18px;
  display: inline-flex; align-items: center; justify-content: center;
  border-radius: 50%;
  font-size: 11px;
  cursor: pointer;
  transition: var(--transition-fast);
  background: rgba(255,255,255,0.08);
}

.current-role-chip .chip-remove:hover {
  background: rgba(239,68,68,0.3);
  color: #FCA5A5;
}

/* ── Form Actions ────────────────────────────────── */
.user-form-actions {
  display: flex;
  gap: 12px;
  margin-top: 28px;
  padding-top: 20px;
  border-top: 1px solid var(--border);
}

/* ── Delete Modal ────────────────────────────────── */
.user-modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.82);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  animation: fadeIn 0.2s ease;
}

.user-modal {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 32px;
  max-width: 420px;
  width: 90%;
  box-shadow: var(--shadow-lg);
  animation: slideUp 0.25s ease;
}

[data-theme="light"] .user-modal-overlay {
  background: rgba(15, 23, 42, 0.62);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
}

[data-theme="light"] .user-modal {
  background: #FFFFFF;
  border-color: rgba(239, 68, 68, 0.28);
  box-shadow: 0 28px 72px rgba(0, 0, 0, 0.3), 0 0 0 1px rgba(239, 68, 68, 0.08);
}

.user-modal h3 {
  font-size: 18px;
  font-weight: 700;
  margin-bottom: 12px;
}

.user-modal p {
  color: var(--text-secondary);
  font-size: 14px;
  margin-bottom: 24px;
  line-height: 1.6;
}

.user-modal-actions {
  display: flex;
  gap: 10px;
  justify-content: flex-end;
}

/* ── Loading & Empty ─────────────────────────────── */
.users-skeleton {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.users-skeleton-row {
  height: 56px;
  background: rgba(255,255,255,0.04);
  border-radius: var(--radius-sm);
  animation: pulse 1.5s infinite ease-in-out;
}

.users-empty {
  text-align: center;
  padding: 60px 20px;
  color: var(--text-muted);
}

.users-empty-icon {
  font-size: 48px;
  margin-bottom: 16px;
  opacity: 0.5;
}

.users-empty h3 {
  font-size: 18px;
  color: var(--text-secondary);
  margin-bottom: 8px;
}

.users-empty p {
  font-size: 14px;
  margin-bottom: 20px;
}

/* ── Email Cell ──────────────────────────────────── */
.user-email {
  color: var(--text-secondary);
  font-size: 13px;
}

.user-email a {
  color: var(--accent);
  text-decoration: none;
  transition: var(--transition-fast);
}

.user-email a:hover {
  color: var(--accent-3);
  text-decoration: underline;
}

/* ── Responsive ──────────────────────────────────── */
@media (max-width: 768px) {
  .users-page { padding: 20px 16px 48px; }
  .users-page-header { flex-direction: column; align-items: flex-start; }
  .users-table thead { display: none; }
  .users-table tbody tr {
    display: block;
    padding: 16px;
    border-bottom: 1px solid var(--border);
  }
  .users-table tbody td {
    display: flex;
    justify-content: space-between;
    padding: 6px 0;
    border-bottom: none;
  }
  .users-table tbody td::before {
    content: attr(data-label);
    font-weight: 700;
    font-size: 11px;
    text-transform: uppercase;
    color: var(--text-muted);
    letter-spacing: 0.06em;
  }
  .user-form-card { padding: 24px 18px; }
  .role-assign-grid { grid-template-columns: 1fr; }
}

